fn xml_escape(s: &str) -> String {
    s.replace('\0', "")
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
}

fn quat_conjugate(q: [f32; 4]) -> [f32; 4] {
    [-q[0], -q[1], -q[2], q[3]]
}

fn quat_multiply(a: [f32; 4], b: [f32; 4]) -> [f32; 4] {
    [
        a[3] * b[0] + a[0] * b[3] + a[1] * b[2] - a[2] * b[1],
        a[3] * b[1] - a[0] * b[2] + a[1] * b[3] + a[2] * b[0],
        a[3] * b[2] + a[0] * b[1] - a[1] * b[0] + a[2] * b[3],
        a[3] * b[3] - a[0] * b[0] - a[1] * b[1] - a[2] * b[2],
    ]
}

fn quat_rotate_vec3(q: [f32; 4], v: [f32; 3]) -> [f32; 3] {
    let vq = [v[0], v[1], v[2], 0.0];
    let result = quat_multiply(quat_multiply(q, vq), quat_conjugate(q));
    [result[0], result[1], result[2]]
}

fn sorted_clamp(a: f32, val: f32, b: f32) -> f32 {
    let (lo, hi) = if a <= b { (a, b) } else { (b, a) };
    val.clamp(lo, hi)
}

fn ray_aabb_intersect(
    ray_origin: [f32; 3],
    ray_dir: [f32; 3],
    box_center: [f32; 3],
    box_half: [f32; 3],
) -> Option<([f32; 3], [f32; 3])> {
    let box_min = [
        box_center[0] - box_half[0],
        box_center[1] - box_half[1],
        box_center[2] - box_half[2],
    ];
    let box_max = [
        box_center[0] + box_half[0],
        box_center[1] + box_half[1],
        box_center[2] + box_half[2],
    ];
    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;
    let mut normal = [0.0f32; 3];
    for i in 0..3 {
        if ray_dir[i].abs() < 1e-8 {
            if ray_origin[i] < box_min[i] || ray_origin[i] > box_max[i] {
                return None;
            }
        } else {
            let inv_d = 1.0 / ray_dir[i];
            let mut t1 = (box_min[i] - ray_origin[i]) * inv_d;
            let mut t2 = (box_max[i] - ray_origin[i]) * inv_d;
            let mut n = [0.0f32; 3];
            n[i] = -inv_d.signum();
            if t1 > t2 {
                std::mem::swap(&mut t1, &mut t2);
            }
            if t1 > tmin {
                tmin = t1;
                normal = n;
            }
            if t2 < tmax {
                tmax = t2;
            }
            if tmin > tmax {
                return None;
            }
        }
    }
    if tmin < 0.0 {
        return None;
    }
    let hit = [
        ray_origin[0] + ray_dir[0] * tmin,
        ray_origin[1] + ray_dir[1] * tmin,
        ray_origin[2] + ray_dir[2] * tmin,
    ];
    Some((hit, normal))
}

