// Phase 91: TERSE update tolerance thresholds (from opensim-master)
const ROTATION_TOLERANCE: f32 = 0.01;
const VELOCITY_TOLERANCE: f32 = 0.1;
const LOW_VELOCITY_SQ: f32 = 0.1;
const POSITION_LARGE_TOLERANCE: f32 = 5.0;
const POSITION_SMALL_TOLERANCE: f32 = 0.05;

const PID_D_BASE: f32 = 0.55;
const PID_P_BASE: f32 = 0.225;
const AVATAR_MASS: f32 = 80.0;
const WALK_DIVISOR: f32 = 1.3;
const RUN_DIVISOR: f32 = 0.9;
const DELAYED_STOP_MS: f64 = 250.0;
const VEL_SMOOTH_OLD: f32 = 0.4;
const VEL_SMOOTH_NEW: f32 = 0.6;
const MAX_AVATAR_SPEED: f32 = 30.0;

fn quat_rotate(q: [f32; 4], v: [f32; 3]) -> [f32; 3] {
    let (qx, qy, qz, qw) = (q[0], q[1], q[2], q[3]);
    let (x, y, z) = (v[0], v[1], v[2]);
    [
        x * (1.0 - 2.0 * (qy * qy + qz * qz))
            + y * 2.0 * (qx * qy - qz * qw)
            + z * 2.0 * (qx * qz + qy * qw),
        x * 2.0 * (qx * qy + qz * qw)
            + y * (1.0 - 2.0 * (qx * qx + qz * qz))
            + z * 2.0 * (qy * qz - qx * qw),
        x * 2.0 * (qx * qz - qy * qw)
            + y * 2.0 * (qy * qz + qx * qw)
            + z * (1.0 - 2.0 * (qx * qx + qy * qy)),
    ]
}

fn compute_pid_velocity(
    target_vel: [f32; 3],
    actual_vel: [f32; 3],
    _position: [f32; 3],
    _zero_pos: [f32; 3],
    is_flying: bool,
    _on_ground: bool,
    is_running: bool,
    _dt: f32,
) -> [f32; 3] {
    let divisor = if is_running {
        RUN_DIVISOR
    } else {
        WALK_DIVISOR
    };
    let mut corrected = [
        target_vel[0] / divisor,
        target_vel[1] / divisor,
        if is_flying {
            target_vel[2] / divisor
        } else {
            target_vel[2]
        },
    ];

    if !is_flying && !_on_ground {
        corrected[2] -= 9.81 * 0.091;
    }

    let speed_sq =
        corrected[0] * corrected[0] + corrected[1] * corrected[1] + corrected[2] * corrected[2];
    if speed_sq > MAX_AVATAR_SPEED * MAX_AVATAR_SPEED {
        let speed = speed_sq.sqrt();
        let scale = MAX_AVATAR_SPEED / speed;
        corrected[0] *= scale;
        corrected[1] *= scale;
        corrected[2] *= scale;
    }

    corrected
}

fn determine_movement_animation(state: &AvatarMovementState) -> &'static str {
    let has_horizontal = state.target_velocity[0] != 0.0 || state.target_velocity[1] != 0.0;
    let has_up = state.target_velocity[2] > 0.0;
    let has_down = state.target_velocity[2] < 0.0;
    let is_running = state.control_flags & 0x00000400 != 0; // AGENT_CONTROL_FAST_AT
    let is_crouching = state.control_flags & 0x00000020 != 0; // AGENT_CONTROL_UP_NEG
    let is_turning_left = state.control_flags & 0x02000000 != 0; // AGENT_CONTROL_TURN_LEFT
    let is_turning_right = state.control_flags & 0x04000000 != 0; // AGENT_CONTROL_TURN_RIGHT

    if state.is_flying {
        if has_horizontal {
            return if is_running {
                ANIM_NAME_FLY
            } else {
                ANIM_NAME_FLYSLOW
            };
        }
        if has_up {
            return ANIM_NAME_HOVER_UP;
        }
        if has_down {
            return ANIM_NAME_HOVER_DOWN;
        }
        return ANIM_NAME_HOVER;
    }

    if !state.is_flying && !state.on_ground && state.actual_velocity[2] < -0.5 {
        return ANIM_NAME_FALLDOWN;
    }

    if is_crouching {
        if has_horizontal {
            return ANIM_NAME_CROUCHWALK;
        }
        return "CROUCH";
    }

    if !has_horizontal && (is_turning_left || is_turning_right) {
        if is_turning_left {
            return ANIM_NAME_TURNLEFT;
        }
        return ANIM_NAME_TURNRIGHT;
    }

    if has_horizontal {
        return if is_running {
            ANIM_NAME_RUN
        } else {
            ANIM_NAME_WALK
        };
    }
    ANIM_NAME_STAND
}

fn should_send_terse(state: &AvatarMovementState) -> bool {
    let vel = state.actual_velocity;
    let is_moving = vel[0] != 0.0 || vel[1] != 0.0 || vel[2] != 0.0;
    if is_moving {
        return true;
    }

    let last_vel = state.last_sent_velocity;
    let just_stopped = last_vel[0] != 0.0 || last_vel[1] != 0.0 || last_vel[2] != 0.0;
    if just_stopped {
        return true;
    }

    let rot_changed = (state.rotation[0] - state.last_sent_rotation[0]).abs() > ROTATION_TOLERANCE
        || (state.rotation[1] - state.last_sent_rotation[1]).abs() > ROTATION_TOLERANCE
        || (state.rotation[2] - state.last_sent_rotation[2]).abs() > ROTATION_TOLERANCE;
    rot_changed
}

#[derive(Debug, Clone)]
pub struct UdpPacket {
    pub flags: u8,
    pub sequence: u32,
    pub message_id: u32,
    pub data: Bytes,
    pub source: SocketAddr,
}

impl UdpPacket {
    pub fn parse(data: &[u8], source: SocketAddr) -> Result<Self> {
        use super::zero_encoder::zero_decode;

        if data.len() < 7 {
            return Err(anyhow!("Packet too short: {} bytes", data.len()));
        }

        let flags = data[0];
        let sequence = u32::from_be_bytes([data[1], data[2], data[3], data[4]]);
        let _extra = data[5];

        let body_start = 6;
        let mut body = &data[body_start..];

        if flags & FLAG_ACK_APPENDED != 0 && !body.is_empty() {
            let ack_count = body[body.len() - 1] as usize;
            let ack_section_size = ack_count * 4 + 1;
            if body.len() >= ack_section_size {
                body = &body[..body.len() - ack_section_size];
                debug!(
                    "Stripped {} appended ACKs ({} bytes) from packet",
                    ack_count, ack_section_size
                );
            }
        }

        let decoded_body = if flags & FLAG_ZEROCODED != 0 {
            zero_decode(body)
        } else {
            body.to_vec()
        };

        if decoded_body.is_empty() {
            return Err(anyhow!("Empty message body after decode"));
        }

        let message_id = {
            let first_byte = decoded_body[0];
            if first_byte == 0xFF && decoded_body.len() > 1 {
                let second_byte = decoded_body[1];
                if second_byte == 0xFF && decoded_body.len() > 3 {
                    0xFFFF0000 | ((decoded_body[2] as u32) << 8) | (decoded_body[3] as u32)
                } else {
                    0xFF00 | (second_byte as u32)
                }
            } else {
                first_byte as u32
            }
        };

        let payload_start = if message_id <= 0xFF {
            1
        } else if message_id <= 0xFFFF {
            2
        } else {
            4
        };

        let remaining_data = if payload_start < decoded_body.len() {
            Bytes::copy_from_slice(&decoded_body[payload_start..])
        } else {
            Bytes::new()
        };

        Ok(Self {
            flags,
            sequence,
            message_id,
            data: remaining_data,
            source,
        })
    }

    pub fn is_reliable(&self) -> bool {
        self.flags & FLAG_RELIABLE != 0
    }

    pub fn is_resent(&self) -> bool {
        self.flags & FLAG_RESENT != 0
    }

    pub fn has_acks(&self) -> bool {
        self.flags & FLAG_ACK_APPENDED != 0
    }
}

