                                        pkt.push(0xFF);
                                        pkt.push(0x00);
                                        pkt.push(0x9F); // Low 159 = SetFollowCamProperties
                                        pkt.extend_from_slice(&data);
                                        let _ = socket.send_to(&pkt, addr).await;
                                        info!("[SCRIPT] SetFollowCamProperties sent to {} ({} params) for object {}", avatar_id, params.len(), object_id);
