                                let mut pkt = Vec::with_capacity(10 + data.len());
                                pkt.push(0x40);
                                pkt.extend_from_slice(&seq.to_be_bytes());
                                pkt.push(0xFF);
                                pkt.push(0x0E); // Medium 14 = AttachedSoundGainChange
                                pkt.extend_from_slice(&data);
                                let addrs: Vec<SocketAddr> = { let states = avatar_states.read(); states.values().filter(|s| !s.is_npc).map(|s| s.client_addr).collect() };
                                for addr in &addrs { let _ = socket.send_to(&pkt, addr).await; }
