    async fn send_region_info(
        &self,
        agent_id: Uuid,
        session_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        let mut data = BytesMut::with_capacity(256);

        // AgentData block (Single)
        data.put_slice(agent_id.as_bytes()); // AgentID
        data.put_slice(session_id.as_bytes()); // SessionID

        // RegionInfo block (Single)
        let sim_name = self.region_name.as_bytes();
        data.put_u8(sim_name.len() as u8); // SimName length
        data.put_slice(sim_name); // SimName
        data.put_u32_le(1); // EstateID
        data.put_u32_le(0); // ParentEstateID
        let region_flags = Self::compute_region_flags() as u32;
        info!(
            "[REGION] RegionInfo flags: 0x{:08x} (ALLOW_LANDMARK={}, ALLOW_SET_HOME={})",
            region_flags,
            region_flags & 2 != 0,
            region_flags & 4 != 0
        );
        data.put_u32_le(region_flags); // RegionFlags
        data.put_u8(21); // SimAccess (Mature)
        data.put_u8(100); // MaxAgents
        data.put_f32_le(1.0); // BillableFactor
        data.put_f32_le(1.0); // ObjectBonusFactor
        data.put_f32_le(self.water_height); // WaterHeight
        data.put_f32_le(100.0); // TerrainRaiseLimit
        data.put_f32_le(-100.0); // TerrainLowerLimit
        data.put_i32_le(1); // PricePerMeter
        data.put_i32_le(0); // RedirectGridX
        data.put_i32_le(0); // RedirectGridY
        data.put_u8(1); // UseEstateSun
        data.put_f32_le(6.0); // SunHour

        // RegionInfo2 block (Single) - REQUIRED
        data.put_u8(0); // ProductSKU (Variable 1) - empty
        let product_name = b"OpenSim";
        data.put_u8(product_name.len() as u8); // ProductName length
        data.put_slice(product_name); // ProductName
        data.put_u32_le(100); // MaxAgents32
        data.put_u32_le(100); // HardMaxAgents
        data.put_u32_le(15000); // HardMaxObjects

        // RegionInfo3 block (Variable) - 0 blocks
        data.put_u8(0); // Block count = 0

        // RegionInfo5 block (Variable) - 0 blocks
        data.put_u8(0); // Block count = 0

        // CombatSettings block (Variable) - 0 blocks
        data.put_u8(0); // Block count = 0

        self.send_message(REGION_INFO_ID, &data, dest, true, true)
            .await?;

        info!(
            "[LOGIN] Sent RegionInfo (with RegionInfo2) to {} for agent {}",
            dest, agent_id
        );
        Ok(())
    }

    async fn send_terrain(&self, dest: SocketAddr, agent_id: Uuid) -> Result<()> {
        self.send_terrain_with_circuit(dest, agent_id, None).await
    }

    async fn send_terrain_with_circuit(
        &self,
        dest: SocketAddr,
        agent_id: Uuid,
        circuit_code: Option<u32>,
    ) -> Result<()> {
        let terrain_sender = self
            .terrain_sender
            .as_ref()
            .ok_or_else(|| anyhow!("TerrainSender not initialized"))?;

        let packets = terrain_sender
            .get_terrain_packets(self.default_region_uuid)
            .await?;
        let packet_count = packets.len();

        info!(
            "[TERRAIN] Sending {} LayerData packets via send_message() to {}",
            packet_count, dest
        );

        for (i, message) in packets.iter().enumerate() {
            let body = message.serialize_body();

            if i == 0 {
                warn!(
                    "[TERRAIN] First LayerData body ({} bytes): {:02x?}",
                    body.len(),
                    &body[..body.len().min(30)]
                );
            }

            self.send_message(LAYER_DATA_ID, &body, dest, true, false)
                .await?;

            if (i + 1) % 16 == 0 {
                info!(
                    "[TERRAIN] Sent {}/{} terrain packets via send_message()",
                    i + 1,
                    packet_count
                );
                tokio::task::yield_now().await;
            }
        }

        info!(
            "[TERRAIN] ✅ All {} terrain packets sent via send_message() to {}",
            packet_count, dest
        );

        // Mark terrain sent stage
        if let Some(cc) = circuit_code {
            self.stage_tracker
                .mark_passed_with_count_by_circuit(
                    cc,
                    LoginStage::TerrainSent,
                    packet_count as u32,
                    Some(format!("{} LayerData packets sent", packet_count)),
                )
                .await;
        }

        Ok(())
    }

    async fn send_parcel_overlay(&self, agent_id: Uuid, dest: SocketAddr) -> Result<()> {
        const LAND_BLOCKS_PER_PACKET: usize = 1024;
        const LAND_FLAG_BORDER_WEST: u8 = 0x40;
        const LAND_FLAG_BORDER_SOUTH: u8 = 0x80;

        let blocks_x = (self.region_size_x / 4) as usize;
        let blocks_y = (self.region_size_y / 4) as usize;
        let total_blocks = blocks_x * blocks_y;
        let num_packets = (total_blocks + LAND_BLOCKS_PER_PACKET - 1) / LAND_BLOCKS_PER_PACKET;

        let parcel_ids: Vec<(i32, u8)> = {
            let parcels = self.parcels.read();
            let mut ids = Vec::with_capacity(total_blocks);
            for idx in 0..total_blocks {
                let bx = idx % blocks_x;
                let by = idx / blocks_x;
                let wx = bx as f32 * 4.0 + 2.0;
                let wy = by as f32 * 4.0 + 2.0;
                let mut owner_type = 0u8;
                let mut found_id = -1i32;
                for p in parcels.iter() {
                    if p.contains_point(wx, wy) {
                        found_id = p.local_id;
                        if p.sale_price >= 0 && (p.flags & 0x00000080) != 0 {
                            owner_type = 4; // ForSale
                        } else if p.owner_id == agent_id {
                            owner_type = 3; // OwnedByRequester
                        } else if p.is_group_owned {
                            owner_type = 2; // OwnedByGroup
                        } else if p.owner_id != Uuid::nil() {
                            owner_type = 1; // OwnedByOther
                        }
                        break;
                    }
                }
                ids.push((found_id, owner_type));
            }
            ids
        };

        for sequence_id in 0..num_packets {
            let start_block = sequence_id * LAND_BLOCKS_PER_PACKET;
            let end_block = std::cmp::min(start_block + LAND_BLOCKS_PER_PACKET, total_blocks);

            let mut overlay_data = Vec::with_capacity(end_block - start_block);
            for idx in start_block..end_block {
                let bx = idx % blocks_x;
                let by = idx / blocks_x;
                let (my_id, mut byte) = parcel_ids[idx];

                if bx == 0 || (bx > 0 && parcel_ids[idx - 1].0 != my_id) {
                    byte |= LAND_FLAG_BORDER_WEST;
                }
                if by == 0 || (by > 0 && parcel_ids[idx - blocks_x].0 != my_id) {
                    byte |= LAND_FLAG_BORDER_SOUTH;
                }
                overlay_data.push(byte);
            }

            let mut data = BytesMut::with_capacity(overlay_data.len() + 8);
            data.put_i32_le(sequence_id as i32);
            data.put_u16_le(overlay_data.len() as u16);
            data.put_slice(&overlay_data);

            self.send_message(PARCEL_OVERLAY_ID, &data, dest, true, true)
                .await?;
            if num_packets > 16 && sequence_id % 16 == 15 {
                tokio::time::sleep(std::time::Duration::from_millis(10)).await;
            }
        }

        info!(
            "[PARCEL] Sent {} ParcelOverlay packets ({}x{} blocks) to {}",
            num_packets, blocks_x, blocks_y, dest
        );
        Ok(())
    }

    async fn send_parcel_properties_event(&self, session_id: &str, agent_id: Uuid) -> Result<()> {
        use crate::caps::event_queue::EventQueueEvent;
        use base64::{engine::general_purpose::STANDARD as BASE64, Engine as _};
        use serde_json::{json, Map};

        if let Some(caps_manager) = &self.caps_manager {
            let parcel = {
                let parcels = self.parcels.read();
                parcels.first().cloned().unwrap_or_else(|| {
                    crate::modules::land::Parcel::new_default(self.default_region_uuid, agent_id)
                })
            };

            let (owner_prims, group_prims, other_prims, total_prims) =
                self.count_parcel_prims(&parcel);
            let sim_wide_total = {
                let objects = self.scene_objects.read();
                objects.values().filter(|o| o.parent_id == 0).count() as i32
            };

            let bitmap_base64 = format!("b64:{}", BASE64.encode(&parcel.bitmap));

            let mut parcel_data = Map::new();
            parcel_data.insert("LocalID".to_string(), json!(parcel.local_id));
            parcel_data.insert(
                "AABBMax".to_string(),
                json!([self.region_size_x as f32, self.region_size_y as f32, 768.0]),
            );
            parcel_data.insert("AABBMin".to_string(), json!([0.0, 0.0, 0.0]));
            parcel_data.insert("Area".to_string(), json!(parcel.area));
            parcel_data.insert("AuctionID".to_string(), json!(parcel.auction_id));
            parcel_data.insert(
                "AuthBuyerID".to_string(),
                json!(parcel.auth_buyer_id.to_string()),
            );
            parcel_data.insert("Bitmap".to_string(), json!(bitmap_base64));
            parcel_data.insert("Category".to_string(), json!(parcel.category as i32));
            parcel_data.insert("ClaimDate".to_string(), json!("2024-01-01T00:00:00Z"));
            parcel_data.insert("ClaimPrice".to_string(), json!(0));
            parcel_data.insert("Desc".to_string(), json!(parcel.description));
            parcel_data.insert("ParcelFlags".to_string(), json!(parcel.flags));
            parcel_data.insert("GroupID".to_string(), json!(parcel.group_id.to_string()));
            parcel_data.insert("GroupPrims".to_string(), json!(group_prims));
            parcel_data.insert("IsGroupOwned".to_string(), json!(parcel.is_group_owned));
            parcel_data.insert("LandingType".to_string(), json!(parcel.landing_type as i32));
            parcel_data.insert("MaxPrims".to_string(), json!(parcel.max_prims));
            parcel_data.insert(
                "MediaID".to_string(),
                json!("00000000-0000-0000-0000-000000000000"),
            );
            parcel_data.insert("MediaURL".to_string(), json!(parcel.media_url));
            parcel_data.insert("MediaAutoScale".to_string(), json!(parcel.media_auto_scale));
            parcel_data.insert("MusicURL".to_string(), json!(parcel.music_url));
            parcel_data.insert("Name".to_string(), json!(parcel.name));
            parcel_data.insert("OtherCleanTime".to_string(), json!(parcel.other_clean_time));
            parcel_data.insert("OtherCount".to_string(), json!(0));
            parcel_data.insert("OtherPrims".to_string(), json!(other_prims));
            parcel_data.insert("OwnerID".to_string(), json!(parcel.owner_id.to_string()));
            parcel_data.insert("OwnerPrims".to_string(), json!(owner_prims));
            parcel_data.insert("ParcelPrimBonus".to_string(), json!(1.0));
            parcel_data.insert("PassHours".to_string(), json!(parcel.pass_hours));
            parcel_data.insert("PassPrice".to_string(), json!(parcel.pass_price));
            parcel_data.insert("PublicCount".to_string(), json!(0));
            parcel_data.insert("RegionDenyAnonymous".to_string(), json!(false));
            parcel_data.insert("RegionDenyIdentified".to_string(), json!(false));
            parcel_data.insert("RegionDenyTransacted".to_string(), json!(false));
            parcel_data.insert("RegionPushOverride".to_string(), json!(false));
            parcel_data.insert("RentPrice".to_string(), json!(0));
            parcel_data.insert("RequestResult".to_string(), json!(0));
            parcel_data.insert("SalePrice".to_string(), json!(parcel.sale_price));
            parcel_data.insert("SelectedPrims".to_string(), json!(0));
            parcel_data.insert("SelfCount".to_string(), json!(0));
            parcel_data.insert("SequenceID".to_string(), json!(0));
            parcel_data.insert(
                "SimWideMaxPrims".to_string(),
                json!(parcel.sim_wide_max_prims),
            );
            parcel_data.insert("SimWideTotalPrims".to_string(), json!(sim_wide_total));
            parcel_data.insert("SnapSelection".to_string(), json!(true));
            parcel_data.insert(
                "SnapshotID".to_string(),
                json!(parcel.snapshot_id.to_string()),
            );
            parcel_data.insert("Status".to_string(), json!(parcel.status as i32));
            parcel_data.insert("TotalPrims".to_string(), json!(total_prims));
            parcel_data.insert(
                "UserLocation".to_string(),
                json!(parcel.landing_point.to_vec()),
            );
            parcel_data.insert(
                "UserLookAt".to_string(),
                json!(parcel.landing_look_at.to_vec()),
            );
            parcel_data.insert("SeeAVs".to_string(), json!(true));
            parcel_data.insert("AnyAVSounds".to_string(), json!(true));
            parcel_data.insert("GroupAVSounds".to_string(), json!(true));

            let mut media_data = Map::new();
            media_data.insert("MediaDesc".to_string(), json!(""));
            media_data.insert("MediaHeight".to_string(), json!(0));
            media_data.insert("MediaWidth".to_string(), json!(0));
            media_data.insert("MediaLoop".to_string(), json!(false));
            media_data.insert("MediaType".to_string(), json!("none/none"));
            media_data.insert("ObscureMedia".to_string(), json!(false));
            media_data.insert("ObscureMusic".to_string(), json!(false));

            let mut age_block = Map::new();
            age_block.insert("RegionDenyAgeUnverified".to_string(), json!(false));

            let mut env_block = Map::new();
            env_block.insert("ParcelEnvironmentVersion".to_string(), json!(-1));
            env_block.insert("RegionAllowEnvironmentOverride".to_string(), json!(true));

            let mut access_block = Map::new();
            access_block.insert("RegionAllowAccessOverride".to_string(), json!(true));

            let event = EventQueueEvent {
                message: "ParcelProperties".to_string(),
                body: json!({
                    "ParcelData": [parcel_data],
                    "MediaData": [media_data],
                    "AgeVerificationBlock": [age_block],
                    "ParcelEnvironmentBlock": [env_block],
                    "RegionAllowAccessBlock": [access_block]
                }),
            };

            caps_manager
                .get_event_queue()
                .send_event(session_id, event)
                .await;
            info!(
                "[PARCEL] Sent ParcelProperties event '{}' via EventQueue to session {}",
                parcel.name, session_id
            );
        }

        Ok(())
    }

