    async fn send_agent_wearables_update(
        &self,
        agent_id: Uuid,
        session_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        use crate::udp::messages::AgentWearablesUpdateMessage;

        let mut wearables_msg = AgentWearablesUpdateMessage::new(agent_id, session_id);
        wearables_msg.serial_num = self.avatar_factory.next_serial_num(agent_id).await;
        let mut loaded_any = false;
        let mut cof_slots: std::collections::HashSet<u8> = std::collections::HashSet::new();

        if let Some(db) = &self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                let cof_links: Vec<(Uuid, Uuid, i32)> = match sqlx::query_as(
                    r#"SELECT i.inventoryid, i.assetid, i.flags
                       FROM inventoryitems i
                       JOIN inventoryfolders f ON i.parentfolderid = f.folderid
                       WHERE f.agentid = $1 AND f.type = 46 AND i.assettype = 24"#,
                )
                .bind(agent_id)
                .fetch_all(pool)
                .await
                {
                    Ok(r) => r,
                    Err(e) => {
                        warn!("[WEARABLES] COF query failed for {}: {}", agent_id, e);
                        vec![]
                    }
                };

                if !cof_links.is_empty() {
                    info!(
                        "[WEARABLES] Found {} COF link items for agent {}",
                        cof_links.len(),
                        agent_id
                    );
                    for (_link_item_id, linked_item_id, _link_flags) in &cof_links {
                        let real_item: Option<(Uuid, i32)> = sqlx::query_as::<_, (Uuid, i32)>(
                            "SELECT assetid, flags FROM inventoryitems WHERE inventoryid = $1",
                        )
                        .bind(linked_item_id)
                        .fetch_optional(pool)
                        .await
                        .ok()
                        .flatten();

                        if let Some((asset_id, real_flags)) = real_item {
                            let wtype = real_flags as u8;
                            wearables_msg.add_wearable(*linked_item_id, asset_id, wtype);
                            cof_slots.insert(wtype);
                            loaded_any = true;
                            info!(
                                "[WEARABLES] COF slot {}: item={} asset={}",
                                wtype, linked_item_id, asset_id
                            );

                            let name = format!("Wearable {}:0", wtype);
                            let value = format!("{}:{}", linked_item_id, asset_id);
                            let _ = sqlx::query(
                                "INSERT INTO avatars (principalid, name, value) VALUES ($1::uuid, $2, $3) \
                                 ON CONFLICT (principalid, name) DO UPDATE SET value = $3"
                            )
                            .bind(agent_id.to_string())
                            .bind(&name)
                            .bind(&value)
                            .execute(pool)
                            .await;
                        }
                    }
                }

                let rows: Vec<(String, String)> = match sqlx::query_as(
                    "SELECT name, value FROM avatars WHERE principalid = $1::uuid AND name LIKE 'Wearable %'"
                )
                .bind(agent_id.to_string())
                .fetch_all(pool)
                .await {
                    Ok(r) => r,
                    Err(e) => {
                        warn!("[WEARABLES] Avatars query failed for {}: {}", agent_id, e);
                        vec![]
                    }
                };

                let mut avatars_slots: std::collections::HashSet<u8> =
                    std::collections::HashSet::new();
                for (name, value) in rows {
                    if let Some(wearable_type) = name.strip_prefix("Wearable ") {
                        let wtype: u8 = wearable_type
                            .split(':')
                            .next()
                            .and_then(|s| s.parse().ok())
                            .unwrap_or(0);

                        if cof_slots.contains(&wtype) || avatars_slots.contains(&wtype) {
                            continue;
                        }

                        let parts: Vec<&str> = value.split(':').collect();
                        if parts.len() == 2 {
                            if let (Ok(item_id), Ok(asset_id)) =
                                (Uuid::parse_str(parts[0]), Uuid::parse_str(parts[1]))
                            {
                                let exists: bool = sqlx::query_scalar::<_, i64>(
                                    "SELECT COUNT(*) FROM inventoryitems WHERE inventoryid = $1",
                                )
                                .bind(item_id)
                                .fetch_one(pool)
                                .await
                                .unwrap_or(0)
                                    > 0;

                                if !exists {
                                    let (asset_type, folder_type) = if wtype <= 3 {
                                        (13i32, 13i32)
                                    } else {
                                        (5i32, 5i32)
                                    };
                                    let wname = match wtype {
                                        0 => "Default Shape",
                                        1 => "Default Skin",
                                        2 => "Default Hair",
                                        3 => "Default Eyes",
                                        4 => "Default Shirt",
                                        _ => "Default Pants",
                                    };
                                    let folder_id: Option<Uuid> = sqlx::query_scalar(
                                        "SELECT folderid FROM inventoryfolders WHERE agentid = $1 AND type = $2 LIMIT 1"
                                    )
                                    .bind(agent_id).bind(folder_type)
                                    .fetch_optional(pool).await.ok().flatten();

                                    if let Some(fid) = folder_id {
                                        let _ = sqlx::query(
                                            "INSERT INTO inventoryitems (inventoryid, assetid, assettype, inventoryname, \
                                             inventorydescription, inventorynextpermissions, inventorycurrentpermissions, \
                                             invtype, creatorid, inventorybasepermissions, inventoryeveryonepermissions, \
                                             saleprice, saletype, creationdate, groupid, groupowned, flags, \
                                             parentfolderid, avatarid, inventorygrouppermissions) \
                                             VALUES ($1, $2, $3, $4, '', 2147483647, 2147483647, 18, $5, \
                                             2147483647, 0, 0, 0, $6, '00000000-0000-0000-0000-000000000000'::uuid, \
                                             0, $7, $8, $5, 0)"
                                        )
                                        .bind(item_id).bind(asset_id).bind(asset_type)
                                        .bind(wname).bind(agent_id)
                                        .bind(chrono::Utc::now().timestamp() as i32)
                                        .bind(wtype as i32).bind(fid)
                                        .execute(pool).await;
                                        info!("[WEARABLES] Auto-created missing inventory item {} ({}) for agent {}", item_id, wname, agent_id);
                                    }
                                }

                                wearables_msg.add_wearable(item_id, asset_id, wtype);
                                avatars_slots.insert(wtype);
                                loaded_any = true;
                            }
                        }
                    }
                }

                if loaded_any {
                    info!("[WEARABLES] Loaded {} total wearables ({} from COF, rest from avatars) for agent {}",
                          wearables_msg.wearables.len(), cof_slots.len(), agent_id);
                }
            }
        }

        if !loaded_any {
            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    let direct_items: Vec<(Uuid, Uuid, i32)> = sqlx::query_as(
                        r#"SELECT DISTINCT ON (i.flags) i.inventoryid, i.assetid, i.flags
                           FROM inventoryitems i
                           JOIN inventoryfolders f ON i.parentfolderid = f.folderid
                           WHERE f.agentid = $1 AND i.assettype IN (13, 5) AND i.flags BETWEEN 0 AND 5
                           ORDER BY i.flags, i.inventoryid"#
                    )
                    .bind(agent_id)
                    .fetch_all(pool)
                    .await
                    .unwrap_or_default();

                    for (item_id, asset_id, flags) in &direct_items {
                        wearables_msg.add_wearable(*item_id, *asset_id, *flags as u8);
                        loaded_any = true;
                    }

                    if loaded_any {
                        info!("[WEARABLES] Loaded {} wearables from direct inventory query for agent {}",
                              direct_items.len(), agent_id);
                        for (item_id, asset_id, flags) in &direct_items {
                            let name = format!("Wearable {}:0", flags);
                            let value = format!("{}:{}", item_id, asset_id);
                            let _ = sqlx::query(
                                "INSERT INTO avatars (principalid, name, value) VALUES ($1::uuid, $2, $3) \
                                 ON CONFLICT (principalid, name) DO UPDATE SET value = $3"
                            )
                            .bind(agent_id.to_string())
                            .bind(&name)
                            .bind(&value)
                            .execute(pool)
                            .await;
                        }
                    }
                }
            }

            if !loaded_any {
                warn!(
                    "[WEARABLES] No wearables found for {}, using default Ruth",
                    agent_id
                );
                wearables_msg =
                    AgentWearablesUpdateMessage::with_default_ruth(agent_id, session_id);
            }
        }

        let data = wearables_msg.serialize();

        self.send_message(AGENT_WEARABLES_UPDATE_ID, &data, dest, true, true)
            .await?;
        info!(
            "[WEARABLES] Sent AgentWearablesUpdate with {} wearables to {}",
            wearables_msg.wearables.len(),
            dest
        );

        Self::ensure_cof_populated(agent_id, &wearables_msg.wearables, &self.db_connection).await;

        Ok(())
    }

    /// Send BulkUpdateInventory via EventQueue for the actual wearable items that COF links point to.
    /// This pre-populates the viewer's gInventory so COF link resolution succeeds in
    /// LLInitialWearablesFetch::processContents() → collectDescendentsIf(LLFindWearables).
    async fn send_cof_target_items_bulk_update(&self, agent_id: Uuid) -> Result<()> {
        let pool = self
            .db_connection
            .as_ref()
            .and_then(|db| db.postgres_pool())
            .ok_or_else(|| anyhow!("No database connection"))?;

        // Query COF link items and their target wearable items in one join
        let rows: Vec<(
            Uuid,
            Uuid,
            Uuid,
            String,
            String,
            i32,
            i32,
            i32,
            i32,
            i32,
            i32,
            i32,
            i32,
        )> = sqlx::query_as(
            r#"SELECT t.inventoryid, t.assetid, t.parentfolderid,
                      t.inventoryname, COALESCE(t.inventorydescription, ''),
                      t.assettype, t.invtype, t.flags,
                      t.inventorycurrentpermissions, t.inventorybasepermissions,
                      t.inventoryeveryonepermissions, t.inventorynextpermissions,
                      t.inventorygrouppermissions
               FROM inventoryitems link
               JOIN inventoryfolders cof ON link.parentfolderid = cof.folderid
               JOIN inventoryitems t ON link.assetid = t.inventoryid
               WHERE cof.agentid = $1 AND cof.type = 46 AND link.assettype = 24"#,
        )
        .bind(agent_id)
        .fetch_all(pool)
        .await
        .unwrap_or_default();

        if rows.is_empty() {
            info!(
                "[WEARABLES] No COF target items found for BulkUpdateInventory for agent {}",
                agent_id
            );
            return Ok(());
        }

        let items: Vec<crate::services::traits::InventoryItem> = rows
            .iter()
            .map(|r| crate::services::traits::InventoryItem {
                item_id: r.0,
                asset_id: r.1,
                folder_id: r.2,
                owner_id: agent_id,
                creator_id: agent_id,
                creator_data: String::new(),
                name: r.3.clone(),
                description: r.4.clone(),
                asset_type: r.5,
                inv_type: r.6,
                flags: r.7 as u32,
                creation_date: 0,
                base_permissions: r.9 as u32,
                current_permissions: r.8 as u32,
                everyone_permissions: r.10 as u32,
                next_permissions: r.11 as u32,
                group_permissions: r.12 as u32,
                group_id: Uuid::nil(),
                group_owned: false,
                sale_price: 0,
                sale_type: 0,
            })
            .collect();

        // Get EQ session ID for this agent
        let caps = self
            .caps_manager
            .as_ref()
            .ok_or_else(|| anyhow!("No caps manager"))?;
        let circuit_code = self
            .session_manager
            .get_session_by_agent_id(agent_id)
            .map(|s| s.circuit_code)
            .ok_or_else(|| anyhow!("No session for agent"))?;
        let caps_session = caps
            .get_session_by_circuit_code(circuit_code)
            .await
            .ok_or_else(|| anyhow!("No caps session for circuit"))?;

        info!(
            "[WEARABLES] Sending BulkUpdateInventory with {} target wearable items for agent {}",
            items.len(),
            agent_id
        );
        self.send_bulk_update_inventory_eq(agent_id, &caps_session.session_id, &[], &items)
            .await?;
        Ok(())
    }

    async fn ensure_cof_populated(
        agent_id: Uuid,
        wearables: &[crate::udp::messages::WearableEntry],
        db_connection: &Option<Arc<crate::database::multi_backend::DatabaseConnection>>,
    ) {
        let db = match db_connection {
            Some(db) => db,
            None => return,
        };
        let pool = match db.postgres_pool() {
            Some(p) => p,
            None => return,
        };

        let cof_folder: Option<(Uuid,)> = sqlx::query_as(
            "SELECT folderid FROM inventoryfolders WHERE agentid = $1 AND type = 46",
        )
        .bind(agent_id)
        .fetch_optional(pool)
        .await
        .ok()
        .flatten();

        let cof_folder_id = match cof_folder {
            Some((id,)) => id,
            None => return,
        };

        let existing_count: i64 = sqlx::query_as::<_, (i64,)>(
            "SELECT COUNT(*) FROM inventoryitems WHERE parentfolderid = $1",
        )
        .bind(cof_folder_id)
        .fetch_one(pool)
        .await
        .map(|(c,)| c)
        .unwrap_or(0);

        if existing_count > 0 {
            info!(
                "[COF] COF has {} existing items, preserving them for agent {}",
                existing_count, agent_id
            );
            return;
        }

        info!(
            "[COF] COF is empty (first login), populating with {} default links for {}",
            wearables.len(),
            agent_id
        );

        let wearable_names = ["Shape", "Skin", "Hair", "Eyes", "Shirt", "Pants"];
        for wearable in wearables {
            if wearable.wearable_type > 5 {
                continue;
            }
            let link_id = Uuid::new_v4();
            let name = format!(
                "Default {}",
                wearable_names
                    .get(wearable.wearable_type as usize)
                    .unwrap_or(&"Item")
            );
            let _ = sqlx::query(
                r#"INSERT INTO inventoryitems
                   (inventoryid, assetid, assettype, parentfolderid, avatarid, inventoryname, inventorydescription,
                    inventorynextpermissions, inventorycurrentpermissions, invtype, creatorid,
                    inventorybasepermissions, inventoryeveryonepermissions, inventorygrouppermissions,
                    saleprice, saletype, creationdate, groupid, groupowned, flags)
                   VALUES ($1, $2, 24, $3, $4, $5, '', 2147483647, 2147483647, 18, $6,
                           2147483647, 0, 0, 0, 0, EXTRACT(EPOCH FROM NOW())::integer,
                           '00000000-0000-0000-0000-000000000000', 0, $7)"#
            )
            .bind(link_id)
            .bind(wearable.item_id)
            .bind(cof_folder_id)
            .bind(agent_id)
            .bind(&name)
            .bind(agent_id.to_string())
            .bind(wearable.wearable_type as i32)
            .execute(pool)
            .await;
        }

        info!(
            "[COF] Populated COF with default links for first-login agent {}",
            agent_id
        );
    }

    async fn load_appearance_from_db_fast(&self, agent_id: Uuid) {
        let db = match &self.db_connection {
            Some(db) => db,
            None => {
                info!(
                    "[APPEARANCE] No DB connection, using Ruth defaults for {}",
                    agent_id
                );
                self.avatar_factory
                    .create_appearance_with_ruth_defaults(agent_id)
                    .await;
                return;
            }
        };

        let mut texture_entries: Vec<(usize, Uuid)> = Vec::new();
        let mut visual_params: Vec<u8> = Vec::new();
        let mut raw_texture_entry_hex: Option<String> = None;

        match db.as_ref() {
            crate::database::multi_backend::DatabaseConnection::PostgreSQL(pool) => {
                let rows: Vec<(String, String)> = match sqlx::query_as(
                    "SELECT name, value FROM avatars WHERE principalid = $1::uuid",
                )
                .bind(agent_id.to_string())
                .fetch_all(pool)
                .await
                {
                    Ok(r) => r,
                    Err(e) => {
                        warn!("[APPEARANCE] DB query failed for {}: {}", agent_id, e);
                        self.avatar_factory
                            .create_appearance_with_ruth_defaults(agent_id)
                            .await;
                        return;
                    }
                };

                if rows.is_empty() {
                    info!(
                        "[APPEARANCE] No saved appearance for {}, using Ruth defaults",
                        agent_id
                    );
                    self.avatar_factory
                        .create_appearance_with_ruth_defaults(agent_id)
                        .await;
                    return;
                }

                for (name, value) in &rows {
                    if name.starts_with("Texture ") {
                        if let Ok(idx) = name[8..].parse::<usize>() {
                            if let Ok(tex_id) = Uuid::parse_str(value) {
                                texture_entries.push((idx, tex_id));
                            }
                        }
                    } else if name == "VisualParams" {
                        visual_params = (0..value.len() / 2)
                            .filter_map(|i| u8::from_str_radix(&value[i * 2..i * 2 + 2], 16).ok())
                            .collect();
                    } else if name == "RawTextureEntry" {
                        raw_texture_entry_hex = Some(value.clone());
                    }
                }
            }
            crate::database::multi_backend::DatabaseConnection::MySQL(pool) => {
                let rows: Vec<(String, String)> =
                    match sqlx::query_as("SELECT name, value FROM Avatars WHERE PrincipalID = ?")
                        .bind(agent_id.to_string())
                        .fetch_all(pool)
                        .await
                    {
                        Ok(r) => r,
                        Err(e) => {
                            warn!("[APPEARANCE] DB query failed for {}: {}", agent_id, e);
                            self.avatar_factory
                                .create_appearance_with_ruth_defaults(agent_id)
                                .await;
                            return;
                        }
                    };

                if rows.is_empty() {
                    info!(
                        "[APPEARANCE] No saved appearance for {}, using Ruth defaults",
                        agent_id
                    );
                    self.avatar_factory
                        .create_appearance_with_ruth_defaults(agent_id)
                        .await;
                    return;
                }

                for (name, value) in &rows {
                    if name.starts_with("Texture ") {
                        if let Ok(idx) = name[8..].parse::<usize>() {
                            if let Ok(tex_id) = Uuid::parse_str(value) {
                                texture_entries.push((idx, tex_id));
                            }
                        }
                    } else if name == "VisualParams" {
                        visual_params = (0..value.len() / 2)
                            .filter_map(|i| u8::from_str_radix(&value[i * 2..i * 2 + 2], 16).ok())
                            .collect();
                    } else if name == "RawTextureEntry" {
                        raw_texture_entry_hex = Some(value.clone());
                    }
                }
            }
            _ => {
                info!("[APPEARANCE] Unsupported DB backend for appearance, using Ruth defaults for {}", agent_id);
                self.avatar_factory
                    .create_appearance_with_ruth_defaults(agent_id)
                    .await;
                return;
            }
        }

        if let Some(ref hex) = raw_texture_entry_hex {
            let raw_te: Vec<u8> = (0..hex.len() / 2)
                .filter_map(|i| u8::from_str_radix(&hex[i * 2..i * 2 + 2], 16).ok())
                .collect();
            if !raw_te.is_empty() {
                let parsed = crate::avatar::factory::parse_texture_entry_uuids(&raw_te);
                if !parsed.is_empty() {
                    texture_entries = parsed;
                }
                self.avatar_factory
                    .set_raw_texture_entry(agent_id, raw_te)
                    .await;
                info!(
                    "[APPEARANCE] Restored raw_texture_entry from DB for {}",
                    agent_id
                );
            }
        }

        if texture_entries.is_empty() && visual_params.is_empty() {
            info!(
                "[APPEARANCE] No appearance data in DB for {}, using Ruth defaults",
                agent_id
            );
            self.avatar_factory
                .create_appearance_with_ruth_defaults(agent_id)
                .await;
            return;
        }

        self.avatar_factory
            .set_appearance_from_db(agent_id, &texture_entries, visual_params)
            .await;
        info!("[APPEARANCE-FAST] Loaded appearance (no bake preload) for {} — ObjectUpdate can proceed", agent_id);

        {
            let bg_server = self.clone();
            let bg_agent = agent_id;
            tokio::spawn(async move {
                bg_server.load_baked_textures_background(bg_agent).await;
            });
        }
    }

    async fn load_baked_textures_background(&self, agent_id: Uuid) {
        let appearance = self.avatar_factory.get_appearance(agent_id).await;
        let texture_entries: Vec<(usize, Uuid)> = match appearance {
            Some(ref app) => {
                let mut entries = Vec::new();
                for (i, tex) in app.texture_ids.iter().enumerate() {
                    if !tex.is_nil() {
                        entries.push((i, *tex));
                    }
                }
                entries
            }
            None => return,
        };

        if let Some(ref caps_manager) = self.caps_manager {
            let bake_indices: &[usize] = &crate::avatar::factory::BAKE_INDICES;
            let default_uuid = Uuid::parse_str(crate::avatar::factory::DEFAULT_AVATAR_TEXTURE)
                .unwrap_or(Uuid::nil());
            let bake_tex_ids: Vec<(usize, Uuid)> = texture_entries
                .iter()
                .filter(|(idx, id): &&(usize, Uuid)| {
                    bake_indices.contains(idx) && !id.is_nil() && *id != default_uuid
                })
                .cloned()
                .collect();

            if bake_tex_ids.is_empty() {
                return;
            }

            if let Some(ref db_conn) = self.db_connection {
                if let Some(pool) = db_conn.postgres_pool() {
                    let mut restored = 0usize;
                    for (_face_idx, tex_id) in &bake_tex_ids {
                        if caps_manager.get_baked_texture(tex_id).is_some() {
                            restored += 1;
                            continue;
                        }
                        let row: Option<(Vec<u8>,)> =
                            sqlx::query_as("SELECT data FROM assets WHERE id = $1")
                                .bind(*tex_id)
                                .fetch_optional(pool)
                                .await
                                .ok()
                                .flatten();

                        if let Some((data,)) = row {
                            if data.len() >= crate::avatar::factory::MIN_BAKE_TEXTURE_SIZE {
                                caps_manager.store_baked_texture(*tex_id, data);
                                self.avatar_factory.cache_texture(*tex_id).await;
                                restored += 1;
                            }
                        }
                    }
                    info!(
                        "[APPEARANCE-BG] Restored {}/{} baked textures from DB for {}",
                        restored,
                        bake_tex_ids.len(),
                        agent_id
                    );
                }
            }
        }
    }

    async fn load_appearance_from_db(&self, agent_id: Uuid) {
        let db = match &self.db_connection {
            Some(db) => db,
            None => {
                info!(
                    "[APPEARANCE] No DB connection, using Ruth defaults for {}",
                    agent_id
                );
                self.avatar_factory
                    .create_appearance_with_ruth_defaults(agent_id)
                    .await;
                return;
            }
        };

        let mut texture_entries: Vec<(usize, Uuid)> = Vec::new();
        let mut visual_params: Vec<u8> = Vec::new();
        let mut raw_texture_entry_hex: Option<String> = None;
        let mut wearable_cache_entries: Vec<(usize, Uuid, Uuid)> = Vec::new();

        match db.as_ref() {
            crate::database::multi_backend::DatabaseConnection::PostgreSQL(pool) => {
                let rows: Vec<(String, String)> = match sqlx::query_as(
                    "SELECT name, value FROM avatars WHERE principalid = $1::uuid",
                )
                .bind(agent_id.to_string())
                .fetch_all(pool)
                .await
                {
                    Ok(r) => r,
                    Err(e) => {
                        warn!("[APPEARANCE] DB query failed for {}: {}", agent_id, e);
                        self.avatar_factory
                            .create_appearance_with_ruth_defaults(agent_id)
                            .await;
                        return;
                    }
                };

                if rows.is_empty() {
                    info!(
                        "[APPEARANCE] No saved appearance for {}, using Ruth defaults",
                        agent_id
                    );
                    self.avatar_factory
                        .create_appearance_with_ruth_defaults(agent_id)
                        .await;
                    return;
                }

                for (name, value) in &rows {
                    if name.starts_with("Texture ") {
                        if let Ok(idx) = name[8..].parse::<usize>() {
                            if let Ok(tex_id) = Uuid::parse_str(value) {
                                texture_entries.push((idx, tex_id));
                            }
                        }
                    } else if name == "VisualParams" {
                        visual_params = (0..value.len() / 2)
                            .filter_map(|i| u8::from_str_radix(&value[i * 2..i * 2 + 2], 16).ok())
                            .collect();
                    } else if name == "RawTextureEntry" {
                        raw_texture_entry_hex = Some(value.clone());
                    } else if name.starts_with("WearableCache ") {
                        if let Ok(idx) = name[14..].parse::<usize>() {
                            let parts: Vec<&str> = value.split('|').collect();
                            if parts.len() == 2 {
                                if let (Ok(cache_id), Ok(texture_id)) =
                                    (Uuid::parse_str(parts[0]), Uuid::parse_str(parts[1]))
                                {
                                    wearable_cache_entries.push((idx, cache_id, texture_id));
                                }
                            }
                        }
                    }
                }
            }
            crate::database::multi_backend::DatabaseConnection::MySQL(pool) => {
                let rows: Vec<(String, String)> =
                    match sqlx::query_as("SELECT name, value FROM Avatars WHERE PrincipalID = ?")
                        .bind(agent_id.to_string())
                        .fetch_all(pool)
                        .await
                    {
                        Ok(r) => r,
                        Err(e) => {
                            warn!("[APPEARANCE] DB query failed for {}: {}", agent_id, e);
                            self.avatar_factory
                                .create_appearance_with_ruth_defaults(agent_id)
                                .await;
                            return;
                        }
                    };

                if rows.is_empty() {
                    info!(
                        "[APPEARANCE] No saved appearance for {}, using Ruth defaults",
                        agent_id
                    );
                    self.avatar_factory
                        .create_appearance_with_ruth_defaults(agent_id)
                        .await;
                    return;
                }

                for (name, value) in &rows {
                    if name.starts_with("Texture ") {
                        if let Ok(idx) = name[8..].parse::<usize>() {
                            if let Ok(tex_id) = Uuid::parse_str(value) {
                                texture_entries.push((idx, tex_id));
                            }
                        }
                    } else if name == "VisualParams" {
                        visual_params = (0..value.len() / 2)
                            .filter_map(|i| u8::from_str_radix(&value[i * 2..i * 2 + 2], 16).ok())
                            .collect();
                    } else if name == "RawTextureEntry" {
                        raw_texture_entry_hex = Some(value.clone());
                    } else if name.starts_with("WearableCache ") {
                        if let Ok(idx) = name[14..].parse::<usize>() {
                            let parts: Vec<&str> = value.split('|').collect();
                            if parts.len() == 2 {
                                if let (Ok(cache_id), Ok(texture_id)) =
                                    (Uuid::parse_str(parts[0]), Uuid::parse_str(parts[1]))
                                {
                                    wearable_cache_entries.push((idx, cache_id, texture_id));
                                }
                            }
                        }
                    }
                }
            }
        }

        let mut raw_te_bytes: Option<Vec<u8>> = None;
        if let Some(ref hex) = raw_texture_entry_hex {
            let raw_te: Vec<u8> = (0..hex.len() / 2)
                .filter_map(|i| u8::from_str_radix(&hex[i * 2..i * 2 + 2], 16).ok())
                .collect();
            if !raw_te.is_empty() {
                let parsed = crate::avatar::factory::parse_texture_entry_uuids(&raw_te);
                if !parsed.is_empty() {
                    info!(
                        "[APPEARANCE] RawTextureEntry loaded: {} bytes -> {} face UUIDs for {}",
                        raw_te.len(),
                        parsed.len(),
                        agent_id
                    );
                    texture_entries = parsed;
                }
                raw_te_bytes = Some(raw_te);
            }
        }

        if texture_entries.is_empty()
            && visual_params.is_empty()
            && wearable_cache_entries.is_empty()
        {
            info!(
                "[APPEARANCE] No appearance data in DB for {}, using Ruth defaults",
                agent_id
            );
            self.avatar_factory
                .create_appearance_with_ruth_defaults(agent_id)
                .await;
            return;
        }

        info!(
            "[APPEARANCE] Loaded {} textures, {} VP bytes, {} wearable cache from DB for {}",
            texture_entries.len(),
            visual_params.len(),
            wearable_cache_entries.len(),
            agent_id
        );
        self.avatar_factory
            .set_appearance_from_db(agent_id, &texture_entries, visual_params)
            .await;

        if let Some(raw_te) = raw_te_bytes {
            self.avatar_factory
                .set_raw_texture_entry(agent_id, raw_te)
                .await;
            info!(
                "[APPEARANCE] Restored raw_texture_entry from DB for {}",
                agent_id
            );
        }

        if !texture_entries.is_empty() {
            if let Some(ref caps_manager) = self.caps_manager {
                let bake_indices: &[usize] = &crate::avatar::factory::BAKE_INDICES;
                let default_uuid = Uuid::parse_str(crate::avatar::factory::DEFAULT_AVATAR_TEXTURE)
                    .unwrap_or(Uuid::nil());
                let bake_tex_ids: Vec<(usize, Uuid)> = texture_entries
                    .iter()
                    .filter(|(idx, id)| {
                        bake_indices.contains(idx) && !id.is_nil() && *id != default_uuid
                    })
                    .map(|(idx, id)| (*idx, *id))
                    .collect();

                if !bake_tex_ids.is_empty() {
                    let mut restored = 0usize;
                    let mut bad_face_ids: Vec<(usize, Uuid)> = Vec::new();
                    if let Some(ref db_conn) = self.db_connection {
                        if let Some(pool) = db_conn.postgres_pool() {
                            for (face_idx, tex_id) in &bake_tex_ids {
                                if caps_manager.get_baked_texture(tex_id).is_some() {
                                    restored += 1;
                                    continue;
                                }
                                let row: Option<(Vec<u8>,)> =
                                    sqlx::query_as("SELECT data FROM assets WHERE id = $1")
                                        .bind(*tex_id)
                                        .fetch_optional(pool)
                                        .await
                                        .ok()
                                        .flatten();

                                match row {
                                    Some((data,))
                                        if data.len()
                                            >= crate::avatar::factory::MIN_BAKE_TEXTURE_SIZE =>
                                    {
                                        caps_manager.store_baked_texture(*tex_id, data);
                                        self.avatar_factory.cache_texture(*tex_id).await;
                                        restored += 1;
                                    }
                                    Some((data,)) => {
                                        warn!("[APPEARANCE] Undersized baked texture face[{}]={} ({} bytes < {}) — replacing with default", face_idx, tex_id, data.len(), crate::avatar::factory::MIN_BAKE_TEXTURE_SIZE);
                                        bad_face_ids.push((*face_idx, *tex_id));
                                        let _ = sqlx::query("DELETE FROM assets WHERE id = $1")
                                            .bind(*tex_id)
                                            .execute(pool)
                                            .await;
                                    }
                                    None => {
                                        warn!("[APPEARANCE] Missing baked texture face[{}]={} — replacing with default", face_idx, tex_id);
                                        bad_face_ids.push((*face_idx, *tex_id));
                                    }
                                }
                            }
                        }
                    }

                    if !bad_face_ids.is_empty() {
                        warn!(
                            "[APPEARANCE] Cleaning {} bad bake faces from appearance for {}",
                            bad_face_ids.len(),
                            agent_id
                        );
                        for (face_idx, _bad_id) in &bad_face_ids {
                            if let Some(entry) =
                                texture_entries.iter_mut().find(|(idx, _)| idx == face_idx)
                            {
                                entry.1 = default_uuid;
                            }
                        }
                        self.avatar_factory
                            .set_appearance_from_db(agent_id, &texture_entries, vec![])
                            .await;
                        self.avatar_factory.clear_raw_texture_entry(agent_id).await;
                        info!("[APPEARANCE] Cleared raw_texture_entry and reset {} bad faces to default for {}", bad_face_ids.len(), agent_id);
                    }

                    info!(
                        "[APPEARANCE] Restored {}/{} baked textures from DB for {}",
                        restored,
                        bake_tex_ids.len(),
                        agent_id
                    );
                    if restored == 0 && bad_face_ids.is_empty() {
                        warn!("[APPEARANCE] No valid baked textures restored - clearing stale raw_texture_entry for {}", agent_id);
                        self.avatar_factory.clear_raw_texture_entry(agent_id).await;
                    }
                }
            }
        }

        if !wearable_cache_entries.is_empty() {
            let cache_items: Vec<(usize, Uuid)> = wearable_cache_entries
                .iter()
                .map(|(idx, cid, _)| (*idx, *cid))
                .collect();
            let tex_items: Vec<(usize, Uuid)> = wearable_cache_entries
                .iter()
                .map(|(idx, _, tid)| (*idx, *tid))
                .collect();
            self.avatar_factory
                .store_wearable_cache_from_viewer(agent_id, &cache_items, &tex_items)
                .await;
            info!(
                "[APPEARANCE] Restored {} WearableCache items from DB for {}",
                wearable_cache_entries.len(),
                agent_id
            );
        }
    }

    async fn send_avatar_appearance(&self, agent_id: Uuid, dest: SocketAddr) -> Result<()> {
        self.send_avatar_appearance_inner(agent_id, dest, false)
            .await
    }

    async fn send_avatar_appearance_ruth_only(
        &self,
        agent_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        self.send_avatar_appearance_inner(agent_id, dest, true)
            .await
    }

    // Source: OpenSim C# LLClientView.cs:4440 SendAppearance()
    // Format: Sender(ID+IsTrial) + ObjectData(TextureEntry) + VisualParam(Variable) + AppearanceData(Variable) + AppearanceHover(Variable)
    async fn send_avatar_appearance_inner(
        &self,
        agent_id: Uuid,
        dest: SocketAddr,
        force_ruth: bool,
    ) -> Result<()> {
        let mut data = Vec::with_capacity(500);

        data.extend_from_slice(agent_id.as_bytes());
        data.push(0); // IsTrial

        let appearance = self.avatar_factory.get_appearance(agent_id).await;
        let (texture_entry, visual_params, source) = if force_ruth {
            let vp = if let Some(ref app) = appearance {
                if app.visual_params.len() >= 218 {
                    app.visual_params.clone()
                } else {
                    Self::get_ruth_visual_params().to_vec()
                }
            } else {
                Self::get_ruth_visual_params().to_vec()
            };
            (
                Self::build_default_rebake_texture_entry(),
                vp,
                "ruth-fallback-initial",
            )
        } else if let Some(ref app) = appearance {
            if let Some(ref raw_te) = app.raw_texture_entry {
                let vp = if app.visual_params.len() >= 218 {
                    app.visual_params.clone()
                } else {
                    Self::get_ruth_visual_params().to_vec()
                };
                let bakes_te = crate::avatar::factory::get_bakes_bytes(raw_te);
                (bakes_te, vp, "viewer-baked-filtered")
            } else {
                let full_te = Self::build_texture_entry_from_appearance(app);
                if full_te.len() > 16 {
                    let bakes_te = crate::avatar::factory::get_bakes_bytes(&full_te);
                    (
                        bakes_te,
                        app.visual_params.clone(),
                        "factory-built-filtered",
                    )
                } else {
                    let vp = if app.visual_params.len() >= 218 {
                        app.visual_params.clone()
                    } else {
                        Self::get_ruth_visual_params().to_vec()
                    };
                    (
                        Self::build_default_rebake_texture_entry(),
                        vp,
                        "ruth-fallback",
                    )
                }
            }
        } else {
            (
                Self::build_default_rebake_texture_entry(),
                Self::get_ruth_visual_params().to_vec(),
                "ruth-fallback",
            )
        };

        data.extend_from_slice(&(texture_entry.len() as u16).to_le_bytes());
        data.extend_from_slice(&texture_entry);

        data.push(visual_params.len() as u8);
        data.extend_from_slice(&visual_params);

        // AppearanceData count = 0 (legacy mode, matching OpenSim C# LLClientView.cs:4448)
        // OpenSim C# does NOT send AppearanceVersion/CofVersion — this avoids SSB mode
        // which causes CofVersion checking and endless rebake loops in the viewer
        data.push(0); // AppearanceData count = 0 (no AppearanceVersion, no CofVersion, no Flags)
        data.push(1); // AppearanceHover count = 1
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&0f32.to_le_bytes());

        self.send_message(AVATAR_APPEARANCE_ID, &data, dest, true, true)
            .await?;
        info!(
            "[APPEARANCE] Sent AvatarAppearance ({}, {} TE bytes, legacy mode) to {}",
            source,
            texture_entry.len(),
            dest
        );
        Ok(())
    }

    async fn send_rebake_avatar_textures(&self, texture_id: Uuid, dest: SocketAddr) -> Result<()> {
        let mut data = Vec::with_capacity(16);
        data.extend_from_slice(texture_id.as_bytes());
        self.send_message(REBAKE_AVATAR_TEXTURES_ID, &data, dest, true, false)
            .await?;
        info!(
            "[REBAKE] Sent RebakeAvatarTextures for texture {} to {}",
            texture_id, dest
        );
        Ok(())
    }

    async fn request_rebake_missing_textures(
        &self,
        agent_id: Uuid,
        dest: SocketAddr,
    ) -> Result<u32> {
        let appearance = self.avatar_factory.get_appearance(agent_id).await;
        let default_tex = Uuid::parse_str("c228d1cf-4b5d-4ba8-84f4-899a0796aa97").unwrap();
        let default_avatar_tex = Uuid::parse_str("5748decc-f629-461c-9a36-a35a221fe21f").unwrap();
        let mut rebake_count = 0u32;

        if let Some(ref app) = appearance {
            for &idx in crate::avatar::factory::BAKE_INDICES.iter() {
                if idx >= app.texture_ids.len() {
                    continue;
                }
                let tex_id = app.texture_ids[idx];
                if tex_id.is_nil() || tex_id == default_tex || tex_id == default_avatar_tex {
                    continue;
                }
                let in_cache = if let Some(ref cm) = self.caps_manager {
                    cm.get_baked_texture(&tex_id).is_some()
                } else {
                    false
                };
                if !in_cache {
                    self.send_rebake_avatar_textures(tex_id, dest).await?;
                    rebake_count += 1;
                }
            }
        }

        if rebake_count > 0 {
            info!(
                "[REBAKE] Requested rebake for {} missing baked textures for agent {}",
                rebake_count, agent_id
            );
        }
        Ok(rebake_count)
    }

    fn build_texture_entry_from_appearance(
        appearance: &crate::avatar::factory::AgentAppearanceData,
    ) -> Vec<u8> {
        let mut te = Vec::with_capacity(300);

        let default_tex =
            appearance.texture_ids.first().copied().unwrap_or_else(|| {
                Uuid::parse_str("c228d1cf-4b5d-4ba8-84f4-899a0796aa97").unwrap()
            });
        te.extend_from_slice(default_tex.as_bytes());

        let default_tex_uuid = Uuid::parse_str("c228d1cf-4b5d-4ba8-84f4-899a0796aa97").unwrap();
        for idx in 0..appearance.texture_ids.len() {
            let tex_id = appearance.texture_ids[idx];
            if !tex_id.is_nil() && tex_id != default_tex_uuid && tex_id != default_tex {
                te.extend_from_slice(&Self::encode_face_bitfield(idx as u32));
                te.extend_from_slice(tex_id.as_bytes());
            }
        }

        te.push(0); // Texture section terminator

        te.extend_from_slice(&[0x00, 0x00, 0x00, 0x00]); // RGBA default
        te.push(0);

        te.extend_from_slice(&1.0f32.to_le_bytes()); // RepeatU
        te.push(0);
        te.extend_from_slice(&1.0f32.to_le_bytes()); // RepeatV
        te.push(0);
        te.extend_from_slice(&0i16.to_le_bytes()); // OffsetU
        te.push(0);
        te.extend_from_slice(&0i16.to_le_bytes()); // OffsetV
        te.push(0);
        te.extend_from_slice(&0i16.to_le_bytes()); // Rotation
        te.push(0);

        te.push(0);
        te.push(0); // Material
        te.push(0);
        te.push(0); // Media
        te.push(0);
        te.push(0); // Glow
        te.extend_from_slice(&[0u8; 16]); // MaterialID
        te.push(0); // MaterialID face override terminator

        te
    }

    fn build_default_rebake_texture_entry() -> Vec<u8> {
        let mut te = Vec::with_capacity(300);

        let default_tex = Uuid::parse_str("c228d1cf-4b5d-4ba8-84f4-899a0796aa97").unwrap();
        te.extend_from_slice(default_tex.as_bytes());

        let default_avatar_tex = Uuid::parse_str("5748decc-f629-461c-9a36-a35a221fe21f").unwrap();
        let bake_faces: [u32; 11] = [8, 9, 10, 11, 19, 20, 40, 41, 42, 43, 44];
        for &idx in &bake_faces {
            te.extend_from_slice(&Self::encode_face_bitfield(idx));
            te.extend_from_slice(default_avatar_tex.as_bytes());
        }

        te.push(0); // Texture section terminator

        te.extend_from_slice(&[0x00, 0x00, 0x00, 0x00]); // RGBA
        te.push(0);

        te.extend_from_slice(&1.0f32.to_le_bytes());
        te.push(0);
        te.extend_from_slice(&1.0f32.to_le_bytes());
        te.push(0);
        te.extend_from_slice(&0i16.to_le_bytes());
        te.push(0);
        te.extend_from_slice(&0i16.to_le_bytes());
        te.push(0);
        te.extend_from_slice(&0i16.to_le_bytes());
        te.push(0);

        te.push(0);
        te.push(0); // Material
        te.push(0);
        te.push(0); // Media
        te.push(0);
        te.push(0); // Glow
        te.extend_from_slice(&[0u8; 16]); // MaterialID
        te.push(0); // MaterialID face override terminator

        te
    }

    fn encode_face_bitfield(face: u32) -> Vec<u8> {
        let bitfield: u64 = 1u64 << face;

        let mut byte_length = 0;
        let mut tmp = bitfield;
        while tmp != 0 {
            tmp >>= 7;
            byte_length += 1;
        }

        if byte_length == 0 {
            return vec![0];
        }

        let mut result = Vec::with_capacity(byte_length);
        for i in 0..byte_length {
            let shift = 7 * (byte_length - i - 1);
            let mut byte = ((bitfield >> shift) & 0x7F) as u8;
            if i < byte_length - 1 {
                byte |= 0x80;
            }
            result.push(byte);
        }
        result
    }

    fn get_ruth_visual_params() -> [u8; 218] {
        crate::avatar::factory::get_ruth_visual_params()
    }

    async fn send_avatar_animation(&self, agent_id: Uuid, dest: SocketAddr) -> Result<()> {
        let mut data = Vec::with_capacity(100);

        // Sender block: AgentID (UUID, 16 bytes)
        data.extend_from_slice(agent_id.as_bytes());

        // AnimationList block count (U8)
        data.push(1); // 1 animation

        // Animation entry:
        // AnimID (UUID, 16 bytes) - STAND animation
        let stand_anim_uuid = Uuid::parse_str("2408fe9e-df1d-1d7d-f4ff-1384fa7b350f")
            .expect("Valid STAND animation UUID");
        data.extend_from_slice(stand_anim_uuid.as_bytes());
        // AnimSequenceID (S32, 4 bytes) - sequence number 1
        data.extend_from_slice(&1i32.to_le_bytes());

        // AnimationSourceList block count (U8)
        // For self-animations (avatar's own animation), count is 0 - no external object sources
        // OpenSim only includes ObjectIDs for animations triggered by external objects
        data.push(0); // 0 sources for self-animations

        // PhysicalAvatarEventList block count (U8)
        data.push(0); // No physical events

        self.send_message(AVATAR_ANIMATION_ID, &data, dest, true, false)
            .await?;
        info!(
            "[ANIMATION] Sent AvatarAnimation (STAND) to agent {} at {}",
            agent_id, dest
        );
        Ok(())
    }

    async fn send_camera_constraint(&self, dest: SocketAddr) -> Result<()> {
        let camera_constraint = CameraConstraintMessage::default_constraint();
        let data = camera_constraint.serialize();

        self.send_message(CAMERA_CONSTRAINT_ID, &data, dest, false, false)
            .await?;
        info!("[CAMERA] Phase 71.14: Sent CameraConstraint to {}", dest);
        Ok(())
    }

    async fn send_improved_terse_object_update(
        &self,
        local_id: u32,
        position: [f32; 3],
        dest: SocketAddr,
    ) -> Result<()> {
        // Use default rotation (identity)
        self.send_improved_terse_object_update_with_rotation(
            local_id,
            position,
            [0.0, 0.0, 0.0, 1.0],
            dest,
        )
        .await
    }

    async fn send_improved_terse_object_update_with_rotation(
        &self,
        local_id: u32,
        position: [f32; 3],
        rotation: [f32; 4], // quaternion [x, y, z, w]
        dest: SocketAddr,
    ) -> Result<()> {
        // Helper to convert float to U16 with range scaling (matches OpenSim Utils.FloatToUInt16Bytes)
        fn float_to_u16(value: f32, range: f32) -> u16 {
            let clamped = value.clamp(-range, range);
            let normalized = (clamped + range) / (2.0 * range);
            (normalized * 65535.0) as u16
        }

        let mut data = Vec::with_capacity(76);

        // RegionData block
        let region_handle: u64 = self.region_handle;
        data.extend_from_slice(&region_handle.to_le_bytes()); // 8 bytes
        data.extend_from_slice(&65535u16.to_le_bytes()); // TimeDilation: 2 bytes

        // ObjectData block count (Variable block)
        data.push(1); // 1 object

        // Data field uses Variable 1 (1-byte length prefix per message template)
        data.push(60); // 60 bytes of avatar data follows

        // LocalID (4 bytes)
        data.extend_from_slice(&local_id.to_le_bytes());

        // State (1 byte) - attachPoint for avatars
        data.push(0);

        // isAvatar flag (1 byte) = 1 for avatars
        data.push(1);

        // CollisionPlane (16 bytes) - Vector4.UnitW (0, 0, 0, 1) for ground plane
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&1f32.to_le_bytes());

        // Position (12 bytes) - Vector3
        data.extend_from_slice(&position[0].to_le_bytes());
        data.extend_from_slice(&position[1].to_le_bytes());
        data.extend_from_slice(&position[2].to_le_bytes());

        // Velocity (6 bytes) - 0x7fff for zero velocity
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());

        // Acceleration (6 bytes) - ALWAYS 0x7fff per OpenSim
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());

        // Rotation (8 bytes) - For standing avatar, X/Y = 0x7fff (neutral)
        // Only Z and W carry rotation
        data.extend_from_slice(&0x7fffu16.to_le_bytes()); // X = 0
        data.extend_from_slice(&0x7fffu16.to_le_bytes()); // Y = 0

        let rz = rotation[2];
        let rw = rotation[3];
        let a = rz * rz + rw * rw;
        if a.abs() < 1e-6 {
            data.extend_from_slice(&0x7fffu16.to_le_bytes());
            data.extend_from_slice(&0xffffu16.to_le_bytes());
        } else {
            let inv_len = 1.0 / a.sqrt();
            data.extend_from_slice(&float_to_u16(rz * inv_len, 1.0).to_le_bytes());
            data.extend_from_slice(&float_to_u16(rw * inv_len, 1.0).to_le_bytes());
        }

        // Angular Velocity (6 bytes) - 0x7fff for zero
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());

        // Texture Entry length (2 bytes) = 0 (no texture update)
        data.extend_from_slice(&0u16.to_le_bytes());

        static DUMP_COUNT: std::sync::atomic::AtomicUsize = std::sync::atomic::AtomicUsize::new(0);
        let count = DUMP_COUNT.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        if count < 5 {
            warn!(
                "[TERSE] Packet hex dump #{} ({} bytes):",
                count + 1,
                data.len()
            );
            for (i, chunk) in data.chunks(16).enumerate() {
                let hex: Vec<String> = chunk.iter().map(|b| format!("{:02x}", b)).collect();
                warn!("[TERSE]   {:04x}: {}", i * 16, hex.join(" "));
            }
        }

        self.send_message(IMPROVED_TERSE_OBJECT_UPDATE_ID, &data, dest, true, true)
            .await?;
        info!(
            "[TERSE] Sent ImprovedTerseObjectUpdate for LocalID {} at ({:.2}, {:.2}, {:.2}) to {}",
            local_id, position[0], position[1], position[2], dest
        );
        Ok(())
    }

    async fn send_improved_terse_object_update_full(
        &self,
        local_id: u32,
        position: [f32; 3],
        velocity: [f32; 3],
        rotation: [f32; 4],
        is_flying: bool,
        dest: SocketAddr,
    ) -> Result<()> {
        // OpenSim-master exact format for ImprovedTerseObjectUpdate (avatar)
        // Reference: LLClientView.cs CreateAvatartImprovedTerseBlock
        fn float_to_u16(value: f32, range: f32) -> u16 {
            let clamped = value.clamp(-range, range);
            let normalized = (clamped + range) / (2.0 * range);
            (normalized * 65535.0) as u16
        }

        let mut data = Vec::with_capacity(76);

        // RegionData block
        let region_handle: u64 = self.region_handle;
        data.extend_from_slice(&region_handle.to_le_bytes()); // 8 bytes
        data.extend_from_slice(&65535u16.to_le_bytes()); // TimeDilation: 2 bytes

        // ObjectData block count (Variable block)
        data.push(1); // 1 object

        // Data field uses Variable 1 (1-byte length prefix per message template)
        data.push(60); // 60 bytes of avatar data follows

        // LocalID (4 bytes)
        data.extend_from_slice(&local_id.to_le_bytes());

        // State/AttachPoint (1 byte) - 0 for avatar
        data.push(0);

        // IsAvatar flag (1 byte) - 1 for avatar
        data.push(1);

        // CollisionPlane (16 bytes) - Vector4.UnitW = (0, 0, 0, 1)
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&0f32.to_le_bytes());
        data.extend_from_slice(&1f32.to_le_bytes());

        // Position (12 bytes)
        data.extend_from_slice(&position[0].to_le_bytes());
        data.extend_from_slice(&position[1].to_le_bytes());
        data.extend_from_slice(&position[2].to_le_bytes());

        // Velocity (6 bytes) - U16 encoded with range 128
        data.extend_from_slice(&float_to_u16(velocity[0], 128.0).to_le_bytes());
        data.extend_from_slice(&float_to_u16(velocity[1], 128.0).to_le_bytes());
        data.extend_from_slice(&float_to_u16(velocity[2], 128.0).to_le_bytes());

        // Acceleration (6 bytes) - ALWAYS 0x7fff (neutral) per OpenSim
        // 0x7fff = 32767 which represents 0.0 in the U16 encoding
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());

        // Rotation (8 bytes) - special handling per OpenSim
        // For non-flying avatars, X and Y are forced to 0x7fff (neutral)
        // Only Z and W carry rotation data
        if !is_flying {
            // X and Y set to neutral (0x7fff = 0.0)
            data.extend_from_slice(&0x7fffu16.to_le_bytes());
            data.extend_from_slice(&0x7fffu16.to_le_bytes());

            // Z and W - normalize and encode
            let rz = rotation[2];
            let rw = rotation[3];
            let a = rz * rz + rw * rw;
            if a.abs() < 1e-6 {
                // Near-zero, use default
                data.extend_from_slice(&0x7fffu16.to_le_bytes());
                data.extend_from_slice(&0xffffu16.to_le_bytes());
            } else {
                let inv_len = 1.0 / a.sqrt();
                data.extend_from_slice(&float_to_u16(rz * inv_len, 1.0).to_le_bytes());
                data.extend_from_slice(&float_to_u16(rw * inv_len, 1.0).to_le_bytes());
            }
        } else {
            // Flying - send full rotation
            data.extend_from_slice(&float_to_u16(rotation[0], 1.0).to_le_bytes());
            data.extend_from_slice(&float_to_u16(rotation[1], 1.0).to_le_bytes());
            data.extend_from_slice(&float_to_u16(rotation[2], 1.0).to_le_bytes());
            data.extend_from_slice(&float_to_u16(rotation[3], 1.0).to_le_bytes());
        }

        // AngularVelocity (6 bytes) - U16 encoded with range 64
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());
        data.extend_from_slice(&0x7fffu16.to_le_bytes());

        // TextureEntry size (2 bytes) - 0 for avatar (no texture entry)
        data.extend_from_slice(&0u16.to_le_bytes());

        static DUMP_COUNT: std::sync::atomic::AtomicUsize = std::sync::atomic::AtomicUsize::new(0);
        let count = DUMP_COUNT.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        if count < 5 {
            warn!(
                "[TERSE-FULL] Packet hex dump #{} ({} bytes) vel=({:.2},{:.2},{:.2}):",
                count + 1,
                data.len(),
                velocity[0],
                velocity[1],
                velocity[2]
            );
            for (i, chunk) in data.chunks(16).enumerate() {
                let hex: Vec<String> = chunk.iter().map(|b| format!("{:02x}", b)).collect();
                warn!("[TERSE-FULL]   {:04x}: {}", i * 16, hex.join(" "));
            }
        }

        self.send_message(IMPROVED_TERSE_OBJECT_UPDATE_ID, &data, dest, true, true)
            .await?;
        info!("[TERSE] Sent ImprovedTerseObjectUpdate for LocalID {} at ({:.2}, {:.2}, {:.2}) vel=({:.2},{:.2},{:.2}) to {}",
              local_id, position[0], position[1], position[2], velocity[0], velocity[1], velocity[2], dest);
        Ok(())
    }

    async fn send_sim_stats(&self, dest: SocketAddr) -> Result<()> {
        let mut data = Vec::with_capacity(400);

        data.extend_from_slice(&self.region_grid_x.to_le_bytes());
        data.extend_from_slice(&self.region_grid_y.to_le_bytes());
        data.extend_from_slice(&(Self::compute_region_flags() as u32).to_le_bytes());
        data.extend_from_slice(&15000u32.to_le_bytes());

        let stats: [(u32, f32); 21] = [
            (0, 45.0),
            (1, 44.0),
            (2, 0.022),
            (3, 0.001),
            (4, 0.001),
            (5, 0.001),
            (6, 0.001),
            (7, 0.0),
            (8, 0.0),
            (9, 0.0),
            (10, 0.0),
            (11, 0.0),
            (12, 0.0),
            (13, 100.0),
            (14, 0.0),
            (15, 0.0),
            (16, 0.0),
            (17, 0.0),
            (18, 0.0),
            (19, 0.0),
            (20, 0.0),
        ];

        data.push(stats.len() as u8);
        for (stat_id, stat_value) in &stats {
            data.extend_from_slice(&stat_id.to_le_bytes());
            data.extend_from_slice(&stat_value.to_le_bytes());
        }

        data.extend_from_slice(&1i32.to_le_bytes());

        data.push(0);

        self.send_message(SIM_STATS_ID, &data, dest, false, false)
            .await?;
        debug!("Sent SimStats to {}", dest);
        Ok(())
    }

    async fn send_terse_static(
        socket: &Arc<UdpSocket>,
        local_id: u32,
        position: [f32; 3],
        velocity: [f32; 3],
        rotation: [f32; 4],
        collision_plane: [f32; 4],
        is_flying: bool,
        dest: SocketAddr,
        reliability_mgr: &Arc<ReliabilityManager>,
        region_handle: u64,
    ) -> Result<()> {
        use super::zero_encoder::ZeroEncoder;

        fn float_to_u16(value: f32, range: f32) -> u16 {
            let clamped = value.clamp(-range, range);
            let normalized = (clamped + range) / (2.0 * range);
            (normalized * 65535.0) as u16
        }

        let mut body = Vec::with_capacity(76);
        body.extend_from_slice(&region_handle.to_le_bytes());
        body.extend_from_slice(&65535u16.to_le_bytes());

        body.push(1); // 1 object
        body.push(60); // 60 bytes data length (Variable 1)

        body.extend_from_slice(&local_id.to_le_bytes());
        body.push(0); // state
        body.push(1); // isAvatar

        body.extend_from_slice(&collision_plane[0].to_le_bytes());
        body.extend_from_slice(&collision_plane[1].to_le_bytes());
        body.extend_from_slice(&collision_plane[2].to_le_bytes());
        body.extend_from_slice(&collision_plane[3].to_le_bytes());

        body.extend_from_slice(&position[0].to_le_bytes());
        body.extend_from_slice(&position[1].to_le_bytes());
        body.extend_from_slice(&position[2].to_le_bytes());

        body.extend_from_slice(&float_to_u16(velocity[0], 128.0).to_le_bytes());
        body.extend_from_slice(&float_to_u16(velocity[1], 128.0).to_le_bytes());
        body.extend_from_slice(&float_to_u16(velocity[2], 128.0).to_le_bytes());

        body.extend_from_slice(&0x7fffu16.to_le_bytes()); // Accel X
        body.extend_from_slice(&0x7fffu16.to_le_bytes()); // Accel Y
        body.extend_from_slice(&0x7fffu16.to_le_bytes()); // Accel Z

        if !is_flying {
            body.extend_from_slice(&0x7fffu16.to_le_bytes()); // Rot X
            body.extend_from_slice(&0x7fffu16.to_le_bytes()); // Rot Y
            let rz = rotation[2];
            let rw = rotation[3];
            let a = rz * rz + rw * rw;
            if a.abs() < 1e-6 {
                body.extend_from_slice(&0x7fffu16.to_le_bytes());
                body.extend_from_slice(&0xffffu16.to_le_bytes());
            } else {
                let inv_len = 1.0 / a.sqrt();
                body.extend_from_slice(&float_to_u16(rz * inv_len, 1.0).to_le_bytes());
                body.extend_from_slice(&float_to_u16(rw * inv_len, 1.0).to_le_bytes());
            }
        } else {
            body.extend_from_slice(&float_to_u16(rotation[0], 1.0).to_le_bytes());
            body.extend_from_slice(&float_to_u16(rotation[1], 1.0).to_le_bytes());
            body.extend_from_slice(&float_to_u16(rotation[2], 1.0).to_le_bytes());
            body.extend_from_slice(&float_to_u16(rotation[3], 1.0).to_le_bytes());
        }

        body.extend_from_slice(&0x7fffu16.to_le_bytes()); // AngVel X
        body.extend_from_slice(&0x7fffu16.to_le_bytes()); // AngVel Y
        body.extend_from_slice(&0x7fffu16.to_le_bytes()); // AngVel Z

        body.extend_from_slice(&0u16.to_le_bytes()); // TextureEntry size = 0

        let sequence = reliability_mgr.next_sequence();
        let flags: u8 = FLAG_RELIABLE | FLAG_ZEROCODED;
        let mut packet = BytesMut::with_capacity(body.len() + 12);
        packet.put_u8(flags);
        packet.put_u32(sequence);
        packet.put_u8(0x00);

        let mut encoder = ZeroEncoder::new(body.len() + 2);
        encoder.add_byte(IMPROVED_TERSE_OBJECT_UPDATE_ID as u8); // High freq: 1 byte
        encoder.add_bytes(&body);
        let encoded = encoder.finish();
        packet.put_slice(&encoded);

        socket.send_to(&packet, dest).await?;
        Ok(())
    }

    async fn send_animation_static(
        socket: &Arc<UdpSocket>,
        agent_id: Uuid,
        anim_name: &str,
        seq: i32,
        dest: SocketAddr,
        reliability_mgr: &Arc<ReliabilityManager>,
    ) -> Result<()> {
        let anim_uuid_str = anim_name_to_uuid(anim_name);
        let anim_uuid =
            Uuid::parse_str(anim_uuid_str).unwrap_or_else(|_| Uuid::parse_str(ANIM_STAND).unwrap());

        let mut body = Vec::with_capacity(42);
        body.extend_from_slice(agent_id.as_bytes()); // AgentID (16)
        body.push(1); // AnimationList count
        body.extend_from_slice(anim_uuid.as_bytes()); // AnimID (16)
        body.extend_from_slice(&seq.to_le_bytes()); // SeqNum (4)
        body.push(0); // AnimationSourceList count
        body.push(0); // PhysicalAvatarEventList count

        let sequence = reliability_mgr.next_sequence();
        let mut packet = BytesMut::with_capacity(body.len() + 10);
        packet.put_u8(FLAG_RELIABLE); // reliable, not zerocoded
        packet.put_u32(sequence);
        packet.put_u8(0x00);
        packet.put_u8(AVATAR_ANIMATION_ID as u8); // High freq: 1 byte (0x14)
        packet.put_slice(&body);

        socket.send_to(&packet, dest).await?;
        info!(
            "[SCENE] Sent AvatarAnimation ({}) seq={} for agent {} to {}",
            anim_name, seq, agent_id, dest
        );
        Ok(())
    }

    async fn send_periodic_updates(socket: &Arc<UdpSocket>, dest: SocketAddr) -> Result<()> {
        let mut data = Vec::with_capacity(400);

        data.extend_from_slice(&1000u32.to_le_bytes());
        data.extend_from_slice(&1000u32.to_le_bytes());
        data.extend_from_slice(&(Self::compute_region_flags() as u32).to_le_bytes());
        data.extend_from_slice(&15000u32.to_le_bytes());

        let stats: [(u32, f32); 21] = [
            (0, 45.0),
            (1, 44.0),
            (2, 0.022),
            (3, 0.001),
            (4, 0.001),
            (5, 0.001),
            (6, 0.001),
            (7, 0.0),
            (8, 0.0),
            (9, 0.0),
            (10, 0.0),
            (11, 0.0),
            (12, 0.0),
            (13, 100.0),
            (14, 0.0),
            (15, 0.0),
            (16, 0.0),
            (17, 0.0),
            (18, 0.0),
            (19, 0.0),
            (20, 0.0),
        ];

        data.push(stats.len() as u8);
        for (stat_id, stat_value) in &stats {
            data.extend_from_slice(&stat_id.to_le_bytes());
            data.extend_from_slice(&stat_value.to_le_bytes());
        }

        data.extend_from_slice(&1i32.to_le_bytes());

        data.push(0);

        let mut packet = BytesMut::with_capacity(data.len() + 12);
        packet.put_u8(0x00); // flags
        packet.put_u32(0); // sequence number
        packet.put_u8(0x00); // extra header byte
                             // Low frequency message ID encoding: 0xFF 0xFF + 2-byte big-endian ID
        packet.put_u8(0xFF);
        packet.put_u8(0xFF);
        let low_bytes = (SIM_STATS_ID & 0xFFFF) as u16;
        packet.put_u8((low_bytes >> 8) as u8); // 0x00
        packet.put_u8((low_bytes & 0xFF) as u8); // 0x8C
        packet.put_slice(&data);

        socket.send_to(&packet, dest).await?;
        Ok(())
    }

    async fn send_periodic_coarse_location(
        socket: &Arc<UdpSocket>,
        dest: SocketAddr,
        agent_id: Uuid,
        x: f32,
        y: f32,
        z: f32,
    ) -> Result<()> {
        let mut update = CoarseLocationUpdate::new();
        update.add_avatar(agent_id, x, y, z, true);

        let serialized_data = update.serialize();

        let mut packet = BytesMut::with_capacity(serialized_data.len() + 10);
        packet.put_u8(0x00); // flags
        packet.put_u32(0); // sequence number
        packet.put_u8(0x00); // extra header byte
                             // Medium frequency message ID encoding: 0xFF + 1-byte ID
        packet.put_u8(0xFF);
        packet.put_u8((COARSE_LOCATION_UPDATE_ID & 0xFF) as u8); // 0x06
        packet.put_slice(&serialized_data);

        socket.send_to(&packet, dest).await?;
        Ok(())
    }

    async fn send_periodic_ping(
        socket: &Arc<UdpSocket>,
        dest: SocketAddr,
        ping_id: u8,
    ) -> Result<()> {
        let mut packet = BytesMut::with_capacity(12);
        packet.put_u8(0x00); // flags (not reliable)
        packet.put_u32(0); // sequence number (0 for pings, like C#)
        packet.put_u8(0x00); // extra header byte
        packet.put_u8(0x01); // High frequency message ID 1 = StartPingCheck
        packet.put_u8(ping_id);
        packet.put_u32_le(0); // oldest_unacked

        socket.send_to(&packet, dest).await?;
        Ok(())
    }

    async fn send_enable_simulator(&self, agent_id: Uuid, dest: SocketAddr) -> Result<()> {
        let mut data = BytesMut::with_capacity(50);

        data.put_u8(1);

        data.put_u32(0x7F000001u32.swap_bytes());
        data.put_u16_le(9000);
        data.put_u64_le(self.region_handle); // METER coords for region_handle

        const ENABLE_SIMULATOR_ID: u32 = 0xFFFF0000 | 151;
        self.send_message(ENABLE_SIMULATOR_ID, &data, dest, true, false)
            .await?;
        info!("[LOGIN] ✅ Sent EnableSimulator to {}", dest);
        Ok(())
    }

    async fn send_teleport_finish(
        &self,
        agent_id: Uuid,
        session_id: &str,
        dest: SocketAddr,
    ) -> Result<()> {
        let mut data = BytesMut::with_capacity(200);

        data.put_u8(1);

        data.put_slice(agent_id.as_bytes());
        data.put_u32_le(4);
        data.put_u32(0x7F000001u32.swap_bytes());
        data.put_u16_le(self.caps_port);
        data.put_u64_le(self.region_handle); // METER coords for region_handle

        let seed_cap = format!("http://127.0.0.1:{}/cap/{}", self.caps_port, session_id);
        data.put_u8(seed_cap.len() as u8);
        data.put_slice(seed_cap.as_bytes());

        data.put_u8(0x01);
        // Phase 73: TeleportFlags - ViaLogin = 1 << 7 = 128 (NOT 4160 which was ViaHome|ViaTelehub)
        data.put_u32_le(128); // TeleportFlags (ViaLogin = 128)

        const TELEPORT_FINISH_ID: u32 = 0xFFFF0045; // Low 69
        self.send_message(TELEPORT_FINISH_ID, &data, dest, true, false)
            .await?;
        info!(
            "[LOGIN] ✅ Sent TeleportFinish to {} with seed capability for session {}",
            dest, session_id
        );
        Ok(())
    }

    async fn send_ack(&self, sequence: u32, dest: SocketAddr) -> Result<()> {
        let mut buffer = BytesMut::with_capacity(15);

        // Standard PacketAck: non-reliable, use incrementing sequence
        buffer.put_u8(0x00);
        let ack_sequence = self.reliability_manager.next_sequence();
        buffer.put_u32(ack_sequence);
        buffer.put_u8(0x00);

        // Phase 62.5: CRITICAL FIX - PacketAck message ID must be 0xFFFFFFFB not 0xFFFF00FB!
        buffer.put_u8(0xFF);
        buffer.put_u8(0xFF);
        buffer.put_u8(0xFF); // Fixed: was 0x00, should be 0xFF
        buffer.put_u8(0xFB);

        buffer.put_u8(1);
        buffer.put_u32_le(sequence); // Phase 64.5: Little-endian for data fields

        // Phase 62.6: Log exact PacketAck bytes for protocol debugging
        let hex_dump: String = buffer
            .iter()
            .map(|b| format!("{:02x}", b))
            .collect::<Vec<_>>()
            .join(" ");
        debug!(
            "🔍 [Phase 62.6] PacketAck bytes ({}): {}",
            buffer.len(),
            hex_dump
        );

        self.socket.send_to(&buffer, dest).await?;

        // Phase 62.3: Log PacketAck at INFO level for protocol analysis
        debug!(
            "📤 UDP SEND: PacketAck (0xfffffffb) to {} [ack_seq={}, size={}]",
            dest,
            sequence,
            buffer.len()
        );
        debug!("Sent ACK for sequence {} to {}", sequence, dest);

        Ok(())
    }

    async fn handle_mute_list_request(&self, packet: &UdpPacket) -> Result<()> {
        debug!(
            "Received MuteListRequest from {}, seq={}",
            packet.source, packet.sequence
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 32 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let _mute_crc = if packet.data.len() >= 36 {
                u32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0; 4]))
            } else {
                0
            };

            let mut mute_data = String::new();
            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    if let Ok(rows) = sqlx::query(
                        r#"SELECT "MuteType", "MuteID", "MuteName", "MuteFlags" FROM "MuteList" WHERE "AgentID" = $1"#
                    ).bind(agent_id.to_string()).fetch_all(pool).await {
                        use sqlx::Row;
                        for row in &rows {
                            let mtype: i32 = row.try_get("MuteType").unwrap_or(0);
                            let mid: String = row.try_get("MuteID").unwrap_or_default();
                            let mname: String = row.try_get("MuteName").unwrap_or_default();
                            let mflags: i32 = row.try_get("MuteFlags").unwrap_or(0);
                            mute_data.push_str(&format!("{}|{}|{}|{}\n", mtype, mid, mname, mflags));
                        }
                        info!("[MUTE] Loaded {} mute entries for {}", rows.len(), agent_id);
                    }
                }
            }

            if mute_data.is_empty() {
                let mut response_data = Vec::with_capacity(16);
                response_data.extend_from_slice(agent_id.as_bytes());
                self.send_message(
                    USE_CACHED_MUTE_LIST_ID,
                    &response_data,
                    packet.source,
                    true,
                    false,
                )
                .await?;
            } else {
                let file_name = format!("{}.ml", agent_id);
                let file_data = mute_data.as_bytes();
                let xfer_id: u64 = rand::random();
                let mut header = Vec::with_capacity(32 + file_data.len());
                header.extend_from_slice(&xfer_id.to_le_bytes());
                header.put_u8(file_name.len() as u8);
                header.extend_from_slice(file_name.as_bytes());
                const XFER_ID: u32 = 0x0011; // Fixed 17 - SendXferPacket
                let chunk_size = 1000;
                let total_len = file_data.len() as u32;
                let mut pkt_num: u32 = 0;
                let mut offset = 0usize;
                while offset < file_data.len() || pkt_num == 0 {
                    let end = (offset + chunk_size).min(file_data.len());
                    let chunk = &file_data[offset..end];
                    let is_last = end >= file_data.len();
                    let mut xfer_data = Vec::with_capacity(12 + chunk.len());
                    xfer_data.extend_from_slice(&xfer_id.to_le_bytes());
                    let pkt_field = if is_last {
                        pkt_num | 0x80000000
                    } else {
                        pkt_num
                    };
                    xfer_data.extend_from_slice(&pkt_field.to_le_bytes());
                    if pkt_num == 0 {
                        xfer_data.extend_from_slice(&total_len.to_le_bytes());
                    }
                    xfer_data.extend_from_slice(chunk);
                    const SEND_XFER_PACKET_ID: u32 = 0x0011;
                    self.send_message(SEND_XFER_PACKET_ID, &xfer_data, packet.source, true, false)
                        .await?;
                    offset = end;
                    pkt_num += 1;
                    if is_last {
                        break;
                    }
                }
                info!(
                    "[MUTE] Sent mute list via Xfer ({} bytes, {} packets) to {}",
                    file_data.len(),
                    pkt_num,
                    agent_id
                );
            }
        }

        Ok(())
    }

    async fn handle_create_inventory_folder(&self, packet: &UdpPacket) -> Result<()> {
        info!(
            "[INVENTORY] CreateInventoryFolder from {}, seq={}",
            packet.source, packet.sequence
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 66 {
            let mut cursor = std::io::Cursor::new(&packet.data);

            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);

            let mut session_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut session_id_bytes);
            let _session_id = Uuid::from_bytes(session_id_bytes);

            let mut folder_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut folder_id_bytes);
            let folder_id = Uuid::from_bytes(folder_id_bytes);

            let mut parent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut parent_id_bytes);
            let parent_id = Uuid::from_bytes(parent_id_bytes);

            let folder_type = cursor.get_i8();

            let name_len = cursor.get_u8() as usize;
            let mut name_bytes = vec![0u8; name_len];
            if name_len > 0 && packet.data.len() >= 66 + name_len {
                cursor.copy_to_slice(&mut name_bytes);
            }
            let folder_name = String::from_utf8_lossy(&name_bytes).to_string();

            info!(
                "[INVENTORY] Creating folder: {} (type={}) id={} parent={} for agent={}",
                folder_name, folder_type, folder_id, parent_id, agent_id
            );

            if let Some(db) = &self.db_connection {
                use crate::database::multi_backend::DatabaseConnection;
                match db.as_ref() {
                    DatabaseConnection::PostgreSQL(pool) => {
                        let existing: Option<(uuid::Uuid,)> = sqlx::query_as(
                            r#"SELECT folderid FROM inventoryfolders
                               WHERE agentid = $1 AND parentfolderid = $2
                                 AND foldername = $3 AND type = $4
                               LIMIT 1"#,
                        )
                        .bind(agent_id)
                        .bind(parent_id)
                        .bind(&folder_name)
                        .bind(folder_type as i32)
                        .fetch_optional(pool)
                        .await
                        .unwrap_or(None);

                        if let Some((existing_id,)) = existing {
                            info!("[INVENTORY] Folder '{}' (type={}) already exists as {} under parent {} — skipping duplicate creation (viewer sent {})",
                                folder_name, folder_type, existing_id, parent_id, folder_id);
                        } else {
                            let result = sqlx::query(
                                r#"INSERT INTO inventoryfolders
                                   (folderid, agentid, parentfolderid, foldername, type, version)
                                   VALUES ($1, $2, $3, $4, $5, 1)
                                   ON CONFLICT (folderid) DO UPDATE SET
                                     foldername = EXCLUDED.foldername,
                                     type = EXCLUDED.type,
                                     parentfolderid = EXCLUDED.parentfolderid,
                                     version = inventoryfolders.version + 1"#,
                            )
                            .bind(folder_id)
                            .bind(agent_id)
                            .bind(parent_id)
                            .bind(&folder_name)
                            .bind(folder_type as i32)
                            .execute(pool)
                            .await;

                            match result {
                                Ok(_) => info!(
                                    "[INVENTORY] Created folder {} in PostgreSQL",
                                    folder_name
                                ),
                                Err(e) => warn!("[INVENTORY] Failed to create folder: {}", e),
                            }
                        }
                    }
                    DatabaseConnection::MySQL(pool) => {
                        let existing: Option<(String,)> = sqlx::query_as(
                            r#"SELECT folderID FROM inventoryfolders
                               WHERE agentID = ? AND parentFolderID = ?
                                 AND folderName = ? AND type = ?
                               LIMIT 1"#,
                        )
                        .bind(agent_id.to_string())
                        .bind(parent_id.to_string())
                        .bind(&folder_name)
                        .bind(folder_type as i32)
                        .fetch_optional(pool)
                        .await
                        .unwrap_or(None);

                        if let Some((existing_id,)) = existing {
                            info!("[INVENTORY] Folder '{}' (type={}) already exists as {} under parent {} — skipping duplicate creation (viewer sent {})",
                                folder_name, folder_type, existing_id, parent_id, folder_id);
                        } else {
                            let result = sqlx::query(
                                r#"INSERT INTO inventoryfolders
                                   (folderID, agentID, parentFolderID, folderName, type, version)
                                   VALUES (?, ?, ?, ?, ?, 1)
                                   ON DUPLICATE KEY UPDATE
                                     folderName = VALUES(folderName),
                                     type = VALUES(type),
                                     parentFolderID = VALUES(parentFolderID),
                                     version = version + 1"#,
                            )
                            .bind(folder_id.to_string())
                            .bind(agent_id.to_string())
                            .bind(parent_id.to_string())
                            .bind(&folder_name)
                            .bind(folder_type as i32)
                            .execute(pool)
                            .await;

                            match result {
                                Ok(_) => {
                                    info!("[INVENTORY] Created folder {} in MySQL", folder_name)
                                }
                                Err(e) => warn!("[INVENTORY] Failed to create folder: {}", e),
                            }
                        }
                    }
                }
            } else {
                debug!("[INVENTORY] No database connection - folder creation acknowledged but not persisted");
            }
        } else {
            warn!(
                "[INVENTORY] CreateInventoryFolder too short: {} bytes (need 66)",
                packet.data.len()
            );
        }

        Ok(())
    }

