    async fn handle_purge_inventory_descendents(&self, packet: &UdpPacket) -> Result<()> {
        info!(
            "[INVENTORY] PurgeInventoryDescendents from {} ({} bytes)",
            packet.source,
            packet.data.len()
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        // PurgeInventoryDescendents Low 285 format:
        // AgentData: AgentID (16) + SessionID (16) = 32 bytes
        // InventoryData: FolderID (16)
        if packet.data.len() >= 48 {
            let mut cursor = std::io::Cursor::new(&packet.data);

            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);

            let mut session_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut session_id_bytes);
            let _session_id = Uuid::from_bytes(session_id_bytes);

            let mut folder_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut folder_id_bytes);
            let folder_id = Uuid::from_bytes(folder_id_bytes);

            info!(
                "[INVENTORY] Purging descendents of folder {} for agent {}",
                folder_id, agent_id
            );

            let mut is_cof = false;
            if let Some(db) = &self.db_connection {
                use crate::database::multi_backend::DatabaseConnection;

                if let DatabaseConnection::PostgreSQL(pool) = db.as_ref() {
                    let folder_type: Option<(i32,)> =
                        sqlx::query_as("SELECT type FROM inventoryfolders WHERE folderid = $1")
                            .bind(folder_id)
                            .fetch_optional(pool)
                            .await
                            .ok()
                            .flatten();
                    is_cof = folder_type.map(|(t,)| t == 46).unwrap_or(false);
                }

                match db.as_ref() {
                    DatabaseConnection::PostgreSQL(pool) => {
                        let items_result =
                            sqlx::query("DELETE FROM inventoryitems WHERE parentfolderid = $1")
                                .bind(folder_id)
                                .execute(pool)
                                .await;
                        let folders_result =
                            sqlx::query("DELETE FROM inventoryfolders WHERE parentfolderid = $1")
                                .bind(folder_id)
                                .execute(pool)
                                .await;
                        match (items_result, folders_result) {
                            (Ok(i), Ok(f)) => info!(
                                "[INVENTORY] Purged {} items and {} folders",
                                i.rows_affected(),
                                f.rows_affected()
                            ),
                            (Err(e), _) | (_, Err(e)) => {
                                warn!("[INVENTORY] Failed to purge: {}", e)
                            }
                        }
                    }
                    DatabaseConnection::MySQL(pool) => {
                        let items_result =
                            sqlx::query("DELETE FROM inventoryitems WHERE parentFolderID = ?")
                                .bind(folder_id.to_string())
                                .execute(pool)
                                .await;
                        let folders_result =
                            sqlx::query("DELETE FROM inventoryfolders WHERE parentFolderID = ?")
                                .bind(folder_id.to_string())
                                .execute(pool)
                                .await;
                        match (items_result, folders_result) {
                            (Ok(i), Ok(f)) => info!(
                                "[INVENTORY] Purged {} items and {} folders in MySQL",
                                i.rows_affected(),
                                f.rows_affected()
                            ),
                            (Err(e), _) | (_, Err(e)) => {
                                warn!("[INVENTORY] Failed to purge: {}", e)
                            }
                        }
                    }
                }
            }

            if is_cof {
                info!(
                    "[COF] COF was purged - repopulating from avatars table for agent {}",
                    agent_id
                );
                if let Some(db) = &self.db_connection {
                    if let Some(pool) = db.postgres_pool() {
                        let rows: Vec<(String, String)> = sqlx::query_as(
                            "SELECT name, value FROM avatars WHERE principalid = $1::uuid AND name LIKE 'Wearable %'"
                        )
                        .bind(agent_id.to_string())
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();

                        let mut wearables = Vec::new();
                        for (name, value) in &rows {
                            if let Some(wearable_type) = name.strip_prefix("Wearable ") {
                                let wtype: u8 = wearable_type.parse().unwrap_or(0);
                                let parts: Vec<&str> = value.split(':').collect();
                                if parts.len() == 2 {
                                    if let (Ok(item_id), Ok(asset_id)) =
                                        (Uuid::parse_str(parts[0]), Uuid::parse_str(parts[1]))
                                    {
                                        wearables.push(crate::udp::messages::WearableEntry {
                                            item_id,
                                            asset_id,
                                            wearable_type: wtype,
                                        });
                                    }
                                }
                            }
                        }

                        if !wearables.is_empty() {
                            Self::ensure_cof_populated(agent_id, &wearables, &self.db_connection)
                                .await;
                        } else {
                            warn!("[COF] No wearable data in avatars table for agent {} - COF will remain empty", agent_id);
                        }
                    }
                }
            }
        } else {
            warn!(
                "[INVENTORY] PurgeInventoryDescendents too short: {} bytes",
                packet.data.len()
            );
        }

        Ok(())
    }

    async fn handle_money_balance_request(&self, packet: &UdpPacket) -> Result<()> {
        debug!(
            "Received MoneyBalanceRequest from {}, seq={}",
            packet.source, packet.sequence
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 32 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);

            let mut transaction_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut transaction_id_bytes);
            let transaction_id = Uuid::from_bytes(transaction_id_bytes);

            let mut balance: i32 = 0;
            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    match sqlx::query_scalar::<_, i64>("SELECT COALESCE(balance, 0) FROM currency_balances WHERE user_id = $1 AND currency_code = 'LS'")
                        .bind(agent_id)
                        .fetch_optional(pool).await
                    {
                        Ok(Some(b)) => { balance = b as i32; }
                        Ok(None) => {
                            sqlx::query("INSERT INTO currency_balances (user_id, currency_code, balance, reserved, available, version) VALUES ($1, 'LS', 1000, 0, 1000, 1) ON CONFLICT DO NOTHING")
                                .bind(agent_id)
                                .execute(pool).await.ok();
                            balance = 1000;
                        }
                        Err(e) => { warn!("[ECONOMY] DB query failed: {}", e); balance = 0; }
                    }
                }
            }

            let mut response_data = Vec::with_capacity(100);
            response_data.extend_from_slice(agent_id.as_bytes());
            response_data.extend_from_slice(transaction_id.as_bytes());
            response_data.push(1);
            response_data.extend_from_slice(&balance.to_le_bytes());
            response_data.extend_from_slice(&0i32.to_le_bytes());
            response_data.extend_from_slice(&0i32.to_le_bytes());
            response_data.push(0);

            response_data.extend_from_slice(&0i32.to_le_bytes());
            response_data.extend_from_slice(Uuid::nil().as_bytes());
            response_data.push(0);
            response_data.extend_from_slice(Uuid::nil().as_bytes());
            response_data.push(0);
            response_data.extend_from_slice(&0i32.to_le_bytes());
            response_data.push(0);

            info!(
                "[ECONOMY] MoneyBalanceReply: agent={}, balance={}L$",
                agent_id, balance
            );
            self.send_message(
                MONEY_BALANCE_REPLY_ID,
                &response_data,
                packet.source,
                true,
                true,
            )
            .await?;
        }

        Ok(())
    }

    async fn handle_agent_data_update_request(&self, packet: &UdpPacket) -> Result<()> {
        debug!(
            "Received AgentDataUpdateRequest from {}, seq={}",
            packet.source, packet.sequence
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
            debug!(
                "Sent ACK for AgentDataUpdateRequest seq={}",
                packet.sequence
            );
        }

        if packet.data.len() >= 32 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);

            // Phase 79.12: Get actual user name from session instead of hardcoded values
            let (first_name, last_name) =
                if let Some(session) = self.session_manager.get_session_by_agent_id(agent_id) {
                    (session.first_name.clone(), session.last_name.clone())
                } else {
                    // Fallback if session not found
                    warn!(
                        "[AGENT DATA] No session found for agent {}, using fallback name",
                        agent_id
                    );
                    ("Unknown".to_string(), "User".to_string())
                };
            let group_title = "";
            let group_name = "";

            let mut response_data = Vec::with_capacity(100);
            response_data.extend_from_slice(agent_id.as_bytes());
            response_data.push(first_name.len() as u8);
            response_data.extend_from_slice(first_name.as_bytes());
            response_data.push(last_name.len() as u8);
            response_data.extend_from_slice(last_name.as_bytes());
            response_data.push(group_title.len() as u8);
            response_data.extend_from_slice(group_title.as_bytes());
            response_data.extend_from_slice(Uuid::nil().as_bytes());
            response_data.extend_from_slice(&0u64.to_le_bytes());
            response_data.push(group_name.len() as u8);
            response_data.extend_from_slice(group_name.as_bytes());

            self.send_message(
                AGENT_DATA_UPDATE_ID,
                &response_data,
                packet.source,
                true,
                true,
            )
            .await?;
            info!(
                "[AGENT DATA] Sent AgentDataUpdate to {} with name '{} {}'",
                packet.source, first_name, last_name
            );

            self.send_agent_group_data_update(agent_id, packet.source)
                .await?;
        } else {
            debug!(
                "AgentDataUpdateRequest too short: {} bytes",
                packet.data.len()
            );
        }

        Ok(())
    }

    async fn send_agent_group_data_update(&self, agent_id: Uuid, dest: SocketAddr) -> Result<()> {
        const AGENT_GROUP_DATA_UPDATE_ID: u32 = 0xFFFF0185; // Low 389

        let mut data = BytesMut::with_capacity(200);
        data.put_slice(agent_id.as_bytes()); // AgentData.AgentID

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let rows = sqlx::query(
                    "SELECT g.GroupID, g.Name, g.InsigniaID, m.SelectedRoleID, m.Contribution, m.AcceptNotices \
                     FROM os_groups_membership m \
                     JOIN os_groups_groups g ON g.GroupID = m.GroupID \
                     WHERE m.AgentID = $1"
                )
                .bind(agent_id.to_string())
                .fetch_all(pool)
                .await
                .unwrap_or_default();

                let count = rows.len().min(255);
                data.put_u8(count as u8);

                for row in rows.iter().take(255) {
                    let gid_str: String = sqlx::Row::get(&*row, "groupid");
                    let gid = Uuid::parse_str(&gid_str).unwrap_or(Uuid::nil());
                    let group_name: String = sqlx::Row::get(&*row, "name");
                    let insignia_str: String = sqlx::Row::get(&*row, "insigniaid");
                    let insignia = Uuid::parse_str(&insignia_str).unwrap_or(Uuid::nil());
                    let contribution: i32 = sqlx::Row::get(&*row, "contribution");
                    let accept_notices: i32 = sqlx::Row::get(&*row, "acceptnotices");

                    data.put_slice(gid.as_bytes()); // GroupID
                    data.put_u64_le(0); // GroupPowers
                    data.put_u8(if accept_notices != 0 { 1 } else { 0 }); // AcceptNotices
                    data.put_slice(insignia.as_bytes()); // GroupInsigniaID
                    data.put_i32_le(contribution); // Contribution
                    let name_bytes = group_name.as_bytes();
                    data.put_u8(name_bytes.len().min(255) as u8);
                    data.put_slice(&name_bytes[..name_bytes.len().min(255)]); // GroupName
                }

                if count > 0 {
                    info!(
                        "[GROUPS] Sent AgentGroupDataUpdate to {} with {} group(s)",
                        dest, count
                    );
                }

                return self
                    .send_message(AGENT_GROUP_DATA_UPDATE_ID, &data, dest, true, true)
                    .await;
            }
        }

        data.put_u8(0); // 0 groups
        self.send_message(AGENT_GROUP_DATA_UPDATE_ID, &data, dest, true, true)
            .await
    }

    async fn handle_request_region_info(&self, packet: &UdpPacket) -> Result<()> {
        info!(
            "[REGION] Received RequestRegionInfo from {}, seq={}",
            packet.source, packet.sequence
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        // Parse RequestRegionInfo to get agent_id and session_id
        // Format: AgentData { AgentID: UUID, SessionID: UUID }
        if packet.data.len() >= 32 {
            let agent_id = Uuid::from_slice(&packet.data[0..16]).unwrap_or_default();
            let session_id = Uuid::from_slice(&packet.data[16..32]).unwrap_or_default();

            // Use the proper send_region_info which includes all required blocks
            self.send_region_info(agent_id, session_id, packet.source)
                .await?;
            info!(
                "[REGION] Sent complete RegionInfo response to {}",
                packet.source
            );
        } else {
            warn!(
                "[REGION] RequestRegionInfo packet too short: {} bytes",
                packet.data.len()
            );
        }

        Ok(())
    }

    async fn handle_transfer_request(&self, packet: &UdpPacket) -> Result<()> {
        info!(
            "[TRANSFER] Received TransferRequest from {}, seq={}",
            packet.source, packet.sequence
        );

        // Send ACK if reliable
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        // Parse TransferRequest
        let request = match TransferRequest::parse(&packet.data) {
            Ok(req) => req,
            Err(e) => {
                warn!("[TRANSFER] Failed to parse TransferRequest: {}", e);
                return Ok(());
            }
        };

        info!(
            "[TRANSFER] Request: transfer_id={}, channel={}, source={}, priority={}",
            request.transfer_id, request.channel_type, request.source_type, request.priority
        );

        // Handle different source types
        match request.source_type {
            2 => {
                // SourceType 2 = Asset transfer
                self.handle_asset_transfer_request(&request, packet.source)
                    .await?;
            }
            3 => {
                // SourceType 3 = Sim inventory item (object inventory)
                self.handle_sim_inventory_transfer_request(&request, packet.source)
                    .await?;
            }
            _ => {
                warn!("[TRANSFER] Unknown SourceType: {}", request.source_type);
                self.send_transfer_abort(&request.transfer_id, request.channel_type, packet.source)
                    .await?;
            }
        }

        Ok(())
    }

    async fn handle_asset_transfer_request(
        &self,
        request: &TransferRequest,
        dest: SocketAddr,
    ) -> Result<()> {
        use crate::opensim_compatibility::avatar_data::get_body_part_data_by_uuid;
        use crate::opensim_compatibility::library_assets::get_global_library_manager;

        let asset_id = match request.get_asset_id() {
            Some(id) => id,
            None => {
                warn!("[TRANSFER] Could not extract asset ID from request params");
                self.send_transfer_abort(&request.transfer_id, request.channel_type, dest)
                    .await?;
                return Ok(());
            }
        };

        let asset_type = request.get_asset_type().unwrap_or(-1);

        info!(
            "[TRANSFER] Asset request: asset_id={}, type={}",
            asset_id, asset_type
        );

        let mut asset_data: Option<Vec<u8>> = None;

        if let Some(db_connection) = &self.db_connection {
            asset_data = self.query_asset_data(db_connection, &asset_id).await;
            if asset_data.is_some() {
                info!("[TRANSFER] Found asset {} in database", asset_id);
            }
        }

        if asset_data.is_none() {
            if let Some(library_manager) = get_global_library_manager() {
                let manager = library_manager.read().await;
                if let Some(data) = manager.get_asset_data(&asset_id) {
                    info!(
                        "[TRANSFER] Found asset {} in library assets: {} bytes",
                        asset_id,
                        data.len()
                    );
                    asset_data = Some(data);
                }
            }
        }

        if asset_data.is_none() {
            if let Some(data) = get_body_part_data_by_uuid(&asset_id).await {
                info!(
                    "[TRANSFER] Found asset {} in body parts: {} bytes",
                    asset_id,
                    data.len()
                );
                asset_data = Some(data);
            }
        }

        let asset_data = match asset_data {
            Some(data) => {
                info!(
                    "[TRANSFER] Serving asset {} ({} bytes)",
                    asset_id,
                    data.len()
                );
                data
            }
            None => {
                info!(
                    "[TRANSFER] Asset {} not found in any source, sending abort",
                    asset_id
                );
                self.send_transfer_abort(&request.transfer_id, request.channel_type, dest)
                    .await?;
                return Ok(());
            }
        };

        // Send TransferInfo with original request params (viewer needs them to identify the asset)
        let mut transfer_info =
            TransferInfo::new_asset_ok(request.transfer_id, asset_data.len() as i32);
        transfer_info.params = request.params.clone();

        info!(
            "[TRANSFER] Sending TransferInfo: size={} bytes, params={} bytes",
            asset_data.len(),
            transfer_info.params.len()
        );

        self.send_message(
            TRANSFER_INFO_ID,
            &transfer_info.serialize(),
            dest,
            true,
            true, // TransferInfo is zerocoded
        )
        .await?;

        // Send TransferPacket(s)
        let packet_builder = TransferPacketBuilder::new(request.transfer_id, request.channel_type)
            .with_chunk_size(1000); // Safe chunk size for UDP

        let packets = packet_builder.build_packets(&asset_data);

        info!(
            "[TRANSFER] Sending {} TransferPacket(s) for asset {}",
            packets.len(),
            asset_id
        );

        for (idx, transfer_packet) in packets.iter().enumerate() {
            self.send_message(
                TRANSFER_PACKET_ID,
                &transfer_packet.serialize(),
                dest,
                false, // TransferPackets are unreliable (High frequency)
                false,
            )
            .await?;

            debug!(
                "[TRANSFER] Sent packet {}/{}: {} bytes, status={:?}",
                idx + 1,
                packets.len(),
                transfer_packet.data.len(),
                transfer_packet.status
            );
        }

        info!("[TRANSFER] Asset transfer complete for {}", asset_id);

        Ok(())
    }

    async fn handle_sim_inventory_transfer_request(
        &self,
        request: &TransferRequest,
        dest: SocketAddr,
    ) -> Result<()> {
        // C# OpenSim extracts asset_id from params offset 80 (not via JOIN)
        // Params layout: AgentID(0-15) SessionID(16-31) OwnerID(32-47) TaskID(48-63) ItemID(64-79) AssetID(80-95) AssetType(96-99)
        let asset_id = if request.params.len() >= 96 {
            let mut bytes = [0u8; 16];
            bytes.copy_from_slice(&request.params[80..96]);
            Uuid::from_bytes(bytes)
        } else {
            warn!(
                "[TRANSFER] SimInventoryItem params too short: {} bytes (need 96)",
                request.params.len()
            );
            self.send_transfer_abort(&request.transfer_id, request.channel_type, dest)
                .await?;
            return Ok(());
        };

        let item_id = if request.params.len() >= 80 {
            let mut bytes = [0u8; 16];
            bytes.copy_from_slice(&request.params[64..80]);
            Uuid::from_bytes(bytes)
        } else {
            Uuid::nil()
        };

        info!(
            "[TRANSFER] Sim inventory request: item={}, asset_from_viewer={}",
            item_id, asset_id
        );

        let resolved_asset_id = if !item_id.is_nil() {
            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    let row: Option<(Uuid,)> =
                        sqlx::query_as("SELECT assetid FROM primitems WHERE itemid = $1")
                            .bind(item_id)
                            .fetch_optional(pool)
                            .await
                            .ok()
                            .flatten();
                    if let Some((db_asset_id,)) = row {
                        if db_asset_id != asset_id {
                            info!(
                                "[TRANSFER] primitems has newer asset {} (viewer sent {})",
                                db_asset_id, asset_id
                            );
                        }
                        db_asset_id
                    } else {
                        asset_id
                    }
                } else {
                    asset_id
                }
            } else {
                asset_id
            }
        } else {
            asset_id
        };

        let asset_data = if let Some(db_connection) = &self.db_connection {
            self.query_asset_data(db_connection, &resolved_asset_id)
                .await
        } else {
            warn!("[TRANSFER] No database connection available");
            None
        };

        match asset_data {
            Some(data) => {
                let mut transfer_info =
                    TransferInfo::new_asset_ok(request.transfer_id, data.len() as i32);
                transfer_info.params = request.params.clone();

                info!(
                    "[TRANSFER] Sending sim inventory TransferInfo: size={} bytes, params={} bytes",
                    data.len(),
                    transfer_info.params.len()
                );

                self.send_message(
                    TRANSFER_INFO_ID,
                    &transfer_info.serialize(),
                    dest,
                    true,
                    true,
                )
                .await?;

                let packet_builder =
                    TransferPacketBuilder::new(request.transfer_id, request.channel_type)
                        .with_chunk_size(1000);

                let packets = packet_builder.build_packets(&data);

                info!(
                    "[TRANSFER] Sending {} sim inventory TransferPacket(s)",
                    packets.len()
                );

                for (idx, transfer_packet) in packets.iter().enumerate() {
                    self.send_message(
                        TRANSFER_PACKET_ID,
                        &transfer_packet.serialize(),
                        dest,
                        false,
                        false,
                    )
                    .await?;

                    debug!(
                        "[TRANSFER] Sent sim inventory packet {}/{}: {} bytes",
                        idx + 1,
                        packets.len(),
                        transfer_packet.data.len()
                    );
                }

                info!(
                    "[TRANSFER] Sim inventory transfer complete for asset {}",
                    asset_id
                );
            }
            None => {
                warn!(
                    "[TRANSFER] Sim inventory asset not found: item={}, asset={}",
                    item_id, asset_id
                );
                self.send_transfer_abort(&request.transfer_id, request.channel_type, dest)
                    .await?;
            }
        }

        Ok(())
    }

    async fn query_asset_data(
        &self,
        db_connection: &DatabaseConnection,
        asset_id: &Uuid,
    ) -> Option<Vec<u8>> {
        use crate::database::multi_backend::DatabaseConnection;

        match db_connection {
            DatabaseConnection::PostgreSQL(pool) => {
                let result: Result<Option<Vec<u8>>, sqlx::Error> =
                    sqlx::query_scalar("SELECT data FROM assets WHERE id = $1")
                        .bind(asset_id)
                        .fetch_optional(pool)
                        .await;

                match result {
                    Ok(Some(data)) if !data.is_empty() => {
                        debug!(
                            "[TRANSFER] PostgreSQL asset found: {} ({} bytes)",
                            asset_id,
                            data.len()
                        );
                        Some(data)
                    }
                    Ok(_) => {
                        debug!("[TRANSFER] Asset not found in PostgreSQL: {}", asset_id);
                        None
                    }
                    Err(e) => {
                        warn!(
                            "[TRANSFER] PostgreSQL query error for asset {}: {}",
                            asset_id, e
                        );
                        None
                    }
                }
            }
            DatabaseConnection::MySQL(pool) => {
                let result: Result<Option<Vec<u8>>, sqlx::Error> =
                    sqlx::query_scalar("SELECT data FROM assets WHERE id = ?")
                        .bind(asset_id.to_string())
                        .fetch_optional(pool)
                        .await;

                match result {
                    Ok(Some(data)) if !data.is_empty() => {
                        debug!(
                            "[TRANSFER] MySQL asset found: {} ({} bytes)",
                            asset_id,
                            data.len()
                        );
                        Some(data)
                    }
                    Ok(_) => {
                        debug!("[TRANSFER] Asset not found in MySQL: {}", asset_id);
                        None
                    }
                    Err(e) => {
                        warn!("[TRANSFER] MySQL query error for asset {}: {}", asset_id, e);
                        None
                    }
                }
            }
        }
    }

    async fn query_sim_inventory_asset(
        &self,
        db_connection: &DatabaseConnection,
        params: &crate::udp::messages::transfer_request::SimInventoryParams,
    ) -> Option<Vec<u8>> {
        use crate::database::multi_backend::DatabaseConnection;

        match db_connection {
            DatabaseConnection::PostgreSQL(pool) => {
                let result: Result<Option<(Vec<u8>,)>, sqlx::Error> = sqlx::query_as(
                    "SELECT a.data FROM inventoryitems i \
                     JOIN assets a ON i.assetid = a.id \
                     WHERE i.inventoryid = $1 AND i.avatarid = $2",
                )
                .bind(params.item_id)
                .bind(params.owner_id)
                .fetch_optional(pool)
                .await;

                match result {
                    Ok(Some((data,))) => {
                        info!("[TRANSFER] Found sim inventory asset: {} bytes", data.len());
                        return Some(data);
                    }
                    Ok(None) => {
                        let alt_result: Result<Option<Vec<u8>>, sqlx::Error> = sqlx::query_scalar(
                            "SELECT a.data FROM inventoryitems i \
                             JOIN assets a ON i.assetid = a.id \
                             WHERE i.inventoryid = $1",
                        )
                        .bind(params.item_id)
                        .fetch_optional(pool)
                        .await;

                        if let Ok(Some(data)) = alt_result {
                            info!(
                                "[TRANSFER] Found asset by item ID (no owner check): {} bytes",
                                data.len()
                            );
                            return Some(data);
                        }
                    }
                    Err(e) => {
                        warn!("[TRANSFER] Database error for sim inventory: {}", e);
                    }
                }
                None
            }
            DatabaseConnection::MySQL(pool) => {
                let result: Result<Option<(Vec<u8>, i32)>, sqlx::Error> = sqlx::query_as(
                    "SELECT a.data, i.asset_type FROM inventoryitems i
                     JOIN assets a ON i.asset_id = a.id
                     WHERE i.inventory_id = ? AND i.avatar_id = ?",
                )
                .bind(params.item_id.to_string())
                .bind(params.owner_id.to_string())
                .fetch_optional(pool)
                .await;

                match result {
                    Ok(Some((data, _asset_type))) => {
                        info!("[TRANSFER] Found sim inventory asset: {} bytes", data.len());
                        return Some(data);
                    }
                    Ok(None) => {
                        let alt_result: Result<Option<Vec<u8>>, sqlx::Error> =
                            sqlx::query_scalar("SELECT data FROM assets WHERE id = ?")
                                .bind(params.item_id.to_string())
                                .fetch_optional(pool)
                                .await;

                        if let Ok(Some(data)) = alt_result {
                            info!("[TRANSFER] Found asset by item ID: {} bytes", data.len());
                            return Some(data);
                        }
                    }
                    Err(e) => {
                        warn!("[TRANSFER] Database error for sim inventory: {}", e);
                    }
                }
                None
            }
        }
    }

