    async fn handle_agent_animation(&self, packet: &UdpPacket) -> Result<()> {
        let message = AgentAnimationMessage::parse(&packet.data)?;

        for anim in &message.animation_list {
            info!(
                "🎭 [ANIMATION] AgentAnimation from {}: agent={}, anim_id={}, start={}",
                packet.source, message.agent_id, anim.anim_id, anim.start_anim
            );
        }

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        let animations_to_start: Vec<Uuid> = message
            .animation_list
            .iter()
            .filter(|a| a.start_anim)
            .map(|a| a.anim_id)
            .collect();

        if animations_to_start.is_empty() {
            info!(
                "🎭 [ANIMATION] Stop-only request for agent {} — not overriding movement animation",
                message.agent_id
            );
            return Ok(());
        }

        let current_movement_anim = {
            let states = self.avatar_states.read();
            states
                .get(&message.agent_id)
                .map(|s| (s.current_animation, s.animation_sequence))
                .unwrap_or((ANIM_NAME_STAND, 1))
        };

        let movement_uuid_str = anim_name_to_uuid(current_movement_anim.0);
        let movement_uuid = Uuid::parse_str(movement_uuid_str)
            .unwrap_or_else(|_| Uuid::parse_str(ANIM_STAND).unwrap());

        let mut response_anims = Vec::with_capacity(animations_to_start.len() + 1);
        response_anims.push(movement_uuid);
        for anim_id in &animations_to_start {
            if *anim_id != movement_uuid {
                response_anims.push(*anim_id);
            }
        }

        info!(
            "🎭 [ANIMATION] Confirming {} animation(s) for agent {} (movement={}, seq={})",
            response_anims.len(),
            message.agent_id,
            current_movement_anim.0,
            current_movement_anim.1
        );

        let clients: Vec<SocketAddr> = {
            let states = self.avatar_states.read();
            states.values().map(|s| s.client_addr).collect()
        };
        for addr in clients {
            let _ = self
                .send_avatar_animation_response(message.agent_id, &response_anims, addr)
                .await;
        }

        Ok(())
    }

    async fn send_avatar_animation_response(
        &self,
        agent_id: Uuid,
        animations: &[Uuid],
        dest: SocketAddr,
    ) -> Result<()> {
        let base_seq = {
            let states = self.avatar_states.read();
            states
                .get(&agent_id)
                .map(|s| s.animation_sequence)
                .unwrap_or(1)
        };

        let mut data = Vec::with_capacity(100);

        data.extend_from_slice(agent_id.as_bytes());
        data.push(animations.len() as u8);

        for (i, anim_id) in animations.iter().enumerate() {
            data.extend_from_slice(anim_id.as_bytes());
            data.extend_from_slice(&(base_seq + i as i32).to_le_bytes());
        }

        data.push(0);
        data.push(0);

        self.send_message(AVATAR_ANIMATION_ID, &data, dest, true, false)
            .await?;
        Ok(())
    }

