    async fn handle_viewer_effect(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 16 {
            let agent_id = Uuid::from_slice(&packet.data[0..16]).unwrap_or(Uuid::nil());
            if !agent_id.is_nil() {
                match self.spam_protection.check_viewer_effect(agent_id) {
                    super::spam_protection::SpamAction::Allow => {}
                    _ => {
                        return Ok(());
                    }
                }
            }
        }

        let clients: Vec<SocketAddr> = {
            let states = self.avatar_states.read();
            states
                .values()
                .filter(|s| !s.is_npc && s.client_addr != packet.source)
                .map(|s| s.client_addr)
                .collect()
        };

        for addr in clients {
            let _ = self
                .send_message(VIEWER_EFFECT_ID, &packet.data, addr, true, false)
                .await;
        }

        Ok(())
    }

    async fn handle_uuid_name_request(&self, packet: &UdpPacket) -> Result<()> {
        let message = UUIDNameRequestMessage::parse(&packet.data)?;

        info!(
            "UUIDNameRequest from {}: {} IDs requested",
            packet.source,
            message.ids.len()
        );

        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        let mut reply = UUIDNameReplyMessage::new();

        for id in &message.ids {
            let name_from_state: Option<(String, String)> = {
                if let Some(session) = self.session_manager.get_session_by_agent_id(*id) {
                    Some((session.first_name.clone(), session.last_name.clone()))
                } else if *id == crate::ai::galadriel::GALADRIEL_AGENT_ID {
                    Some(("Galadriel".to_string(), "AI".to_string()))
                } else {
                    let states = self.avatar_states.read();
                    if let Some(state) = states.get(id) {
                        if state.is_npc {
                            if let Some(ref npc_name) = state.npc_name {
                                let parts: Vec<&str> = npc_name.splitn(2, ' ').collect();
                                Some((
                                    parts[0].to_string(),
                                    parts.get(1).unwrap_or(&"Resident").to_string(),
                                ))
                            } else {
                                Some(("AI".to_string(), "NPC".to_string()))
                            }
                        } else {
                            None
                        }
                    } else {
                        None
                    }
                }
            };

            let (first_name, last_name) = match name_from_state {
                Some(names) => names,
                None => self.lookup_user_name(*id).await,
            };

            reply.add_entry(*id, first_name.clone(), last_name.clone());
            debug!("UUIDNameReply: {} -> {} {}", id, first_name, last_name);
        }

        if !reply.entries.is_empty() {
            self.send_message(
                UUID_NAME_REPLY_ID,
                &reply.serialize(),
                packet.source,
                true,
                false,
            )
            .await?;
            info!(
                "Sent UUIDNameReply with {} entries to {}",
                reply.entries.len(),
                packet.source
            );
        }

        Ok(())
    }

    async fn lookup_user_name(&self, user_id: Uuid) -> (String, String) {
        if let Some(db) = &self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                if let Ok(Some(row)) = sqlx::query_as::<_, (String, String)>(
                    "SELECT firstname, lastname FROM useraccount WHERE principalid = $1",
                )
                .bind(user_id)
                .fetch_optional(pool)
                .await
                {
                    return row;
                }
            }
        }
        ("Unknown".to_string(), "Avatar".to_string())
    }

