                        xml.push_str(&format!("{}<LinkNum>{}</LinkNum>\n", i2, link_number));

                        let click_action: i32 = if is_root {
                            0
                        } else {
                            row.try_get("clickaction").unwrap_or(0)
                        };
                        xml.push_str(&format!(
                            "{}<ClickAction>{}</ClickAction>\n",
                            i2, click_action
                        ));

                        xml.push_str(&format!("{}<Shape>\n", i2));
                        let si = format!("{}  ", i2);
                        let profile_curve: i32 = row.try_get("profilecurve").unwrap_or(1);
