    async fn handle_object_material(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 37 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            cursor.advance(16); // session_id

            let object_count = if cursor.remaining() >= 1 {
                cursor.get_u8()
            } else {
                0
            };
            for _ in 0..object_count {
                if cursor.remaining() < 5 {
                    break;
                }
                let local_id = cursor.get_u32_le();
                let material = cursor.get_u8();
                let mut objects = self.scene_objects.write();
                if let Some(obj) = objects.get_mut(&local_id) {
                    info!("[OBJECT] Set material for {} to {}", local_id, material);
                    obj.material = material;
                }
            }
        }
        Ok(())
    }

    async fn handle_object_flag_update(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 40 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            cursor.advance(16); // session_id

            if cursor.remaining() >= 8 {
                let local_id = cursor.get_u32_le();
                let use_physics = cursor.get_u8() != 0;
                let is_temporary = cursor.get_u8() != 0;
                let is_phantom = cursor.get_u8() != 0;
                let _cast_shadows = cursor.get_u8(); // deprecated

                let mut objects = self.scene_objects.write();
                if let Some(obj) = objects.get_mut(&local_id) {
                    info!(
                        "[OBJECT] Flags for {}: physics={} temp={} phantom={}",
                        local_id, use_physics, is_temporary, is_phantom
                    );
                    obj.flags = 0;
                    if use_physics {
                        obj.flags |= 0x01;
                    }
                    if is_temporary {
                        obj.flags |= 0x04;
                    }
                    if is_phantom {
                        obj.flags |= 0x08;
                    }
                }
            }
        }
        Ok(())
    }

