    async fn send_group_profile_reply(
        &self,
        agent_id: Uuid,
        group_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        const GROUP_PROFILE_REPLY_ID: u32 = 0xFFFF0160; // Low 352

        let mut name = "Unknown Group".to_string();
        let mut charter = String::new();
        let mut show_in_list = true;
        let mut insignia_id = Uuid::nil();
        let mut founder_id = Uuid::nil();
        let mut membership_fee = 0i32;
        let mut open_enrollment = true;
        let mut member_count = 0i32;
        let mut role_count = 1i32;
        let mut owner_role = Uuid::nil();

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                if let Ok(row) = sqlx::query(
                    "SELECT Name, Charter, InsigniaID, FounderID, MembershipFee, \
                     OpenEnrollment, ShowInList, OwnerRoleID \
                     FROM os_groups_groups WHERE GroupID = $1",
                )
                .bind(group_id.to_string())
                .fetch_one(pool)
                .await
                {
                    name = sqlx::Row::get(&row, "name");
                    charter = sqlx::Row::get::<String, _>(&row, "charter");
                    let insignia_str: String = sqlx::Row::get(&row, "insigniaid");
                    insignia_id = Uuid::parse_str(&insignia_str).unwrap_or(Uuid::nil());
                    let founder_str: String = sqlx::Row::get(&row, "founderid");
                    founder_id = Uuid::parse_str(&founder_str).unwrap_or(Uuid::nil());
                    membership_fee = sqlx::Row::get(&row, "membershipfee");
                    let open: i32 = sqlx::Row::get(&row, "openenrollment");
                    open_enrollment = open != 0;
                    let show: i32 = sqlx::Row::get(&row, "showinlist");
                    show_in_list = show != 0;
                    let owner_str: String = sqlx::Row::get(&row, "ownerroleid");
                    owner_role = Uuid::parse_str(&owner_str).unwrap_or(Uuid::nil());
                }

                member_count = sqlx::query_scalar::<_, i64>(
                    "SELECT COUNT(*) FROM os_groups_membership WHERE GroupID = $1",
                )
                .bind(group_id.to_string())
                .fetch_one(pool)
                .await
                .unwrap_or(0) as i32;

                role_count = sqlx::query_scalar::<_, i64>(
                    "SELECT COUNT(*) FROM os_groups_roles WHERE GroupID = $1",
                )
                .bind(group_id.to_string())
                .fetch_one(pool)
                .await
                .unwrap_or(1) as i32;
            }
        }

        let mut data = BytesMut::with_capacity(300);
        data.put_slice(agent_id.as_bytes()); // AgentData.AgentID
        data.put_slice(group_id.as_bytes()); // GroupData.GroupID
        let name_b = name.as_bytes();
        data.put_u8(name_b.len().min(255) as u8);
        data.put_slice(&name_b[..name_b.len().min(255)]); // Name
        let charter_b = charter.as_bytes();
        let charter_len = charter_b.len().min(65535);
        data.put_u16_le(charter_len as u16);
        data.put_slice(&charter_b[..charter_len]); // Charter (Variable 2)
        data.put_u8(if show_in_list { 1 } else { 0 }); // ShowInList
        let title = b"Member";
        data.put_u8(title.len() as u8);
        data.put_slice(title); // MemberTitle
        data.put_u64_le(0); // PowersMask
        data.put_slice(insignia_id.as_bytes()); // InsigniaID
        data.put_slice(founder_id.as_bytes()); // FounderID
        data.put_i32_le(membership_fee); // MembershipFee
        data.put_u8(if open_enrollment { 1 } else { 0 }); // OpenEnrollment
        data.put_i32_le(0); // Money
        data.put_i32_le(member_count); // GroupMembershipCount
        data.put_i32_le(role_count); // GroupRolesCount
        data.put_u8(1); // AllowPublish
        data.put_u8(0); // MaturePublish
        data.put_slice(owner_role.as_bytes()); // OwnerRole

        self.send_message(GROUP_PROFILE_REPLY_ID, &data, dest, true, true)
            .await
    }

