    async fn handle_join_group_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 48 {
            let mut cursor = std::io::Cursor::new(&packet.data);

            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);

            let mut _session_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut _session_id_bytes);
            let mut group_id_bytes = [0u8; 16];
            if cursor.remaining() >= 16 {
                cursor.copy_to_slice(&mut group_id_bytes);
            }
            let group_id = Uuid::from_bytes(group_id_bytes);

            info!(
                "[GROUPS] Agent {} requesting to join group {}",
                agent_id, group_id
            );

            let mut success = false;
            if let Some(ref db_conn) = self.db_connection {
                if let Some(pool) = db_conn.postgres_pool() {
                    let everyone_role = Uuid::nil();
                    let result = sqlx::query(
                        "INSERT INTO os_groups_membership (GroupID, AgentID, SelectedRoleID, Contribution, ListInProfile, AcceptNotices) \
                         VALUES ($1, $2, $3, 0, 1, 1) \
                         ON CONFLICT (GroupID, AgentID) DO NOTHING"
                    )
                    .bind(group_id.to_string())
                    .bind(agent_id.to_string())
                    .bind(everyone_role.to_string())
                    .execute(pool)
                    .await;

                    if result.is_ok() {
                        let _ = sqlx::query(
                            "INSERT INTO os_groups_rolemembership (GroupID, RoleID, AgentID) \
                             VALUES ($1, $2, $3) \
                             ON CONFLICT DO NOTHING",
                        )
                        .bind(group_id.to_string())
                        .bind(everyone_role.to_string())
                        .bind(agent_id.to_string())
                        .execute(pool)
                        .await;
                        success = true;
                        info!("[GROUPS] Agent {} joined group {}", agent_id, group_id);
                    }
                }
            }

            self.send_join_group_reply(agent_id, group_id, success, packet.source)
                .await?;
            if success {
                self.send_agent_group_data_update(agent_id, packet.source)
                    .await?;
            }
        }

        Ok(())
    }

    async fn handle_leave_group_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 48 {
            let mut cursor = std::io::Cursor::new(&packet.data);

            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);

            let mut _session_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut _session_id_bytes);
            let mut group_id_bytes = [0u8; 16];
            if cursor.remaining() >= 16 {
                cursor.copy_to_slice(&mut group_id_bytes);
            }
            let group_id = Uuid::from_bytes(group_id_bytes);

            info!(
                "[GROUPS] Agent {} requesting to leave group {}",
                agent_id, group_id
            );

            if let Some(ref db_conn) = self.db_connection {
                if let Some(pool) = db_conn.postgres_pool() {
                    let _ = sqlx::query(
                        "DELETE FROM os_groups_rolemembership WHERE GroupID = $1 AND AgentID = $2",
                    )
                    .bind(group_id.to_string())
                    .bind(agent_id.to_string())
                    .execute(pool)
                    .await;
                    let _ = sqlx::query(
                        "DELETE FROM os_groups_membership WHERE GroupID = $1 AND AgentID = $2",
                    )
                    .bind(group_id.to_string())
                    .bind(agent_id.to_string())
                    .execute(pool)
                    .await;
                }
            }

            self.send_leave_group_reply(agent_id, group_id, true, packet.source)
                .await?;
            self.send_agent_group_data_update(agent_id, packet.source)
                .await?;
        }

        Ok(())
    }

