    async fn handle_accept_friendship(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 48 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);
            cursor.advance(16); // session_id

            let mut transaction_id_bytes = [0u8; 16];
            if cursor.remaining() >= 16 {
                cursor.copy_to_slice(&mut transaction_id_bytes);
            }

            let folder_count = if cursor.remaining() >= 1 {
                cursor.get_u8()
            } else {
                0
            };
            for _ in 0..folder_count {
                if cursor.remaining() >= 16 {
                    cursor.advance(16);
                }
            }

            info!("[FRIENDS] Agent {} accepted friendship", agent_id);

            let friend_id = Uuid::from_bytes(transaction_id_bytes);
            let target_addr = {
                let states = self.avatar_states.read();
                states.get(&friend_id).map(|s| s.client_addr)
            };
            if let Some(dest) = target_addr {
                self.send_online_notification(&[agent_id], dest).await?;
            }
        }
        Ok(())
    }

