    async fn handle_grant_user_rights(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 53 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);
            cursor.advance(16); // session_id

            let rights_count = if cursor.remaining() >= 1 {
                cursor.get_u8()
            } else {
                0
            };
            for _ in 0..rights_count {
                if cursor.remaining() < 20 {
                    break;
                }
                let mut related_bytes = [0u8; 16];
                cursor.copy_to_slice(&mut related_bytes);
                let related_id = Uuid::from_bytes(related_bytes);
                let rights = cursor.get_i32_le();

                info!(
                    "[FRIENDS] Agent {} granting rights {} to {}",
                    agent_id, rights, related_id
                );

                self.send_change_user_rights(agent_id, related_id, rights, packet.source)
                    .await?;

                let target_addr = {
                    let states = self.avatar_states.read();
                    states.get(&related_id).map(|s| s.client_addr)
                };
                if let Some(dest) = target_addr {
                    self.send_change_user_rights(agent_id, related_id, rights, dest)
                        .await?;
                }
            }
        }
        Ok(())
    }

    async fn handle_avatar_notes_update(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() >= 48 {
            let mut cursor = std::io::Cursor::new(&packet.data);
            let mut agent_id_bytes = [0u8; 16];
            cursor.copy_to_slice(&mut agent_id_bytes);
            let agent_id = Uuid::from_bytes(agent_id_bytes);
            cursor.advance(16); // session_id

            let mut target_id_bytes = [0u8; 16];
            if cursor.remaining() >= 16 {
                cursor.copy_to_slice(&mut target_id_bytes);
            }
            let target_id = Uuid::from_bytes(target_id_bytes);

            let notes_len = if cursor.remaining() >= 2 {
                cursor.get_u16_le() as usize
            } else {
                0
            };
            let notes = if cursor.remaining() >= notes_len {
                let mut buf = vec![0u8; notes_len];
                cursor.copy_to_slice(&mut buf);
                String::from_utf8_lossy(&buf).to_string()
            } else {
                String::new()
            };

            info!(
                "[PROFILE] Agent {} updating notes for {}: '{}'",
                agent_id,
                target_id,
                notes.chars().take(50).collect::<String>()
            );
        }
        Ok(())
    }

