        data.put_u32_le(0);
        data.put_u32_le(0);
        data.put_u32_le(0);
        data.put_u32_le(0);
        data.put_slice(Uuid::nil().as_bytes());
        const MAP_LAYER_REPLY_ID: u32 = 0xFFFF0196;
