    async fn send_activate_group_reply(&self, agent_id: Uuid, dest: SocketAddr) -> Result<()> {
        self.send_activate_group_reply_with_group(agent_id, Uuid::nil(), dest)
            .await
    }

    async fn send_activate_group_reply_with_group(
        &self,
        agent_id: Uuid,
        group_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        let session = self.session_manager.get_session_by_agent_id(agent_id);
        let first_name = session
            .as_ref()
            .map(|s| s.first_name.as_str())
            .unwrap_or("Unknown");
        let last_name = session
            .as_ref()
            .map(|s| s.last_name.as_str())
            .unwrap_or("User");

        let mut group_title = String::new();
        let mut group_name = String::new();
        let mut group_powers: u64 = 0;
        let mut active_group = group_id;

        if !group_id.is_nil() {
            if let Some(ref db_conn) = self.db_connection {
                if let Some(pool) = db_conn.postgres_pool() {
                    if let Ok(row) = sqlx::query(
                        "SELECT r.Title, r.Powers, g.Name \
                         FROM os_groups_membership m \
                         JOIN os_groups_roles r ON r.RoleID = m.SelectedRoleID AND r.GroupID = m.GroupID \
                         JOIN os_groups_groups g ON g.GroupID = m.GroupID \
                         WHERE m.AgentID = $1 AND m.GroupID = $2"
                    )
                    .bind(agent_id.to_string())
                    .bind(group_id.to_string())
                    .fetch_one(pool)
                    .await {
                        group_title = sqlx::Row::get(&row, "title");
                        let powers_str: String = sqlx::Row::try_get(&row, "powers").unwrap_or_default();
                        group_powers = powers_str.parse::<u64>().unwrap_or(0);
                        group_name = sqlx::Row::get(&row, "name");
                    }
                }
            }
        } else {
            active_group = Uuid::nil();
        }

        let mut data = BytesMut::with_capacity(120);
        data.put_slice(agent_id.as_bytes());
        let fn_bytes = first_name.as_bytes();
        data.put_u8(fn_bytes.len().min(255) as u8);
        data.put_slice(&fn_bytes[..fn_bytes.len().min(255)]);
        let ln_bytes = last_name.as_bytes();
        data.put_u8(ln_bytes.len().min(255) as u8);
        data.put_slice(&ln_bytes[..ln_bytes.len().min(255)]);
        let title_b = group_title.as_bytes();
        data.put_u8(title_b.len().min(255) as u8);
        data.put_slice(&title_b[..title_b.len().min(255)]);
        data.put_slice(active_group.as_bytes());
        data.put_u64_le(group_powers);
        let name_b = group_name.as_bytes();
        data.put_u8(name_b.len().min(255) as u8);
        data.put_slice(&name_b[..name_b.len().min(255)]);
        self.send_message(AGENT_DATA_UPDATE_ID, &data, dest, true, true)
            .await
    }

    async fn send_parcel_info_reply(
        &self,
        agent_id: Uuid,
        parcel_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        let session = self.session_manager.get_session_by_agent_id(agent_id);
        let region_x = session
            .as_ref()
            .map(|s| s.region_x)
            .unwrap_or(self.region_grid_x * 256);
        let region_y = session
            .as_ref()
            .map(|s| s.region_y)
            .unwrap_or(self.region_grid_y * 256);

        let mut data = BytesMut::with_capacity(200);
        // AgentData block
        data.put_slice(agent_id.as_bytes()); // AgentID
                                             // Data block
        data.put_slice(parcel_id.as_bytes()); // ParcelID
        data.put_slice(agent_id.as_bytes()); // OwnerID
        let name = b"My Land";
        data.put_u8(name.len() as u8);
        data.put_slice(name); // Name (Variable 1)
        let desc = b"Welcome to OpenSim Next!";
        data.put_u8(desc.len() as u8);
        data.put_slice(desc); // Desc (Variable 1)
        data.put_i32_le(65536); // ActualArea
        data.put_i32_le(65536); // BillableArea
        data.put_u8(0x21); // Flags (PG=0x21 matching opensim-master)
        data.put_f32_le(region_x as f32 + 128.0); // GlobalX
        data.put_f32_le(region_y as f32 + 128.0); // GlobalY
        data.put_f32_le(25.0); // GlobalZ
        let sim_name = b"OpenSim Next";
        data.put_u8(sim_name.len() as u8);
        data.put_slice(sim_name); // SimName (Variable 1)
        data.put_slice(Uuid::nil().as_bytes()); // SnapshotID
        data.put_f32_le(0.0); // Dwell
        data.put_i32_le(0); // SalePrice
        data.put_i32_le(0); // AuctionID
        const PARCEL_INFO_REPLY_ID: u32 = 0xFFFF0037; // Low 55
        self.send_message(PARCEL_INFO_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_avatar_sit_response(
        &self,
        target_id: Uuid,
        sit_pos: [f32; 3],
        sit_rot: [f32; 4],
        force_mouselook: bool,
        autopilot: bool,
        dest: SocketAddr,
    ) -> Result<()> {
        let mut data = BytesMut::with_capacity(80);
        data.put_slice(target_id.as_bytes()); // SitObject.ID
        data.put_u8(if autopilot { 1 } else { 0 }); // AutoPilot
        data.put_f32_le(sit_pos[0]);
        data.put_f32_le(sit_pos[1]);
        data.put_f32_le(sit_pos[2]); // SitPosition
        data.put_f32_le(sit_rot[0]);
        data.put_f32_le(sit_rot[1]);
        data.put_f32_le(sit_rot[2]); // SitRotation (xyz only, viewer ignores w)
        data.put_f32_le(0.0);
        data.put_f32_le(0.0);
        data.put_f32_le(1.0); // CameraEyeOffset
        data.put_f32_le(0.0);
        data.put_f32_le(0.0);
        data.put_f32_le(0.0); // CameraAtOffset
        data.put_u8(if force_mouselook { 1 } else { 0 }); // ForceMouselook
        const AVATAR_SIT_RESPONSE_ID: u32 = 0x15; // High 21
        self.send_message(AVATAR_SIT_RESPONSE_ID, &data, dest, true, true)
            .await
    }

    async fn send_group_titles_reply(
        &self,
        agent_id: Uuid,
        group_id: Uuid,
        request_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        const GROUP_TITLES_REPLY_ID: u32 = 0xFFFF0178; // Low 376

        let mut titles: Vec<(String, Uuid, bool)> = Vec::new();

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let selected_role: Option<String> = sqlx::query_scalar(
                    "SELECT SelectedRoleID FROM os_groups_membership WHERE AgentID = $1 AND GroupID = $2"
                )
                .bind(agent_id.to_string())
                .bind(group_id.to_string())
                .fetch_optional(pool)
                .await
                .ok()
                .flatten();

                let selected_uuid = selected_role
                    .and_then(|s| Uuid::parse_str(&s).ok())
                    .unwrap_or(Uuid::nil());

                let rows = sqlx::query(
                    "SELECT r.RoleID, r.Title FROM os_groups_roles r \
                     INNER JOIN os_groups_rolemembership rm ON rm.RoleID = r.RoleID AND rm.GroupID = r.GroupID \
                     WHERE r.GroupID = $1 AND rm.AgentID = $2"
                )
                .bind(group_id.to_string())
                .bind(agent_id.to_string())
                .fetch_all(pool)
                .await
                .unwrap_or_default();

                for row in &rows {
                    let rid_str: String = sqlx::Row::get(row, "roleid");
                    let rid = Uuid::parse_str(&rid_str).unwrap_or(Uuid::nil());
                    let title: String = sqlx::Row::get(row, "title");
                    let selected = rid == selected_uuid;
                    titles.push((title, rid, selected));
                }

                if titles.is_empty() {
                    titles.push(("Member".to_string(), Uuid::nil(), true));
                }
            }
        }

        let mut data = BytesMut::with_capacity(60 + titles.len() * 40);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(group_id.as_bytes());
        data.put_slice(request_id.as_bytes());

        let count = titles.len().min(255);
        data.put_u8(count as u8);

        for (title, role_id, selected) in titles.iter().take(255) {
            let title_b = title.as_bytes();
            data.put_u8(title_b.len().min(255) as u8);
            data.put_slice(&title_b[..title_b.len().min(255)]);
            data.put_slice(role_id.as_bytes());
            data.put_u8(if *selected { 1 } else { 0 });
        }

        self.send_message(GROUP_TITLES_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_group_members_reply(
        &self,
        agent_id: Uuid,
        group_id: Uuid,
        request_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        const GROUP_MEMBERS_REPLY_ID: u32 = 0xFFFF016F; // Low 367

        let mut members: Vec<(Uuid, i32, String, bool)> = Vec::new();

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let rows = sqlx::query(
                    "SELECT m.AgentID, m.Contribution, r.Title, \
                     CASE WHEN g.FounderID = m.AgentID THEN 1 ELSE 0 END as IsOwner \
                     FROM os_groups_membership m \
                     LEFT JOIN os_groups_roles r ON r.GroupID = m.GroupID AND r.RoleID = m.SelectedRoleID \
                     LEFT JOIN os_groups_groups g ON g.GroupID = m.GroupID \
                     WHERE m.GroupID = $1 LIMIT 100"
                )
                .bind(group_id.to_string())
                .fetch_all(pool)
                .await
                .unwrap_or_default();

                for row in &rows {
                    let aid_str: String = sqlx::Row::get(row, "agentid");
                    let aid = Uuid::parse_str(&aid_str).unwrap_or(Uuid::nil());
                    let contribution: i32 = sqlx::Row::get(row, "contribution");
                    let title: Option<String> = sqlx::Row::try_get(row, "title").ok();
                    let is_owner: i32 = sqlx::Row::get(row, "isowner");
                    members.push((aid, contribution, title.unwrap_or_default(), is_owner != 0));
                }
            }
        }

        let mut data = BytesMut::with_capacity(60 + members.len() * 50);
        data.put_slice(agent_id.as_bytes()); // AgentData.AgentID
        data.put_slice(group_id.as_bytes()); // GroupData.GroupID
        data.put_slice(request_id.as_bytes()); // GroupData.RequestID
        data.put_i32_le(members.len() as i32); // GroupData.MemberCount

        let count = members.len().min(255);
        data.put_u8(count as u8);

        for (mid, contribution, title, is_owner) in members.iter().take(255) {
            data.put_slice(mid.as_bytes()); // AgentID
            data.put_i32_le(*contribution); // Contribution
            let online = b"Online";
            data.put_u8(online.len() as u8);
            data.put_slice(online); // OnlineStatus (Variable 1)
            data.put_u64_le(0); // AgentPowers
            let title_b = title.as_bytes();
            data.put_u8(title_b.len().min(255) as u8);
            data.put_slice(&title_b[..title_b.len().min(255)]); // Title
            data.put_u8(if *is_owner { 1 } else { 0 }); // IsOwner
        }

        self.send_message(GROUP_MEMBERS_REPLY_ID, &data, dest, true, true)
            .await
    }

