    async fn send_dir_people_reply(
        &self,
        agent_id: Uuid,
        query_id: Uuid,
        query_text: &str,
        query_start: i64,
        dest: SocketAddr,
    ) -> Result<()> {
        const DIR_PEOPLE_REPLY_ID: u32 = 0xFFFF0024; // Low 36

        struct PersonResult {
            agent_id: Uuid,
            first_name: String,
            last_name: String,
        }
        let mut results: Vec<PersonResult> = Vec::new();

        if !query_text.is_empty() {
            if let Some(db) = &self.db_connection {
                match db.as_ref() {
                    DatabaseConnection::PostgreSQL(pool) => {
                        let pattern = format!("%{}%", query_text);
                        let rows: Vec<(Uuid, String, String)> = sqlx::query_as(
                            "SELECT principalid, firstname, lastname FROM useraccounts WHERE (firstname ILIKE $1 OR lastname ILIKE $1) AND active = 1 ORDER BY firstname, lastname LIMIT 101 OFFSET $2"
                        )
                        .bind(&pattern)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for (pid, fname, lname) in rows {
                            results.push(PersonResult {
                                agent_id: pid,
                                first_name: fname,
                                last_name: lname,
                            });
                        }
                    }
                    DatabaseConnection::MySQL(pool) => {
                        let pattern = format!("%{}%", query_text);
                        let rows: Vec<(String, String, String)> = sqlx::query_as(
                            "SELECT principalid, firstname, lastname FROM useraccounts WHERE (firstname LIKE ? OR lastname LIKE ?) AND active = 1 ORDER BY firstname, lastname LIMIT 101 OFFSET ?"
                        )
                        .bind(&pattern)
                        .bind(&pattern)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for (pid, fname, lname) in rows {
                            if let Ok(uuid) = Uuid::parse_str(&pid) {
                                results.push(PersonResult {
                                    agent_id: uuid,
                                    first_name: fname,
                                    last_name: lname,
                                });
                            }
                        }
                    }
                }
            }
        }

        info!(
            "[SEARCH] DirPeopleReply: {} results for '{}'",
            results.len(),
            query_text
        );

        let mut data = BytesMut::with_capacity(64 + results.len() * 48);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(query_id.as_bytes());
        data.put_u8(results.len().min(255) as u8);
        for person in &results {
            data.put_slice(person.agent_id.as_bytes());
            let fname = person.first_name.as_bytes();
            data.put_u8(fname.len().min(255) as u8);
            data.put_slice(&fname[..fname.len().min(255)]);
            let lname = person.last_name.as_bytes();
            data.put_u8(lname.len().min(255) as u8);
            data.put_slice(&lname[..lname.len().min(255)]);
            data.put_u8(0); // Group (empty Variable1)
            data.put_u8(0); // Online = false
            data.put_i32_le(0); // Reputation
        }

        self.send_message(DIR_PEOPLE_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_dir_groups_reply(
        &self,
        agent_id: Uuid,
        query_id: Uuid,
        query_text: &str,
        query_start: i64,
        dest: SocketAddr,
    ) -> Result<()> {
        const DIR_GROUPS_REPLY_ID: u32 = 0xFFFF0026; // Low 38

        struct GroupResult {
            group_id: Uuid,
            name: String,
            members: i32,
        }
        let mut results: Vec<GroupResult> = Vec::new();

        if !query_text.is_empty() {
            if let Some(db) = &self.db_connection {
                match db.as_ref() {
                    DatabaseConnection::PostgreSQL(pool) => {
                        use sqlx::Row;
                        let pattern = format!("%{}%", query_text);
                        let rows = sqlx::query(
                            "SELECT g.groupid, g.name, COALESCE(m.cnt, 0) as members FROM os_groups_groups g LEFT JOIN (SELECT groupid, COUNT(*) as cnt FROM os_groups_membership GROUP BY groupid) m ON g.groupid = m.groupid WHERE g.name ILIKE $1 AND g.showinlist = 1 ORDER BY g.name LIMIT 101 OFFSET $2"
                        )
                        .bind(&pattern)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for row in rows {
                            let gid: Uuid = row.get("groupid");
                            let name: String = row.get("name");
                            let members: i64 = row.get("members");
                            results.push(GroupResult {
                                group_id: gid,
                                name,
                                members: members as i32,
                            });
                        }
                    }
                    DatabaseConnection::MySQL(pool) => {
                        use sqlx::Row;
                        let pattern = format!("%{}%", query_text);
                        let rows = sqlx::query(
                            "SELECT g.groupid, g.name, COALESCE(m.cnt, 0) as members FROM os_groups_groups g LEFT JOIN (SELECT groupid, COUNT(*) as cnt FROM os_groups_membership GROUP BY groupid) m ON g.groupid = m.groupid WHERE g.name LIKE ? AND g.showinlist = 1 ORDER BY g.name LIMIT 101 OFFSET ?"
                        )
                        .bind(&pattern)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for row in rows {
                            let gid_str: String = row.get("groupid");
                            let name: String = row.get("name");
                            let members: i64 = row.get("members");
                            if let Ok(gid) = Uuid::parse_str(&gid_str) {
                                results.push(GroupResult {
                                    group_id: gid,
                                    name,
                                    members: members as i32,
                                });
                            }
                        }
                    }
                }
            }
        }

        info!(
            "[SEARCH] DirGroupsReply: {} results for '{}'",
            results.len(),
            query_text
        );

        let mut data = BytesMut::with_capacity(64 + results.len() * 40);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(query_id.as_bytes());
        data.put_u8(results.len().min(255) as u8);
        for group in &results {
            data.put_slice(group.group_id.as_bytes());
            let name = group.name.as_bytes();
            data.put_u8(name.len().min(255) as u8);
            data.put_slice(&name[..name.len().min(255)]);
            data.put_i32_le(group.members);
            data.put_f32_le(0.0); // SearchOrder
        }

        self.send_message(DIR_GROUPS_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_dir_places_reply(
        &self,
        agent_id: Uuid,
        query_id: Uuid,
        query_text: &str,
        query_start: i64,
        dest: SocketAddr,
    ) -> Result<()> {
        const DIR_PLACES_REPLY_ID: u32 = 0xFFFF0023; // Low 35

        struct PlaceResult {
            parcel_id: Uuid,
            name: String,
            for_sale: bool,
            auction: bool,
            dwell: f32,
        }
        let mut results: Vec<PlaceResult> = Vec::new();

        if !query_text.is_empty() {
            if let Some(db) = &self.db_connection {
                match db.as_ref() {
                    DatabaseConnection::PostgreSQL(pool) => {
                        use sqlx::Row;
                        let pattern = format!("%{}%", query_text);
                        let rows = sqlx::query(
                            "SELECT uuid, name, landflags, auctionid, dwell FROM land WHERE name ILIKE $1 ORDER BY dwell DESC, name LIMIT 101 OFFSET $2"
                        )
                        .bind(&pattern)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for row in rows {
                            let uid: Uuid = row.get("uuid");
                            let name: String = row.get("name");
                            let flags: i32 = row.get("landflags");
                            let auction: i32 = row.get("auctionid");
                            let dwell: i32 = row.get::<Option<i32>, _>("dwell").unwrap_or(0);
                            let for_sale = (flags & 0x80) != 0;
                            results.push(PlaceResult {
                                parcel_id: uid,
                                name,
                                for_sale,
                                auction: auction > 0,
                                dwell: dwell as f32,
                            });
                        }
                    }
                    DatabaseConnection::MySQL(pool) => {
                        use sqlx::Row;
                        let pattern = format!("%{}%", query_text);
                        let rows = sqlx::query(
                            "SELECT uuid, name, landflags, auctionid, dwell FROM land WHERE name LIKE ? ORDER BY dwell DESC, name LIMIT 101 OFFSET ?"
                        )
                        .bind(&pattern)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for row in rows {
                            let uid_str: String = row.get("uuid");
                            let name: String = row.get("name");
                            let flags: i32 = row.get("landflags");
                            let auction: i32 = row.get("auctionid");
                            let dwell: i32 = row.get::<Option<i32>, _>("dwell").unwrap_or(0);
                            let for_sale = (flags & 0x80) != 0;
                            if let Ok(uid) = Uuid::parse_str(&uid_str) {
                                results.push(PlaceResult {
                                    parcel_id: uid,
                                    name,
                                    for_sale,
                                    auction: auction > 0,
                                    dwell: dwell as f32,
                                });
                            }
                        }
                    }
                }
            }
        }

        info!(
            "[SEARCH] DirPlacesReply: {} results for '{}'",
            results.len(),
            query_text
        );

        let mut data = BytesMut::with_capacity(64 + results.len() * 32);
        data.put_slice(agent_id.as_bytes());
        data.put_u8(1); // QueryData count
        data.put_slice(query_id.as_bytes());
        data.put_u8(results.len().min(255) as u8);
        for place in &results {
            data.put_slice(place.parcel_id.as_bytes());
            let name = place.name.as_bytes();
            data.put_u8(name.len().min(255) as u8);
            data.put_slice(&name[..name.len().min(255)]);
            data.put_u8(if place.for_sale { 1 } else { 0 });
            data.put_u8(if place.auction { 1 } else { 0 });
            data.put_f32_le(place.dwell);
        }
        data.put_u8(1); // StatusData count
        data.put_u32_le(0); // Status = success

        self.send_message(DIR_PLACES_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_dir_land_reply(
        &self,
        agent_id: Uuid,
        query_id: Uuid,
        query_flags: u32,
        price: i32,
        area: i32,
        query_start: i64,
        dest: SocketAddr,
    ) -> Result<()> {
        const DIR_LAND_REPLY_ID: u32 = 0xFFFF0032; // Low 50

        struct LandResult {
            parcel_id: Uuid,
            name: String,
            auction: bool,
            for_sale: bool,
            sale_price: i32,
            actual_area: i32,
        }
        let mut results: Vec<LandResult> = Vec::new();

        if let Some(db) = &self.db_connection {
            match db.as_ref() {
                DatabaseConnection::PostgreSQL(pool) => {
                    use sqlx::Row;
                    let rows = sqlx::query(
                        "SELECT uuid, name, landflags, auctionid, saleprice, area FROM land WHERE (landflags & 128) != 0 AND ($1 <= 0 OR saleprice <= $1) AND ($2 <= 0 OR area >= $2) ORDER BY saleprice ASC, name LIMIT 101 OFFSET $3"
                    )
                    .bind(price)
                    .bind(area)
                    .bind(query_start)
                    .fetch_all(pool)
                    .await
                    .unwrap_or_default();
                    for row in rows {
                        let uid: Uuid = row.get("uuid");
                        let name: String = row.get("name");
                        let flags: i32 = row.get("landflags");
                        let auction: i32 = row.get("auctionid");
                        let sale_price: i32 = row.get("saleprice");
                        let actual_area: i32 = row.get("area");
                        results.push(LandResult {
                            parcel_id: uid,
                            name,
                            auction: auction > 0,
                            for_sale: (flags & 0x80) != 0,
                            sale_price,
                            actual_area,
                        });
                    }
                }
                DatabaseConnection::MySQL(pool) => {
                    use sqlx::Row;
                    let rows = sqlx::query(
                        "SELECT uuid, name, landflags, auctionid, saleprice, area FROM land WHERE (landflags & 128) != 0 AND (? <= 0 OR saleprice <= ?) AND (? <= 0 OR area >= ?) ORDER BY saleprice ASC, name LIMIT 101 OFFSET ?"
                    )
                    .bind(price)
                    .bind(price)
                    .bind(area)
                    .bind(area)
                    .bind(query_start)
                    .fetch_all(pool)
                    .await
                    .unwrap_or_default();
                    for row in rows {
                        let uid_str: String = row.get("uuid");
                        let name: String = row.get("name");
                        let flags: i32 = row.get("landflags");
                        let auction: i32 = row.get("auctionid");
                        let sale_price: i32 = row.get("saleprice");
                        let actual_area: i32 = row.get("area");
                        if let Ok(uid) = Uuid::parse_str(&uid_str) {
                            results.push(LandResult {
                                parcel_id: uid,
                                name,
                                auction: auction > 0,
                                for_sale: (flags & 0x80) != 0,
                                sale_price,
                                actual_area,
                            });
                        }
                    }
                }
            }
        }

        info!(
            "[SEARCH] DirLandReply: {} results (flags=0x{:04X} price={} area={})",
            results.len(),
            query_flags,
            price,
            area
        );

        let mut data = BytesMut::with_capacity(64 + results.len() * 36);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(query_id.as_bytes());
        data.put_u8(results.len().min(255) as u8);
        for land in &results {
            data.put_slice(land.parcel_id.as_bytes());
            let name = land.name.as_bytes();
            data.put_u8(name.len().min(255) as u8);
            data.put_slice(&name[..name.len().min(255)]);
            data.put_u8(if land.auction { 1 } else { 0 });
            data.put_u8(if land.for_sale { 1 } else { 0 });
            data.put_i32_le(land.sale_price);
            data.put_i32_le(land.actual_area);
        }

        self.send_message(DIR_LAND_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_places_reply(
        &self,
        agent_id: Uuid,
        query_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        let mut data = BytesMut::with_capacity(60);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(query_id.as_bytes());
        data.put_slice(Uuid::nil().as_bytes()); // TransactionData.TransactionID
        data.put_u8(0); // QueryData count = 0
        const PLACES_REPLY_ID: u32 = 0xFFFF001E; // Low 30
        self.send_message(PLACES_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_dir_classified_reply(
        &self,
        agent_id: Uuid,
        query_id: Uuid,
        query_text: &str,
        query_start: i64,
        dest: SocketAddr,
    ) -> Result<()> {
        const DIR_CLASSIFIED_REPLY_ID: u32 = 0xFFFF0029; // Low 41

        struct ClassifiedResult {
            id: Uuid,
            name: String,
            flags: u8,
            creation: u32,
            expiration: u32,
            price: i32,
        }
        let mut results: Vec<ClassifiedResult> = Vec::new();

        if !query_text.is_empty() {
            if let Some(db) = &self.db_connection {
                match db.as_ref() {
                    DatabaseConnection::PostgreSQL(pool) => {
                        use sqlx::Row;
                        let pattern = format!("%{}%", query_text);
                        let now = std::time::SystemTime::now()
                            .duration_since(std::time::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs() as i64;
                        let rows = sqlx::query(
                            "SELECT classifieduuid, name, classifiedflags, creationdate, expirationdate, priceforlisting FROM classifieds WHERE name ILIKE $1 AND expirationdate > $2 ORDER BY priceforlisting DESC, name LIMIT 101 OFFSET $3"
                        )
                        .bind(&pattern)
                        .bind(now)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for row in rows {
                            let uid: Uuid = row.get("classifieduuid");
                            let name: String = row.get("name");
                            let flags: i32 = row.get("classifiedflags");
                            let creation: i64 = row.get("creationdate");
                            let expiration: i64 = row.get("expirationdate");
                            let price: i32 = row.get("priceforlisting");
                            results.push(ClassifiedResult {
                                id: uid,
                                name,
                                flags: flags as u8,
                                creation: creation as u32,
                                expiration: expiration as u32,
                                price,
                            });
                        }
                    }
                    DatabaseConnection::MySQL(pool) => {
                        use sqlx::Row;
                        let pattern = format!("%{}%", query_text);
                        let now = std::time::SystemTime::now()
                            .duration_since(std::time::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs() as i64;
                        let rows = sqlx::query(
                            "SELECT classifieduuid, name, classifiedflags, creationdate, expirationdate, priceforlisting FROM classifieds WHERE name LIKE ? AND expirationdate > ? ORDER BY priceforlisting DESC, name LIMIT 101 OFFSET ?"
                        )
                        .bind(&pattern)
                        .bind(now)
                        .bind(query_start)
                        .fetch_all(pool)
                        .await
                        .unwrap_or_default();
                        for row in rows {
                            let uid_str: String = row.get("classifieduuid");
                            let name: String = row.get("name");
                            let flags: i32 = row.get("classifiedflags");
                            let creation: i64 = row.get("creationdate");
                            let expiration: i64 = row.get("expirationdate");
                            let price: i32 = row.get("priceforlisting");
                            if let Ok(uid) = Uuid::parse_str(&uid_str) {
                                results.push(ClassifiedResult {
                                    id: uid,
                                    name,
                                    flags: flags as u8,
                                    creation: creation as u32,
                                    expiration: expiration as u32,
                                    price,
                                });
                            }
                        }
                    }
                }
            }
        }

        info!(
            "[SEARCH] DirClassifiedReply: {} results for '{}'",
            results.len(),
            query_text
        );

        let mut data = BytesMut::with_capacity(64 + results.len() * 40);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(query_id.as_bytes());
        data.put_u8(results.len().min(255) as u8);
        for c in &results {
            data.put_slice(c.id.as_bytes());
            let name = c.name.as_bytes();
            data.put_u8(name.len().min(255) as u8);
            data.put_slice(&name[..name.len().min(255)]);
            data.put_u8(c.flags);
            data.put_u32_le(c.creation);
            data.put_u32_le(c.expiration);
            data.put_i32_le(c.price);
        }
        data.put_u8(1); // StatusData count
        data.put_u32_le(0); // Status = success

        self.send_message(DIR_CLASSIFIED_REPLY_ID, &data, dest, true, true)
            .await
    }

    async fn send_event_info_reply(
        &self,
        agent_id: Uuid,
        event_id: u32,
        dest: SocketAddr,
    ) -> Result<()> {
        const EVENT_INFO_REPLY_ID: u32 = 0xFFFF00B4; // Low 180

        let mut data = BytesMut::with_capacity(128);
        data.put_slice(agent_id.as_bytes());
        data.put_u32_le(event_id);
        data.put_u8(0); // Creator (empty Variable1)
        data.put_u8(0); // Name (empty Variable1)
        data.put_u8(0); // Category (empty Variable1)
        data.put_u16_le(0); // Desc (empty Variable2)
        data.put_u8(0); // Date (empty Variable1)
        data.put_u32_le(0); // DateUTC
        data.put_u32_le(0); // Duration
        data.put_u32_le(0); // Cover
        data.put_u32_le(0); // Amount
        data.put_u8(0); // SimName (empty Variable1)
        data.put_f64_le(0.0); // GlobalPos.X (LLVector3d = 3 * f64)
        data.put_f64_le(0.0); // GlobalPos.Y
        data.put_f64_le(0.0); // GlobalPos.Z
        data.put_u32_le(0); // EventFlags

        self.send_message(EVENT_INFO_REPLY_ID, &data, dest, true, false)
            .await
    }

    async fn send_group_notices_list_reply(
        &self,
        agent_id: Uuid,
        group_id: Uuid,
        dest: SocketAddr,
    ) -> Result<()> {
        const GROUP_NOTICES_LIST_REPLY_ID: u32 = 0xFFFF017B; // Low 379

        let mut notices: Vec<(Uuid, String, String, u32, bool)> = Vec::new();

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let rows = sqlx::query(
                    "SELECT NoticeID, Timestamp, FromName, Subject, HasAttachment \
                     FROM os_groups_notices WHERE GroupID = $1 \
                     ORDER BY Timestamp DESC LIMIT 20",
                )
                .bind(group_id.to_string())
                .fetch_all(pool)
                .await
                .unwrap_or_default();

                for row in &rows {
                    let nid_str: String = sqlx::Row::get(row, "noticeid");
                    let nid = Uuid::parse_str(&nid_str).unwrap_or(Uuid::nil());
                    let timestamp: i32 = sqlx::Row::get(row, "timestamp");
                    let from_name: String = sqlx::Row::get(row, "fromname");
                    let subject: String = sqlx::Row::get(row, "subject");
                    let has_attach: i32 = sqlx::Row::try_get(row, "hasattachment").unwrap_or(0);
                    notices.push((nid, from_name, subject, timestamp as u32, has_attach != 0));
                }
            }
        }

        let mut data = BytesMut::with_capacity(40 + notices.len() * 80);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(group_id.as_bytes());

        let count = notices.len().min(255);
        data.put_u8(count as u8);

        for (notice_id, from_name, subject, timestamp, has_attach) in notices.iter().take(255) {
            data.put_slice(notice_id.as_bytes());
            data.put_u32_le(*timestamp);
            let from_b = from_name.as_bytes();
            data.put_u16_le(from_b.len().min(255) as u16);
            data.put_slice(&from_b[..from_b.len().min(255)]);
            let subj_b = subject.as_bytes();
            data.put_u16_le(subj_b.len().min(255) as u16);
            data.put_slice(&subj_b[..subj_b.len().min(255)]);
            data.put_u8(if *has_attach { 1 } else { 0 });
            data.put_slice(Uuid::nil().as_bytes()); // AssetType placeholder
        }

        self.send_message(GROUP_NOTICES_LIST_REPLY_ID, &data, dest, true, false)
            .await
    }

    async fn send_estate_covenant_reply(&self, dest: SocketAddr) -> Result<()> {
        let mut covenant_id = Uuid::nil();
        let mut covenant_timestamp: u32 = 0;

        if let Some(db) = &self.db_connection {
            let region_uuid = self.default_region_uuid;
            match db.as_ref() {
                crate::database::multi_backend::DatabaseConnection::PostgreSQL(pool) => {
                    if let Ok(row) = sqlx::query(
                        "SELECT covenant, covenant_datetime FROM regionsettings WHERE regionuuid = $1::uuid"
                    )
                    .bind(region_uuid)
                    .fetch_optional(pool)
                    .await
                    {
                        if let Some(row) = row {
                            use sqlx::Row;
                            if let Ok(cov) = row.try_get::<Uuid, _>("covenant") {
                                covenant_id = cov;
                            }
                            if let Ok(ts) = row.try_get::<i32, _>("covenant_datetime") {
                                covenant_timestamp = ts as u32;
                            }
                        }
                    }
                }
                _ => {}
            }
        }

        let mut data = BytesMut::with_capacity(60);
        data.put_slice(covenant_id.as_bytes());
        data.put_u32_le(covenant_timestamp);
        let estate_name = self.estate_name.as_bytes();
        data.put_u8(estate_name.len() as u8);
        data.put_slice(estate_name);
        data.put_slice(self.estate_owner.as_bytes());
        const ESTATE_COVENANT_REPLY_ID: u32 = 0xFFFF00CC; // Low 204
        self.send_message(ESTATE_COVENANT_REPLY_ID, &data, dest, true, false)
            .await
    }

    async fn send_estate_update_info(&self, invoice: Uuid, dest: SocketAddr) -> Result<()> {
        let estate_id = 100u32;
        let estate_flags = 0x00000011u32;
        let parent_estate_id = 1u32;

        let mut data = BytesMut::with_capacity(512);
        data.put_slice(Uuid::nil().as_bytes()); // AgentID (filled by viewer)
        data.put_slice(Uuid::nil().as_bytes()); // SessionID
        data.put_slice(Uuid::new_v4().as_bytes()); // TransactionID

        let method_bytes = b"estateupdateinfo";
        data.put_u8(method_bytes.len() as u8);
        data.put_slice(method_bytes);
        data.put_slice(invoice.as_bytes());

        let params: Vec<String> = vec![
            self.estate_name.clone(),
            self.estate_owner.to_string(),
            estate_id.to_string(),
            estate_flags.to_string(),
            "0".to_string(),
            parent_estate_id.to_string(),
            Uuid::nil().to_string(),
            "0".to_string(),
            "1".to_string(),
            String::new(),
        ];
        data.put_u8(params.len() as u8);
        for p in &params {
            let bytes = p.as_bytes();
            data.put_u8(bytes.len() as u8);
            data.put_slice(bytes);
        }

        const ESTATE_OWNER_MESSAGE_ID: u32 = 0xFFFF0104; // Low 260
        self.send_message(ESTATE_OWNER_MESSAGE_ID, &data, dest, true, true)
            .await?;
        info!(
            "[ESTATE] Sent estateupdateinfo to {} (owner={}, estate='{}')",
            dest, self.estate_owner, self.estate_name
        );
        Ok(())
    }

    // ============================================
    // Phase 93: Missing Handler Implementations
    // ============================================

    async fn handle_agent_request_sit(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 48 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let target_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));
            let viewer_offset = if packet.data.len() >= 60 {
                [
                    f32::from_le_bytes(packet.data[48..52].try_into().unwrap_or([0u8; 4])),
                    f32::from_le_bytes(packet.data[52..56].try_into().unwrap_or([0u8; 4])),
                    f32::from_le_bytes(packet.data[56..60].try_into().unwrap_or([0u8; 4])),
                ]
            } else {
                [0.0, 0.0, 0.0]
            };
            info!(
                "[SIT] Agent {} requesting sit on {} offset {:?}",
                agent_id, target_id, viewer_offset
            );

            #[derive(Clone)]
            struct SitSearchResult {
                sit_prim_uuid: Uuid,
                sit_prim_local_id: u32,
                sit_prim_is_root: bool,
                sit_prim_offset_pos: [f32; 3],
                sit_prim_rotation: [f32; 4],
                sit_target_pos: [f32; 3],
                sit_target_rot: [f32; 4],
                group_root_uuid: Uuid,
                group_root_local_id: u32,
                group_root_rotation: [f32; 4],
                already_occupied: bool,
            }

            let sit_result: Option<SitSearchResult> = {
                let objects = self.scene_objects.read();
                let clicked = objects.values().find(|o| o.uuid == target_id);
                if let Some(clicked_obj) = clicked {
                    let group_id = clicked_obj.scene_group_id;

                    let sit_part = if clicked_obj.sit_target_pos.is_some()
                        && clicked_obj.sitting_avatar.is_none()
                    {
                        Some(clicked_obj)
                    } else {
                        objects
                            .values()
                            .filter(|o| {
                                o.scene_group_id == group_id
                                    && o.sit_target_pos.is_some()
                                    && o.sitting_avatar.is_none()
                                    && o.uuid != target_id
                            })
                            .next()
                    };

                    if let Some(part) = sit_part {
                        let root = objects
                            .values()
                            .find(|o| o.scene_group_id == group_id && o.parent_id == 0)
                            .unwrap_or(part);

                        Some(SitSearchResult {
                            sit_prim_uuid: part.uuid,
                            sit_prim_local_id: part.local_id,
                            sit_prim_is_root: part.parent_id == 0,
                            sit_prim_offset_pos: part.position,
                            sit_prim_rotation: part.rotation,
                            sit_target_pos: part.sit_target_pos.unwrap_or([0.0, 0.0, 0.0]),
                            sit_target_rot: part.sit_target_rot.unwrap_or([0.0, 0.0, 0.0, 1.0]),
                            group_root_uuid: root.uuid,
                            group_root_local_id: root.local_id,
                            group_root_rotation: root.rotation,
                            already_occupied: part.sitting_avatar.is_some(),
                        })
                    } else {
                        let root = objects
                            .values()
                            .find(|o| o.scene_group_id == group_id && o.parent_id == 0)
                            .unwrap_or(clicked_obj);

                        Some(SitSearchResult {
                            sit_prim_uuid: clicked_obj.uuid,
                            sit_prim_local_id: clicked_obj.local_id,
                            sit_prim_is_root: clicked_obj.parent_id == 0,
                            sit_prim_offset_pos: clicked_obj.position,
                            sit_prim_rotation: clicked_obj.rotation,
                            sit_target_pos: [0.0; 3],
                            sit_target_rot: [0.0, 0.0, 0.0, 1.0],
                            group_root_uuid: root.uuid,
                            group_root_local_id: root.local_id,
                            group_root_rotation: root.rotation,
                            already_occupied: clicked_obj.sitting_avatar.is_some(),
                        })
                    }
                } else {
                    None
                }
            };

            if let Some(result) = sit_result {
                if result.already_occupied {
                    info!(
                        "[SIT] Sit target prim {} already has a sitting avatar, rejecting",
                        result.sit_prim_uuid
                    );
                    return Ok(());
                }

                let has_explicit_sit_target = result.sit_target_pos != [0.0, 0.0, 0.0];

                let (mut sit_offset, sit_rot) = if has_explicit_sit_target {
                    (result.sit_target_pos, result.sit_target_rot)
                } else {
                    (
                        [viewer_offset[0], viewer_offset[1], viewer_offset[2] + 0.4],
                        [0.0, 0.0, 0.0, 1.0],
                    )
                };

                if has_explicit_sit_target {
                    sit_offset[2] += 0.4;
                }

                if !result.sit_prim_is_root {
                    let rx = result.sit_prim_rotation[0];
                    let ry = result.sit_prim_rotation[1];
                    let rz = result.sit_prim_rotation[2];
                    let rw = result.sit_prim_rotation[3];
                    let ox = sit_offset[0];
                    let oy = sit_offset[1];
                    let oz = sit_offset[2];
                    sit_offset[0] = (1.0 - 2.0 * (ry * ry + rz * rz)) * ox
                        + 2.0 * (rx * ry - rz * rw) * oy
                        + 2.0 * (rx * rz + ry * rw) * oz;
                    sit_offset[1] = 2.0 * (rx * ry + rz * rw) * ox
                        + (1.0 - 2.0 * (rx * rx + rz * rz)) * oy
                        + 2.0 * (ry * rz - rx * rw) * oz;
                    sit_offset[2] = 2.0 * (rx * rz - ry * rw) * ox
                        + 2.0 * (ry * rz + rx * rw) * oy
                        + (1.0 - 2.0 * (rx * rx + ry * ry)) * oz;
                    sit_offset[0] += result.sit_prim_offset_pos[0];
                    sit_offset[1] += result.sit_prim_offset_pos[1];
                    sit_offset[2] += result.sit_prim_offset_pos[2];
                }

                {
                    let mut states = self.avatar_states.write();
                    if let Some(state) = states.get_mut(&agent_id) {
                        state.sit_object_id = Some(result.sit_prim_uuid);
                        state.sit_object_local_id = result.group_root_local_id;
                        state.sit_offset = sit_offset;
                    }
                }

                info!(
                    "[SIT] Sit target found on prim {} (is_root={}), group_root={}, offset={:?}",
                    result.sit_prim_uuid,
                    result.sit_prim_is_root,
                    result.group_root_local_id,
                    sit_offset
                );
                self.send_avatar_sit_response(
                    result.group_root_uuid,
                    sit_offset,
                    sit_rot,
                    false,
                    !has_explicit_sit_target,
                    packet.source,
                )
                .await?;

                if has_explicit_sit_target {
                    info!("[SIT] Explicit sit target — processing sit immediately (no AgentSit needed)");

                    let (avatar_local_id, avatar_name) = {
                        let mut states = self.avatar_states.write();
                        if let Some(state) = states.get_mut(&agent_id) {
                            state.is_sitting = true;
                            state.target_velocity = [0.0; 3];
                            state.position = sit_offset;
                            let name = if let Some(sess) =
                                self.session_manager.get_session_by_agent_id(agent_id)
                            {
                                format!("{} {}", sess.first_name, sess.last_name)
                            } else {
                                "Avatar Resident".to_string()
                            };
                            (state.local_id, name)
                        } else {
                            (0u32, String::new())
                        }
                    };

                    let script_ids = {
                        let mut objects = self.scene_objects.write();
                        let group_id = objects
                            .values()
                            .find(|o| o.uuid == result.sit_prim_uuid)
                            .map(|o| o.scene_group_id);
                        if let Some(obj) = objects
                            .values_mut()
                            .find(|o| o.uuid == result.sit_prim_uuid)
                        {
                            obj.sitting_avatar = Some(agent_id);
                        }
                        if let Some(gid) = group_id {
                            objects
                                .values()
                                .filter(|o| o.scene_group_id == gid)
                                .flat_map(|o| o.script_items.iter().copied())
                                .collect::<Vec<Uuid>>()
                        } else {
                            Vec::new()
                        }
                    };

                    info!(
                        "[SIT] Firing changed(CHANGED_LINK) to {} scripts in linkset",
                        script_ids.len()
                    );
                    if let Some(ref yeng) = self.yengine {
                        let engine = yeng.read();
                        engine.update_sitting_avatar(&script_ids, agent_id);
                        for sid in &script_ids {
                            engine.post_event(
                                *sid,
                                crate::scripting::state_machine::ScriptEvent {
                                    event_type:
                                        crate::scripting::state_machine::ScriptEventType::Changed,
                                    args: vec![crate::scripting::LSLValue::Integer(32)],
                                },
                            );
                        }
                    }

                    info!(
                        "[SIT] Broadcasting avatar ObjectUpdate with parent_id={} offset={:?}",
                        result.group_root_local_id, sit_offset
                    );
                    let mut avatar_obj =
                        crate::udp::messages::object_update::AvatarObjectData::create_avatar(
                            agent_id,
                            avatar_local_id,
                            sit_offset,
                            avatar_name,
                        );
                    avatar_obj.parent_id = result.group_root_local_id;
                    let update = crate::udp::messages::object_update::ObjectUpdateMessage {
                        region_handle: self.region_handle,
                        time_dilation: 65535,
                        objects: vec![avatar_obj],
                    };
                    let update_data = update.serialize();

                    let all_viewers: Vec<SocketAddr> = {
                        let states = self.avatar_states.read();
                        states
                            .values()
                            .filter(|s| !s.is_npc)
                            .map(|s| s.client_addr)
                            .collect()
                    };
                    for addr in &all_viewers {
                        let _ = self
                            .send_message(OBJECT_UPDATE_ID, &update_data, *addr, true, true)
                            .await;
                    }
                }
            } else {
                warn!("[SIT] Target object {} not found in scene", target_id);
            }
        }
        Ok(())
    }

    async fn handle_agent_sit(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 32 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            info!("[SIT] Agent {} confirmed sit", agent_id);

            let (sit_obj_id, obj_local_id, sit_offset, avatar_local_id, avatar_name) = {
                let mut states = self.avatar_states.write();
                if let Some(state) = states.get_mut(&agent_id) {
                    state.is_sitting = true;
                    state.target_velocity = [0.0; 3];
                    state.position = state.sit_offset;
                    let name = if let Some(sess) =
                        self.session_manager.get_session_by_agent_id(agent_id)
                    {
                        format!("{} {}", sess.first_name, sess.last_name)
                    } else {
                        "Avatar Resident".to_string()
                    };
                    (
                        state.sit_object_id,
                        state.sit_object_local_id,
                        state.sit_offset,
                        state.local_id,
                        name,
                    )
                } else {
                    (None, 0u32, [0.0f32; 3], 0u32, String::new())
                }
            };

            if let Some(obj_id) = sit_obj_id {
                let script_ids = {
                    let mut objects = self.scene_objects.write();
                    let group_id = objects
                        .values()
                        .find(|o| o.uuid == obj_id)
                        .map(|o| o.scene_group_id);
                    if let Some(obj) = objects.values_mut().find(|o| o.uuid == obj_id) {
                        obj.sitting_avatar = Some(agent_id);
                    }
                    if let Some(gid) = group_id {
                        objects
                            .values()
                            .filter(|o| o.scene_group_id == gid)
                            .flat_map(|o| o.script_items.iter().copied())
                            .collect::<Vec<Uuid>>()
                    } else {
                        Vec::new()
                    }
                };
                info!(
                    "[SIT] Firing changed(CHANGED_LINK) to {} scripts in linkset",
                    script_ids.len()
                );
                if let Some(ref yeng) = self.yengine {
                    let engine = yeng.read();
                    engine.update_sitting_avatar(&script_ids, agent_id);
                    for sid in &script_ids {
                        engine.post_event(
                            *sid,
                            crate::scripting::state_machine::ScriptEvent {
                                event_type:
                                    crate::scripting::state_machine::ScriptEventType::Changed,
                                args: vec![crate::scripting::LSLValue::Integer(32)],
                            },
                        );
                    }
                }

                info!(
                    "[SIT] Broadcasting avatar ObjectUpdate with parent_id={} offset={:?}",
                    obj_local_id, sit_offset
                );
                let mut avatar_obj =
                    crate::udp::messages::object_update::AvatarObjectData::create_avatar(
                        agent_id,
                        avatar_local_id,
                        sit_offset,
                        avatar_name,
                    );
                avatar_obj.parent_id = obj_local_id;
                let update = crate::udp::messages::object_update::ObjectUpdateMessage {
                    region_handle: self.region_handle,
                    time_dilation: 65535,
                    objects: vec![avatar_obj],
                };
                let update_data = update.serialize();

                let all_viewers: Vec<SocketAddr> = {
                    let states = self.avatar_states.read();
                    states
                        .values()
                        .filter(|s| !s.is_npc)
                        .map(|s| s.client_addr)
                        .collect()
                };
                for addr in &all_viewers {
                    let _ = self
                        .send_message(OBJECT_UPDATE_ID, &update_data, *addr, true, true)
                        .await;
                }
            }
        }
        Ok(())
    }

    async fn handle_agent_is_now_wearing(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() < 33 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let session_id = Uuid::from_bytes(packet.data[16..32].try_into().unwrap_or([0u8; 16]));

        let mut offset = 32;
        let wearable_count = packet.data[offset] as usize;
        offset += 1;

        let mut wearables: Vec<(Uuid, u8)> = Vec::new();
        for _ in 0..wearable_count {
            if offset + 17 > packet.data.len() {
                break;
            }
            let item_id = Uuid::from_bytes(
                packet.data[offset..offset + 16]
                    .try_into()
                    .unwrap_or([0u8; 16]),
            );
            let wearable_type = packet.data[offset + 16];
            offset += 17;
            wearables.push((item_id, wearable_type));
        }

        info!(
            "[WEARABLE] Agent {} AgentIsNowWearing: {} wearable slots",
            agent_id,
            wearables.len()
        );

        for (item_id, wtype) in &wearables {
            if item_id.is_nil() {
                info!("[WEARABLE]   slot {} = <empty>", wtype);
            } else {
                info!("[WEARABLE]   slot {} = item {}", wtype, item_id);
            }
        }

        if let Some(db) = &self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                for (item_id, wearable_type) in &wearables {
                    let name = format!("Wearable {}:0", wearable_type);
                    let name_old = format!("Wearable {}", wearable_type);

                    if item_id.is_nil() {
                        let _ = sqlx::query(
                            "DELETE FROM avatars WHERE principalid = $1::uuid AND (name = $2 OR name = $3)"
                        )
                        .bind(agent_id.to_string())
                        .bind(&name)
                        .bind(&name_old)
                        .execute(pool)
                        .await;
                        continue;
                    }

                    let mut resolved_asset_id = Uuid::nil();

                    let item_info: Option<(Uuid, i32)> = sqlx::query_as(
                        "SELECT assetid, assettype FROM inventoryitems WHERE inventoryid = $1",
                    )
                    .bind(item_id)
                    .fetch_optional(pool)
                    .await
                    .ok()
                    .flatten();

                    if let Some((asset_id, asset_type)) = item_info {
                        resolved_asset_id = asset_id;
                        if asset_type == 24 && !asset_id.is_nil() {
                            if let Ok(Some((real_asset,))) = sqlx::query_as::<_, (Uuid,)>(
                                "SELECT assetid FROM inventoryitems WHERE inventoryid = $1",
                            )
                            .bind(asset_id)
                            .fetch_optional(pool)
                            .await
                            {
                                resolved_asset_id = real_asset;
                            }
                        }
                    } else {
                        warn!("[WEARABLE] Could not find item {} in inventory (type {}), saving with nil asset", item_id, wearable_type);
                    }

                    let value = format!("{}:{}", item_id, resolved_asset_id);

                    let _ = sqlx::query(
                        "DELETE FROM avatars WHERE principalid = $1::uuid AND name = $2",
                    )
                    .bind(agent_id.to_string())
                    .bind(&name_old)
                    .execute(pool)
                    .await;

                    let _ = sqlx::query(
                        "INSERT INTO avatars (principalid, name, value) VALUES ($1::uuid, $2, $3) \
                         ON CONFLICT (principalid, name) DO UPDATE SET value = $3",
                    )
                    .bind(agent_id.to_string())
                    .bind(&name)
                    .bind(&value)
                    .execute(pool)
                    .await;

                    info!(
                        "[WEARABLE] Saved {} = {} for agent {}",
                        name, value, agent_id
                    );
                }
            }
        }

        // C# OpenSim does NOT send AgentWearablesUpdate here.
        // The viewer already knows what it's wearing — it sent us the data.
        // Sending a response from COF/DB during intermediate states confuses
        // the viewer's state machine (COF already has new item even when
        // viewer says slot is empty during 3-message swap sequence).
        // The viewer will send AgentSetAppearance next, triggering the bake cycle.

        Ok(())
    }

