    async fn handle_request_pay_price(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 16 {
            let object_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let pay_prices = {
                let objects = self.scene_objects.read();
                objects
                    .values()
                    .find(|o| o.uuid == object_id)
                    .map(|o| o.pay_price)
                    .unwrap_or([-1, -1, -1, -1, -1])
            };
            let mut data = BytesMut::with_capacity(40);
            data.put_slice(object_id.as_bytes());
            data.put_i32_le(pay_prices[0]);
            data.put_u8(4);
            data.put_i32_le(pay_prices[1]);
            data.put_i32_le(pay_prices[2]);
            data.put_i32_le(pay_prices[3]);
            data.put_i32_le(pay_prices[4]);
            const PAY_PRICE_REPLY_ID: u32 = 0xFFFF00A2; // Low 162
            self.send_message(PAY_PRICE_REPLY_ID, &data, packet.source, true, false)
                .await?;
            info!(
                "[ECONOMY] PayPriceReply for {}: default={} buttons=[{},{},{},{}]",
                object_id,
                pay_prices[0],
                pay_prices[1],
                pay_prices[2],
                pay_prices[3],
                pay_prices[4]
            );
        }
        Ok(())
    }

    async fn handle_estate_owner_message(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 50 {
            return Ok(());
        }
        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let mut offset = 48;
        let method_len = if offset < packet.data.len() {
            packet.data[offset] as usize
        } else {
            0
        };
        offset += 1;
        let method = if offset + method_len <= packet.data.len() {
            String::from_utf8_lossy(&packet.data[offset..offset + method_len])
                .trim_end_matches('\0')
                .to_string()
        } else {
            String::new()
        };
        offset += method_len;
        let _invoice = if offset + 16 <= packet.data.len() {
            Uuid::from_bytes(
                packet.data[offset..offset + 16]
                    .try_into()
                    .unwrap_or([0u8; 16]),
            )
        } else {
            Uuid::nil()
        };
        offset += 16;
        let mut params: Vec<String> = Vec::new();
        if offset < packet.data.len() {
            let param_count = packet.data[offset] as usize;
            offset += 1;
            for _ in 0..param_count {
                if offset >= packet.data.len() {
                    break;
                }
                let plen = packet.data[offset] as usize;
                offset += 1;
                if offset + plen <= packet.data.len() {
                    params.push(
                        String::from_utf8_lossy(&packet.data[offset..offset + plen])
                            .trim_end_matches('\0')
                            .to_string(),
                    );
                }
                offset += plen;
            }
        }
        info!(
            "[ESTATE] EstateOwnerMessage method='{}' params={:?} from {}",
            method, params, agent_id
        );
        match method.as_str() {
            "getinfo" => {
                self.send_estate_update_info(_invoice, packet.source)
                    .await?;
            }
            "restart" => {
                let delay_secs: u64 = params.first().and_then(|s| s.parse().ok()).unwrap_or(120);
                info!(
                    "[ESTATE] Region restart requested by {} in {}s",
                    agent_id, delay_secs
                );
                let client_addrs: Vec<std::net::SocketAddr> = {
                    let states = self.avatar_states.read();
                    states
                        .values()
                        .filter(|s| !s.is_npc)
                        .map(|s| s.client_addr)
                        .collect()
                };
                for addr in &client_addrs {
                    let msg = format!("Region restart in {} seconds", delay_secs);
                    self.send_chat_alert(*addr, &msg).await.ok();
                }
            }
            "setregioninfo" => {
                info!("[ESTATE] SetRegionInfo: {:?}", params);
            }
            "texturebase" | "texturedetail" | "textureheights" | "texturecommit" => {
                info!("[ESTATE] Terrain texture op: {} {:?}", method, params);
            }
            "estatechangecovenantid" => {
                if let Some(cov_str) = params.first() {
                    if let Ok(cov_id) = Uuid::parse_str(cov_str) {
                        let now = std::time::SystemTime::now()
                            .duration_since(std::time::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs() as i32;
                        if let Some(db) = &self.db_connection {
                            let region_uuid = self.default_region_uuid;
                            match db.as_ref() {
                                crate::database::multi_backend::DatabaseConnection::PostgreSQL(
                                    pool,
                                ) => {
                                    let _ = sqlx::query(
                                        "UPDATE regionsettings SET covenant = $1::uuid, covenant_datetime = $2 WHERE regionuuid = $3::uuid"
                                    )
                                    .bind(cov_id)
                                    .bind(now)
                                    .bind(region_uuid)
                                    .execute(pool)
                                    .await;
                                }
                                _ => {}
                            }
                        }
                        info!(
                            "[ESTATE] Covenant changed to {} at timestamp {}",
                            cov_id, now
                        );
                        self.send_estate_covenant_reply(packet.source).await?;
                    }
                }
            }
            "setaccess" => {
                info!("[ESTATE] Access list change: {:?}", params);
            }
            "telehub" => {
                let op = params.first().map(|s| s.as_str()).unwrap_or("");
                info!("[ESTATE] Telehub operation: {} {:?}", op, &params[1..]);
            }
            "kickestate" => {
                info!("[ESTATE] Kick from estate: {:?}", params);
            }
            _ => {
                info!("[ESTATE] Unhandled method: {} {:?}", method, params);
            }
        }
        Ok(())
    }

