    async fn handle_request_godlike_powers(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 33 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let godlike = packet.data[32] != 0;
            info!(
                "[ADMIN] Agent {} requesting godlike powers (godlike={})",
                agent_id, godlike
            );

            let mut god_level: u8 = 0;
            if godlike {
                if let Some(db) = &self.db_connection {
                    if let Some(pool) = db.postgres_pool() {
                        let row: Option<(i32,)> = sqlx::query_as(
                            "SELECT userlevel FROM useraccounts WHERE principalid = $1",
                        )
                        .bind(agent_id)
                        .fetch_optional(pool)
                        .await
                        .unwrap_or(None);
                        if let Some((level,)) = row {
                            if level >= 200 {
                                god_level = level.min(255) as u8;
                                info!(
                                    "[ADMIN] Granted god level {} to agent {}",
                                    god_level, agent_id
                                );
                            } else {
                                info!(
                                    "[ADMIN] Denied god powers for agent {} (userlevel={})",
                                    agent_id, level
                                );
                            }
                        }
                    }
                }
                if god_level == 0 {
                    if agent_id == self.estate_owner {
                        god_level = 200;
                        info!("[ADMIN] Granted god level 200 to estate owner {}", agent_id);
                    }
                }
            }

            let session_id = self
                .session_manager
                .get_session_by_agent_id(agent_id)
                .map(|s| s.session_id)
                .unwrap_or(Uuid::nil());
            let token = if packet.data.len() >= 49 {
                Uuid::from_bytes(packet.data[33..49].try_into().unwrap_or([0u8; 16]))
            } else {
                Uuid::nil()
            };

            let mut data = BytesMut::with_capacity(49);
            data.put_slice(agent_id.as_bytes());
            data.put_slice(session_id.as_bytes());
            data.put_u8(god_level);
            data.put_slice(token.as_bytes());
            const GRANT_GODLIKE_POWERS_ID: u32 = 0xFFFF0102; // Low 258
            self.send_message(GRANT_GODLIKE_POWERS_ID, &data, packet.source, true, false)
                .await?;
        }
        Ok(())
    }

