    async fn handle_object_duplicate_on_ray(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() < 100 {
            return Ok(());
        }

        let mut cursor = std::io::Cursor::new(&packet.data);

        let mut agent_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut agent_id_bytes);
        let agent_id = Uuid::from_bytes(agent_id_bytes);

        if let Err(reason) = self.prim_limiter.check_prim_creation(agent_id, false) {
            warn!(
                "[GRIEFING] DuplicateOnRay denied for {}: {}",
                agent_id, reason
            );
            self.send_chat_alert(packet.source, &format!("Duplicate denied: {}", reason))
                .await?;
            return Ok(());
        }

        cursor.advance(16);
        let mut group_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut group_id_bytes);
        let group_id = Uuid::from_bytes(group_id_bytes);

        let _ray_start = [
            cursor.get_f32_le(),
            cursor.get_f32_le(),
            cursor.get_f32_le(),
        ];
        let ray_end = [
            cursor.get_f32_le(),
            cursor.get_f32_le(),
            cursor.get_f32_le(),
        ];
        let _bypass_raycast = cursor.get_u8();
        let _ray_end_is_intersection = cursor.get_u8();
        let copy_centers = cursor.get_u8();
        let copy_rotates = cursor.get_u8();
        cursor.advance(16);
        let _dup_flags = cursor.get_u32_le();

        let object_count = if cursor.remaining() >= 1 {
            cursor.get_u8()
        } else {
            0
        };
        let mut source_local_ids = Vec::new();
        for _ in 0..object_count {
            if cursor.remaining() >= 4 {
                source_local_ids.push(cursor.get_u32_le());
            }
        }

        info!(
            "[OBJECT] ObjectDuplicateOnRay from {} — {} objects at ({:.1},{:.1},{:.1})",
            agent_id,
            source_local_ids.len(),
            ray_end[0],
            ray_end[1],
            ray_end[2]
        );

        let clients: Vec<SocketAddr> = {
            let states = self.avatar_states.read();
            states.values().map(|s| s.client_addr).collect()
        };

        let center = if source_local_ids.len() > 1 && copy_centers != 0 {
            let objects = self.scene_objects.read();
            let mut cx = 0.0f32;
            let mut cy = 0.0f32;
            let mut cz = 0.0f32;
            let mut count = 0u32;
            for &lid in &source_local_ids {
                if let Some(o) = objects.get(&lid) {
                    cx += o.position[0];
                    cy += o.position[1];
                    cz += o.position[2];
                    count += 1;
                }
            }
            if count > 0 {
                Some([cx / count as f32, cy / count as f32, cz / count as f32])
            } else {
                None
            }
        } else {
            None
        };

        for &source_lid in &source_local_ids {
            let source_obj = {
                let objects = self.scene_objects.read();
                objects.get(&source_lid).cloned()
            };

            let Some(source) = source_obj else {
                warn!(
                    "[OBJECT] DuplicateOnRay: source local_id {} not found",
                    source_lid
                );
                continue;
            };

            let new_local_id = self
                .next_prim_local_id
                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            let new_uuid = Uuid::new_v4();

            let new_pos = if let Some(c) = center {
                let offset = [
                    source.position[0] - c[0],
                    source.position[1] - c[1],
                    source.position[2] - c[2],
                ];
                [
                    ray_end[0] + offset[0],
                    ray_end[1] + offset[1],
                    ray_end[2] + offset[2],
                ]
            } else {
                ray_end
            };

            let new_rot = if copy_rotates != 0 {
                source.rotation
            } else {
                [0.0, 0.0, 0.0, 1.0]
            };

            let clone = SceneObject {
                local_id: new_local_id,
                uuid: new_uuid,
                owner_id: agent_id,
                group_id,
                position: new_pos,
                rotation: new_rot,
                scene_group_id: new_uuid,
                ..source.clone()
            };

            let mut prim_obj_data = object_update::AvatarObjectData::create_prim_from_scene_object(
                &clone,
                self.region_handle,
            );
            prim_obj_data.update_flags |= object_update::FLAGS_CREATE_SELECTED;
            let prim_data =
                ObjectUpdateMessage::create_prim_update(prim_obj_data, self.region_handle);
            let prim_bytes = prim_data.serialize();

            self.scene_objects
                .write()
                .insert(new_local_id, clone.clone());

            {
                let s = &clone.scale;
                let is_phantom = clone.flags & 0x20 != 0 || clone.flags & 0x08 != 0;
                if !is_phantom && s[0] > 0.05 && s[1] > 0.05 && s[2] > 0.05 {
                    crate::ffi::CollisionWorld::add_box(
                        self.default_region_uuid,
                        new_local_id,
                        clone.position,
                        clone.rotation,
                        [s[0] * 0.5, s[1] * 0.5, s[2] * 0.5],
                        0x02,
                    );
                }
            }

            for &addr in &clients {
                let _ = self
                    .send_message(OBJECT_UPDATE_ID, &prim_bytes, addr, true, true)
                    .await;
            }

            info!(
                "[OBJECT] DuplicateOnRay local_id {} -> {} (uuid={})",
                source_lid, new_local_id, new_uuid
            );

            self.persist_scene_object_to_db(&clone).await;
        }

        Ok(())
    }

