    async fn handle_undo(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 36 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let mut offset = 32;
            let obj_count = if offset < packet.data.len() {
                packet.data[offset] as usize
            } else {
                0
            };
            offset += 1;
            for _ in 0..obj_count {
                if offset + 16 > packet.data.len() {
                    break;
                }
                let obj_id = Uuid::from_bytes(
                    packet.data[offset..offset + 16]
                        .try_into()
                        .unwrap_or([0u8; 16]),
                );
                offset += 16;
                info!("[OBJECT] Undo object {} from {}", obj_id, agent_id);
            }
        }
        Ok(())
    }

