    async fn handle_parcel_buy(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 63 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let group_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));
        let is_group_owned = packet.data[48] != 0;
        let local_id = i32::from_le_bytes(packet.data[50..54].try_into().unwrap_or([0; 4]));
        let _is_final = packet.data[54] != 0;
        let price = i32::from_le_bytes(packet.data[55..59].try_into().unwrap_or([0; 4]));
        let area = i32::from_le_bytes(packet.data[59..63].try_into().unwrap_or([0; 4]));

        info!(
            "[PARCEL] ParcelBuy: agent={} local_id={} price={} area={} group_owned={}",
            agent_id, local_id, price, area, is_group_owned
        );

        let prev_owner = {
            let parcels = self.parcels.read();
            parcels
                .iter()
                .find(|p| p.local_id == local_id)
                .map(|p| p.owner_id)
                .unwrap_or(Uuid::nil())
        };

        let mut success = false;
        let mut new_balance: i32 = 0;
        if let Some(db) = &self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                if price > 0 {
                    let balance: i64 = sqlx::query_scalar("SELECT COALESCE(balance, 0) FROM currency_balances WHERE user_id = $1 AND currency_code = 'LS'")
                        .bind(agent_id.to_string()).fetch_optional(pool).await.ok().flatten().unwrap_or(0);
                    if balance < price as i64 {
                        info!("[PARCEL] Insufficient funds for parcel buy");
                        self.send_money_balance_reply(
                            agent_id,
                            Uuid::new_v4(),
                            false,
                            balance as i32,
                            "Insufficient funds for land purchase",
                            5002,
                            agent_id,
                            false,
                            prev_owner,
                            false,
                            price,
                            "",
                            packet.source,
                        )
                        .await?;
                        return Ok(());
                    }
                    if let Ok(mut tx) = pool.begin().await {
                        let r1 = sqlx::query("UPDATE currency_balances SET balance = balance - $1, available = available - $1 WHERE user_id = $2 AND currency_code = 'LS'")
                            .bind(price as i64).bind(agent_id.to_string()).execute(&mut *tx).await;
                        let r2 = if prev_owner != Uuid::nil() {
                            sqlx::query("INSERT INTO currency_balances (user_id, currency_code, balance, available, last_updated) VALUES ($1, 'LS', $2, $2, NOW()::TEXT) ON CONFLICT (user_id, currency_code) DO UPDATE SET balance = currency_balances.balance + $2, available = currency_balances.available + $2")
                                .bind(prev_owner.to_string()).bind(price as i64).execute(&mut *tx).await
                        } else {
                            Ok(Default::default())
                        };
                        let _ = sqlx::query("INSERT INTO economy_transactions (id, from_user, to_user, amount, currency_code, type, status, description, created_at) VALUES ($1, $2, $3, $4, 'LS', '5002', 'completed', $5, NOW()::TEXT)")
                            .bind(Uuid::new_v4().to_string()).bind(agent_id.to_string()).bind(prev_owner.to_string())
                            .bind(price as i64).bind(format!("Land purchase (parcel {})", local_id)).execute(&mut *tx).await;
                        if r1.is_ok() && r2.is_ok() {
                            tx.commit().await.ok();
                            success = true;
                            new_balance = (balance - price as i64) as i32;
                        }
                    }
                } else {
                    success = true;
                }

                if success {
                    let new_owner = if is_group_owned { group_id } else { agent_id };
                    sqlx::query(r#"UPDATE land SET "AuthbuyerID" = '00000000-0000-0000-0000-000000000000', "OwnerID" = $1, "SalePrice" = 0, "IsGroupOwned" = $2 WHERE "LocalLandID" = $3 AND "RegionUUID" = $4"#)
                        .bind(new_owner.to_string()).bind(is_group_owned).bind(local_id).bind(self.default_region_uuid.to_string())
                        .execute(pool).await.ok();

                    {
                        let mut parcels = self.parcels.write();
                        if let Some(p) = parcels.iter_mut().find(|p| p.local_id == local_id) {
                            p.owner_id = new_owner;
                            p.sale_price = 0;
                            p.auth_buyer_id = Uuid::nil();
                            p.is_group_owned = is_group_owned;
                            if is_group_owned {
                                p.group_id = group_id;
                            }
                        }
                    }

                    info!(
                        "[PARCEL] Transferred parcel {} to {} (price={})",
                        local_id, new_owner, price
                    );
                }
            }
        }

        if success && price > 0 {
            let desc = format!("Land purchase ({} sqm) for L${}", area, price);
            self.send_money_balance_reply(
                agent_id,
                Uuid::new_v4(),
                true,
                new_balance,
                &desc,
                5002,
                agent_id,
                false,
                prev_owner,
                false,
                price,
                "",
                packet.source,
            )
            .await?;

            if prev_owner != Uuid::nil() {
                let seller_addr = {
                    let states = self.avatar_states.read();
                    states.get(&prev_owner).map(|s| s.client_addr)
                };
                if let Some(addr) = seller_addr {
                    if let Some(db) = &self.db_connection {
                        if let Some(pool) = db.postgres_pool() {
                            let sbal: i64 = sqlx::query_scalar("SELECT COALESCE(balance, 0) FROM currency_balances WHERE user_id = $1 AND currency_code = 'LS'")
                                .bind(prev_owner.to_string()).fetch_optional(pool).await.ok().flatten().unwrap_or(0);
                            let sdesc = format!("Land sold ({} sqm) for L${}", area, price);
                            self.send_money_balance_reply(
                                prev_owner,
                                Uuid::new_v4(),
                                true,
                                sbal as i32,
                                &sdesc,
                                5002,
                                agent_id,
                                false,
                                prev_owner,
                                false,
                                price,
                                "",
                                addr,
                            )
                            .await?;
                        }
                    }
                }
            }
        }

        if success {
            self.send_parcel_overlay(agent_id, packet.source).await?;
            self.send_parcel_properties(agent_id, 0, 0.0, 0.0, 256.0, 256.0, false, packet.source)
                .await?;
        }

        Ok(())
    }

    async fn handle_parcel_reclaim(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 36 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let local_id = i32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0u8; 4]));

        if agent_id != self.estate_owner {
            info!(
                "[PARCEL] ParcelReclaim denied for {} (not estate owner)",
                agent_id
            );
            return Ok(());
        }

        let estate_owner = self.estate_owner;
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs() as i32;

        let region_uuid = self.default_region_uuid;
        let mut found = false;

        {
            let mut parcels = self.parcels.write();
            if let Some(p) = parcels.iter_mut().find(|p| p.local_id == local_id) {
                p.owner_id = estate_owner;
                p.group_id = Uuid::nil();
                p.is_group_owned = false;
                p.sale_price = 0;
                p.auth_buyer_id = Uuid::nil();
                p.flags &= !(0x00080000u32 | 0x00100000 | 0x00000080 | 0x00002000);
                found = true;
            }
        }

        if found {
            if let Some(db) = &self.db_connection {
                match db.as_ref() {
                    crate::database::multi_backend::DatabaseConnection::PostgreSQL(pool) => {
                        let _ = sqlx::query(
                            r#"UPDATE land SET owneruuid = $1::uuid, groupuuid = $2::uuid,
                               isgroupowned = false, saleprice = 0, authbuyerid = $2::uuid,
                               landflags = landflags & ~(524288 | 1048576 | 128 | 8192),
                               claimdate = $3
                               WHERE locallandid = $4 AND regionuuid = $5::uuid"#,
                        )
                        .bind(estate_owner)
                        .bind(Uuid::nil())
                        .bind(now)
                        .bind(local_id)
                        .bind(region_uuid)
                        .execute(pool)
                        .await;
                    }
                    _ => {}
                }
            }

            info!(
                "[PARCEL] Reclaimed parcel {} to estate owner {}",
                local_id, estate_owner
            );
            self.send_parcel_overlay(agent_id, packet.source).await?;
            self.send_parcel_properties(agent_id, 0, 0.0, 0.0, 256.0, 256.0, false, packet.source)
                .await?;
        }

        Ok(())
    }

    async fn handle_parcel_release(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 36 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let local_id = i32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0u8; 4]));

        let estate_owner = self.estate_owner;
        let region_uuid = self.default_region_uuid;
        let mut found = false;

        {
            let mut parcels = self.parcels.write();
            if let Some(p) = parcels.iter_mut().find(|p| p.local_id == local_id) {
                if p.owner_id != agent_id && agent_id != self.estate_owner {
                    info!(
                        "[PARCEL] ParcelRelease denied: {} is not owner of parcel {}",
                        agent_id, local_id
                    );
                    return Ok(());
                }
                p.owner_id = estate_owner;
                p.group_id = Uuid::nil();
                p.is_group_owned = false;
                p.flags &= !(0x00080000u32 | 0x00100000 | 0x00000080 | 0x00002000);
                found = true;
            }
        }

        if found {
            if let Some(db) = &self.db_connection {
                match db.as_ref() {
                    crate::database::multi_backend::DatabaseConnection::PostgreSQL(pool) => {
                        let _ = sqlx::query(
                            r#"UPDATE land SET owneruuid = $1::uuid, groupuuid = $2::uuid,
                               isgroupowned = false,
                               landflags = landflags & ~(524288 | 1048576 | 128 | 8192)
                               WHERE locallandid = $3 AND regionuuid = $4::uuid"#,
                        )
                        .bind(estate_owner)
                        .bind(Uuid::nil())
                        .bind(local_id)
                        .bind(region_uuid)
                        .execute(pool)
                        .await;
                    }
                    _ => {}
                }
            }

            info!(
                "[PARCEL] Released/abandoned parcel {} by {} → estate owner {}",
                local_id, agent_id, estate_owner
            );
            self.send_parcel_overlay(agent_id, packet.source).await?;
            self.send_parcel_properties(agent_id, 0, 0.0, 0.0, 256.0, 256.0, false, packet.source)
                .await?;
        }

        Ok(())
    }

    async fn handle_parcel_return_objects(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 40 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let local_id = i32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0u8; 4]));
        let return_type = u32::from_le_bytes(packet.data[36..40].try_into().unwrap_or([0u8; 4]));

        let mut return_ids: Vec<Uuid> = Vec::new();
        if packet.data.len() > 40 {
            let count = packet.data[40] as usize;
            let mut offset = 41;
            for _ in 0..count {
                if offset + 16 <= packet.data.len() {
                    return_ids.push(Uuid::from_bytes(
                        packet.data[offset..offset + 16]
                            .try_into()
                            .unwrap_or([0u8; 16]),
                    ));
                    offset += 16;
                }
            }
        }

        info!(
            "[PARCEL] ParcelReturnObjects from agent {} parcel={} type={} ids={}",
            agent_id,
            local_id,
            return_type,
            return_ids.len()
        );

        let parcel = self.find_parcel_by_id(local_id);
        let objects_to_remove: Vec<u32> = {
            let objects = self.scene_objects.read();
            let mut results: Vec<u32> = Vec::new();
            if let Some(ref p) = parcel {
                for obj in objects.values() {
                    if obj.parent_id != 0 {
                        continue;
                    }
                    if !p.contains_point(obj.position[0], obj.position[1]) {
                        continue;
                    }
                    let matched = match return_type {
                        2 => obj.owner_id == p.owner_id,
                        4 => obj.group_id == p.group_id && p.group_id != Uuid::nil(),
                        8 => obj.owner_id != agent_id,
                        16 => return_ids.contains(&obj.owner_id),
                        _ => false,
                    };
                    if matched {
                        results.push(obj.local_id);
                    }
                }
            }
            results
        };

        info!(
            "[PARCEL] Returning {} objects from parcel {}",
            objects_to_remove.len(),
            local_id
        );

        let mut removed_uuids: Vec<(u32, Uuid)> = Vec::new();
        for lid in &objects_to_remove {
            let children: Vec<u32> = {
                let objects = self.scene_objects.read();
                objects
                    .values()
                    .filter(|o| o.parent_id == *lid)
                    .map(|o| o.local_id)
                    .collect()
            };
            for child_lid in children {
                self.scene_objects.write().remove(&child_lid);
            }
            if let Some(obj) = self.scene_objects.write().remove(lid) {
                removed_uuids.push((*lid, obj.uuid));
            }
        }

        for (lid, obj_uuid) in &removed_uuids {
            if let Some(ref db) = self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    let _ = sqlx::query("DELETE FROM prims WHERE uuid = $1::uuid")
                        .bind(obj_uuid.to_string())
                        .execute(pool)
                        .await;
                    let _ = sqlx::query("DELETE FROM primshapes WHERE uuid = $1::uuid")
                        .bind(obj_uuid.to_string())
                        .execute(pool)
                        .await;
                }
            }
            self.send_kill_object(&[*lid], packet.source).await.ok();
        }

        self.send_parcel_properties(
            agent_id,
            local_id,
            0.0,
            0.0,
            256.0,
            256.0,
            false,
            packet.source,
        )
        .await?;
        Ok(())
    }

    async fn handle_parcel_set_other_clean_time(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 40 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let local_id = i32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0u8; 4]));
        let clean_time = i32::from_le_bytes(packet.data[36..40].try_into().unwrap_or([0u8; 4]));

        info!(
            "[PARCEL] ParcelSetOtherCleanTime: agent={} parcel={} time={}",
            agent_id, local_id, clean_time
        );

        if let Some(ref db) = self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                let _ = sqlx::query("UPDATE land SET othercleantime = $1 WHERE locallandid = $2 AND regionuuid = $3::uuid")
                    .bind(clean_time)
                    .bind(local_id)
                    .bind(self.default_region_uuid.to_string())
                    .execute(pool).await;
            }
        }

        {
            let mut parcels = self.parcels.write();
            if let Some(p) = parcels.iter_mut().find(|p| p.local_id == local_id) {
                p.other_clean_time = clean_time;
            }
        }
        Ok(())
    }

    async fn handle_parcel_god_force_owner(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() < 52 {
            return Ok(());
        }

        let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
        let local_id = i32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0u8; 4]));
        let new_owner = Uuid::from_bytes(packet.data[36..52].try_into().unwrap_or([0u8; 16]));

        info!(
            "[ADMIN] ParcelGodForceOwner: admin={} parcel={} new_owner={}",
            agent_id, local_id, new_owner
        );

        if agent_id != self.estate_owner {
            warn!(
                "[ADMIN] Non-admin {} attempted ParcelGodForceOwner",
                agent_id
            );
            return Ok(());
        }

        if let Some(ref db) = self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                let _ = sqlx::query("UPDATE land SET owneruuid = $1::uuid WHERE locallandid = $2 AND regionuuid = $3::uuid")
                    .bind(new_owner)
                    .bind(local_id)
                    .bind(self.default_region_uuid)
                    .execute(pool).await;
            }
        }

        {
            let mut parcels = self.parcels.write();
            if let Some(p) = parcels.iter_mut().find(|p| p.local_id == local_id) {
                p.owner_id = new_owner;
            }
        }

        self.send_parcel_properties(agent_id, 0, 0.0, 0.0, 256.0, 256.0, false, packet.source)
            .await?;
        Ok(())
    }

    async fn handle_land_stat_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 40 {
            let _agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let report_type = u32::from_le_bytes(packet.data[32..36].try_into().unwrap_or([0; 4]));
            let _request_flags =
                u32::from_le_bytes(packet.data[36..40].try_into().unwrap_or([0; 4]));

            const LAND_STAT_REPLY_ID: u32 = 0xFFFF0086; // Low 134
            let mut data = Vec::with_capacity(32);
            data.extend_from_slice(&report_type.to_le_bytes());
            data.extend_from_slice(&0u32.to_le_bytes()); // TotalObjectCount
            data.put_u8(0); // ReportData count = 0 (empty list)
            self.send_message(LAND_STAT_REPLY_ID, &data, packet.source, true, false)
                .await?;
            info!("[PARCEL] LandStatReply sent (empty) type={}", report_type);
        }
        Ok(())
    }

    async fn handle_activate_gestures(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        let data = &packet.data;
        if data.len() < 33 {
            debug!("[GESTURE] ActivateGestures too short: {} bytes", data.len());
            return Ok(());
        }
        let mut offset = 32; // skip AgentID(16) + SessionID(16)
        if offset >= data.len() {
            return Ok(());
        }
        let block_count = data[offset] as usize;
        offset += 1;
        for _ in 0..block_count {
            if offset + 36 > data.len() {
                break;
            }
            let item_id =
                Uuid::from_bytes(data[offset..offset + 16].try_into().unwrap_or([0u8; 16]));
            offset += 16;
            let _asset_id =
                Uuid::from_bytes(data[offset..offset + 16].try_into().unwrap_or([0u8; 16]));
            offset += 16;
            let _gesture_flags =
                u32::from_le_bytes(data[offset..offset + 4].try_into().unwrap_or([0u8; 4]));
            offset += 4;

            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    match sqlx::query(
                        r#"UPDATE inventoryitems SET flags = flags | 1 WHERE "inventoryID" = $1"#,
                    )
                    .bind(item_id)
                    .execute(pool)
                    .await
                    {
                        Ok(_) => info!("[GESTURE] Activated gesture item {}", item_id),
                        Err(e) => warn!("[GESTURE] Failed to activate {}: {}", item_id, e),
                    }
                }
            }
        }
        Ok(())
    }

    async fn handle_deactivate_gestures(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        let data = &packet.data;
        if data.len() < 33 {
            debug!(
                "[GESTURE] DeactivateGestures too short: {} bytes",
                data.len()
            );
            return Ok(());
        }
        let mut offset = 32; // skip AgentID(16) + SessionID(16)
        if offset >= data.len() {
            return Ok(());
        }
        let block_count = data[offset] as usize;
        offset += 1;
        for _ in 0..block_count {
            if offset + 20 > data.len() {
                break;
            }
            let item_id =
                Uuid::from_bytes(data[offset..offset + 16].try_into().unwrap_or([0u8; 16]));
            offset += 16;
            let _gesture_flags =
                u32::from_le_bytes(data[offset..offset + 4].try_into().unwrap_or([0u8; 4]));
            offset += 4;

            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    match sqlx::query(
                        r#"UPDATE inventoryitems SET flags = flags & ~1 WHERE "inventoryID" = $1"#,
                    )
                    .bind(item_id)
                    .execute(pool)
                    .await
                    {
                        Ok(_) => info!("[GESTURE] Deactivated gesture item {}", item_id),
                        Err(e) => warn!("[GESTURE] Failed to deactivate {}: {}", item_id, e),
                    }
                }
            }
        }
        Ok(())
    }

    async fn handle_update_mute_list_entry(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        let data = &packet.data;
        if data.len() < 52 {
            debug!("[MUTE] UpdateMuteListEntry too short: {} bytes", data.len());
            return Ok(());
        }
        let agent_id = Uuid::from_bytes(data[0..16].try_into().unwrap_or([0u8; 16]));
        let _session_id = &data[16..32];
        let mute_id = Uuid::from_bytes(data[32..48].try_into().unwrap_or([0u8; 16]));
        let mut offset = 48;
        let mute_name = if offset < data.len() {
            let name_len = data[offset] as usize;
            offset += 1;
            if offset + name_len <= data.len() {
                let name = String::from_utf8_lossy(&data[offset..offset + name_len])
                    .trim_end_matches('\0')
                    .to_string();
                offset += name_len;
                name
            } else {
                String::new()
            }
        } else {
            String::new()
        };
        let mute_type: i32 = if offset + 4 <= data.len() {
            i32::from_le_bytes(data[offset..offset + 4].try_into().unwrap_or([0u8; 4]))
        } else {
            0
        };
        offset += 4;
        let mute_flags: i32 = if offset + 4 <= data.len() {
            i32::from_le_bytes(data[offset..offset + 4].try_into().unwrap_or([0u8; 4]))
        } else {
            0
        };

        if let Some(db) = &self.db_connection {
            if let Some(pool) = db.postgres_pool() {
                let now = std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_secs() as i64;
                match sqlx::query(
                    r#"INSERT INTO "MuteList" ("AgentID", "MuteID", "MuteName", "MuteType", "MuteFlags", "Stamp")
                       VALUES ($1, $2, $3, $4, $5, $6)
                       ON CONFLICT ("AgentID", "MuteID", "MuteName") DO UPDATE SET "MuteFlags" = $5, "Stamp" = $6"#
                )
                .bind(agent_id.to_string())
                .bind(mute_id.to_string())
                .bind(&mute_name)
                .bind(mute_type)
                .bind(mute_flags)
                .bind(now)
                .execute(pool)
                .await {
                    Ok(_) => info!("[MUTE] Added mute entry: agent={} mute_id={} name={} type={}", agent_id, mute_id, mute_name, mute_type),
                    Err(e) => warn!("[MUTE] Failed to add mute entry: {}", e),
                }
            }
        }
        Ok(())
    }

