    async fn handle_pick_info_update(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 48 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let pick_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));
            let mut offset = 48;
            let _top_pick = if offset < packet.data.len() {
                packet.data[offset] != 0
            } else {
                false
            };
            offset += 1;
            let parcel_id = if offset + 16 <= packet.data.len() {
                Uuid::from_bytes(
                    packet.data[offset..offset + 16]
                        .try_into()
                        .unwrap_or([0u8; 16]),
                )
            } else {
                Uuid::nil()
            };
            offset += 16;
            let name_len = if offset + 2 <= packet.data.len() {
                u16::from_le_bytes(packet.data[offset..offset + 2].try_into().unwrap_or([0; 2]))
                    as usize
            } else {
                0
            };
            offset += 2;
            let name = if offset + name_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + name_len]).to_string()
            } else {
                String::new()
            };
            offset += name_len;
            let desc_len = if offset + 2 <= packet.data.len() {
                u16::from_le_bytes(packet.data[offset..offset + 2].try_into().unwrap_or([0; 2]))
                    as usize
            } else {
                0
            };
            offset += 2;
            let desc = if offset + desc_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + desc_len]).to_string()
            } else {
                String::new()
            };
            offset += desc_len;
            let snapshot_id = if offset + 16 <= packet.data.len() {
                Uuid::from_bytes(
                    packet.data[offset..offset + 16]
                        .try_into()
                        .unwrap_or([0u8; 16]),
                )
            } else {
                Uuid::nil()
            };
            offset += 16;
            let mut pos = [0f64; 3];
            for i in 0..3 {
                if offset + 8 <= packet.data.len() {
                    pos[i] = f64::from_le_bytes(
                        packet.data[offset..offset + 8]
                            .try_into()
                            .unwrap_or([0u8; 8]),
                    );
                    offset += 8;
                }
            }
            let sort_order: i32 = if offset + 4 <= packet.data.len() {
                i32::from_le_bytes(packet.data[offset..offset + 4].try_into().unwrap_or([0; 4]))
            } else {
                0
            };
            let enabled: bool = if offset + 4 < packet.data.len() {
                packet.data[offset + 4] != 0
            } else {
                true
            };

            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    let pos_str = format!("{},{},{}", pos[0], pos[1], pos[2]);
                    sqlx::query(
                        r#"INSERT INTO userpicks (pickuuid, creatoruuid, toppick, parceluuid, name, description, snapshotuuid, posglobal, sortorder, enabled)
                           VALUES ($1, $2, false, $3, $4, $5, $6, $7, $8, $9)
                           ON CONFLICT (pickuuid) DO UPDATE SET name = $4, description = $5, snapshotuuid = $6, posglobal = $7, sortorder = $8, enabled = $9"#
                    )
                    .bind(pick_id.to_string()).bind(agent_id.to_string()).bind(parcel_id.to_string())
                    .bind(&name).bind(&desc).bind(snapshot_id.to_string()).bind(&pos_str).bind(sort_order).bind(enabled)
                    .execute(pool).await.ok();
                    info!("[PROFILE] Updated pick {} for {}", pick_id, agent_id);
                }
            }
        }
        Ok(())
    }

