    async fn handle_sim_wide_deletes(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 52 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let target_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));
            let flags = i32::from_le_bytes(packet.data[48..52].try_into().unwrap_or([0; 4]));
            info!(
                "[ADMIN] SimWideDeletes from {} target={} flags={}",
                agent_id, target_id, flags
            );
            let to_remove: Vec<u32> = {
                let scene = self.scene_objects.read();
                scene
                    .iter()
                    .filter(|(_, obj)| obj.owner_id == target_id)
                    .map(|(k, _)| *k)
                    .collect()
            };
            let mut count = 0u32;
            for local_id in &to_remove {
                self.scene_objects.write().remove(local_id);
                crate::ffi::CollisionWorld::remove_body(self.default_region_uuid, *local_id);
                count += 1;
            }
            if count > 0 {
                let client_addrs: Vec<std::net::SocketAddr> = {
                    let states = self.avatar_states.read();
                    states
                        .values()
                        .filter(|s| !s.is_npc)
                        .map(|s| s.client_addr)
                        .collect()
                };
                for addr in &client_addrs {
                    self.send_kill_object(&to_remove, *addr).await.ok();
                }
            }
            info!(
                "[ADMIN] SimWideDeletes: removed {} objects owned by {}",
                count, target_id
            );
        }
        Ok(())
    }

    async fn handle_create_group_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() < 32 {
            return Ok(());
        }

        let mut cursor = std::io::Cursor::new(&packet.data);
        let mut agent_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut agent_id_bytes);
        let agent_id = Uuid::from_bytes(agent_id_bytes);
        let mut _session_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut _session_id_bytes);

        let name = if cursor.remaining() > 0 {
            let len = cursor.get_u8() as usize;
            let mut buf = vec![0u8; len.min(cursor.remaining())];
            cursor.copy_to_slice(&mut buf);
            String::from_utf8_lossy(&buf).to_string()
        } else {
            String::new()
        };

        let charter = if cursor.remaining() > 1 {
            let len = cursor.get_u16_le() as usize;
            let mut buf = vec![0u8; len.min(cursor.remaining())];
            cursor.copy_to_slice(&mut buf);
            String::from_utf8_lossy(&buf).to_string()
        } else {
            String::new()
        };

        let show_in_list = if cursor.remaining() >= 1 {
            cursor.get_u8() != 0
        } else {
            true
        };
        let mut insignia_id = Uuid::nil();
        if cursor.remaining() >= 16 {
            let mut bytes = [0u8; 16];
            cursor.copy_to_slice(&mut bytes);
            insignia_id = Uuid::from_bytes(bytes);
        }
        let membership_fee = if cursor.remaining() >= 4 {
            cursor.get_i32_le()
        } else {
            0
        };
        let open_enrollment = if cursor.remaining() >= 1 {
            cursor.get_u8() != 0
        } else {
            true
        };

        info!(
            "[GROUPS] CreateGroupRequest from {} name='{}' fee={}",
            agent_id, name, membership_fee
        );

        let group_id = Uuid::new_v4();
        let owner_role_id = Uuid::new_v4();
        let everyone_role_id = Uuid::nil();
        let mut success = false;

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let now = std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_secs() as i32;

                let r1 = sqlx::query(
                    "INSERT INTO os_groups_groups (GroupID, Name, Charter, InsigniaID, FounderID, \
                     MembershipFee, OpenEnrollment, ShowInList, AllowPublish, MaturePublish, OwnerRoleID) \
                     VALUES ($1, $2, $3, $4, $5, $6, $7, $8, 0, 0, $9)"
                )
                .bind(group_id.to_string())
                .bind(&name)
                .bind(&charter)
                .bind(insignia_id.to_string())
                .bind(agent_id.to_string())
                .bind(membership_fee)
                .bind(if open_enrollment { 1i32 } else { 0 })
                .bind(if show_in_list { 1i32 } else { 0 })
                .bind(owner_role_id.to_string())
                .execute(pool)
                .await;

                if r1.is_ok() {
                    let _ = sqlx::query(
                        "INSERT INTO os_groups_roles (GroupID, RoleID, Name, Description, Title, Powers) \
                         VALUES ($1, $2, 'Everyone', 'Everyone', 'Member', '0')"
                    )
                    .bind(group_id.to_string())
                    .bind(everyone_role_id.to_string())
                    .execute(pool).await;

                    let _ = sqlx::query(
                        "INSERT INTO os_groups_roles (GroupID, RoleID, Name, Description, Title, Powers) \
                         VALUES ($1, $2, 'Owners', 'Owners of the group', 'Owner', '-1')"
                    )
                    .bind(group_id.to_string())
                    .bind(owner_role_id.to_string())
                    .execute(pool).await;

                    let _ = sqlx::query(
                        "INSERT INTO os_groups_membership (GroupID, AgentID, SelectedRoleID, Contribution, \
                         ListInProfile, AcceptNotices) VALUES ($1, $2, $3, 0, 1, 1)"
                    )
                    .bind(group_id.to_string())
                    .bind(agent_id.to_string())
                    .bind(owner_role_id.to_string())
                    .execute(pool).await;

                    let _ = sqlx::query(
                        "INSERT INTO os_groups_rolemembership (GroupID, RoleID, AgentID) VALUES ($1, $2, $3)"
                    )
                    .bind(group_id.to_string())
                    .bind(everyone_role_id.to_string())
                    .bind(agent_id.to_string())
                    .execute(pool).await;

                    let _ = sqlx::query(
                        "INSERT INTO os_groups_rolemembership (GroupID, RoleID, AgentID) VALUES ($1, $2, $3)"
                    )
                    .bind(group_id.to_string())
                    .bind(owner_role_id.to_string())
                    .bind(agent_id.to_string())
                    .execute(pool).await;

                    success = true;
                    info!("[GROUPS] Created group '{}' id={}", name, group_id);
                }
            }
        }

        let mut data = BytesMut::with_capacity(40);
        data.put_slice(agent_id.as_bytes());
        let reply_group = if success { group_id } else { Uuid::nil() };
        data.put_slice(reply_group.as_bytes());
        data.put_u8(if success { 1 } else { 0 });
        let msg = if success {
            b"Group created".as_slice()
        } else {
            b"Failed to create group".as_slice()
        };
        data.put_u8(msg.len() as u8);
        data.put_slice(msg);
        const CREATE_GROUP_REPLY_ID: u32 = 0xFFFF015E; // Low 350
        self.send_message(CREATE_GROUP_REPLY_ID, &data, packet.source, true, false)
            .await?;

        if success {
            self.send_agent_group_data_update(agent_id, packet.source)
                .await?;
        }

        Ok(())
    }

