    async fn handle_group_roles_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() < 48 {
            return Ok(());
        }

        let mut cursor = std::io::Cursor::new(&packet.data);
        let mut agent_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut agent_id_bytes);
        let agent_id = Uuid::from_bytes(agent_id_bytes);
        let mut _session_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut _session_id_bytes);
        let mut group_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut group_id_bytes);
        let group_id = Uuid::from_bytes(group_id_bytes);
        let mut request_id_bytes = [0u8; 16];
        if cursor.remaining() >= 16 {
            cursor.copy_to_slice(&mut request_id_bytes);
        }
        let request_id = Uuid::from_bytes(request_id_bytes);

        info!(
            "[GROUPS] GroupRolesRequest from {} for group {}",
            agent_id, group_id
        );

        let mut roles: Vec<(Uuid, String, String, String, u64, u32)> = Vec::new();

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let rows = sqlx::query(
                    "SELECT r.RoleID, r.Name, r.Title, r.Description, r.Powers, \
                     (SELECT COUNT(*) FROM os_groups_rolemembership rm WHERE rm.GroupID = r.GroupID AND rm.RoleID = r.RoleID) as MemberCount \
                     FROM os_groups_roles r WHERE r.GroupID = $1"
                )
                .bind(group_id.to_string())
                .fetch_all(pool)
                .await
                .unwrap_or_default();

                for row in &rows {
                    let rid_str: String = sqlx::Row::get(row, "roleid");
                    let rid = Uuid::parse_str(&rid_str).unwrap_or(Uuid::nil());
                    let name: String = sqlx::Row::get(row, "name");
                    let title: String = sqlx::Row::get(row, "title");
                    let desc: String = sqlx::Row::get(row, "description");
                    let powers_str: String = sqlx::Row::try_get(row, "powers").unwrap_or_default();
                    let powers = powers_str.parse::<u64>().unwrap_or(0);
                    let member_count: i64 = sqlx::Row::get(row, "membercount");
                    roles.push((rid, name, title, desc, powers, member_count as u32));
                }
            }
        }

        let mut data = BytesMut::with_capacity(60 + roles.len() * 80);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(group_id.as_bytes());
        data.put_slice(request_id.as_bytes());

        let count = roles.len().min(255);
        data.put_u8(count as u8);

        for (role_id, name, title, desc, powers, members) in roles.iter().take(255) {
            data.put_slice(role_id.as_bytes());
            let name_b = name.as_bytes();
            data.put_u8(name_b.len().min(255) as u8);
            data.put_slice(&name_b[..name_b.len().min(255)]);
            let title_b = title.as_bytes();
            data.put_u8(title_b.len().min(255) as u8);
            data.put_slice(&title_b[..title_b.len().min(255)]);
            let desc_b = desc.as_bytes();
            data.put_u8(desc_b.len().min(255) as u8);
            data.put_slice(&desc_b[..desc_b.len().min(255)]);
            data.put_u64_le(*powers);
            data.put_u32_le(*members);
        }

        const GROUP_ROLE_DATA_REPLY_ID: u32 = 0xFFFF0171; // Low 369
        self.send_message(GROUP_ROLE_DATA_REPLY_ID, &data, packet.source, true, true)
            .await
    }

    async fn handle_group_role_members_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }

        if packet.data.len() < 48 {
            return Ok(());
        }

        let mut cursor = std::io::Cursor::new(&packet.data);
        let mut agent_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut agent_id_bytes);
        let agent_id = Uuid::from_bytes(agent_id_bytes);
        let mut _session_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut _session_id_bytes);
        let mut group_id_bytes = [0u8; 16];
        cursor.copy_to_slice(&mut group_id_bytes);
        let group_id = Uuid::from_bytes(group_id_bytes);
        let mut request_id_bytes = [0u8; 16];
        if cursor.remaining() >= 16 {
            cursor.copy_to_slice(&mut request_id_bytes);
        }
        let request_id = Uuid::from_bytes(request_id_bytes);

        info!(
            "[GROUPS] GroupRoleMembersRequest from {} for group {}",
            agent_id, group_id
        );

        let mut pairs: Vec<(Uuid, Uuid)> = Vec::new();

        if let Some(ref db_conn) = self.db_connection {
            if let Some(pool) = db_conn.postgres_pool() {
                let rows = sqlx::query(
                    "SELECT RoleID, AgentID FROM os_groups_rolemembership WHERE GroupID = $1 LIMIT 500"
                )
                .bind(group_id.to_string())
                .fetch_all(pool)
                .await
                .unwrap_or_default();

                for row in &rows {
                    let rid_str: String = sqlx::Row::get(row, "roleid");
                    let aid_str: String = sqlx::Row::get(row, "agentid");
                    let rid = Uuid::parse_str(&rid_str).unwrap_or(Uuid::nil());
                    let aid = Uuid::parse_str(&aid_str).unwrap_or(Uuid::nil());
                    pairs.push((rid, aid));
                }
            }
        }

        let mut data = BytesMut::with_capacity(60 + pairs.len() * 32);
        data.put_slice(agent_id.as_bytes());
        data.put_slice(group_id.as_bytes());
        data.put_slice(request_id.as_bytes());
        data.put_i32_le(pairs.len() as i32);

        let count = pairs.len().min(255);
        data.put_u8(count as u8);

        for (role_id, member_id) in pairs.iter().take(255) {
            data.put_slice(role_id.as_bytes());
            data.put_slice(member_id.as_bytes());
        }

        const GROUP_ROLE_MEMBERS_REPLY_ID: u32 = 0xFFFF0173; // Low 371
        self.send_message(
            GROUP_ROLE_MEMBERS_REPLY_ID,
            &data,
            packet.source,
            true,
            true,
        )
        .await
    }

