    async fn handle_group_account_summary_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 52 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let group_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));
            let request_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));

            const GROUP_ACCOUNT_SUMMARY_REPLY_ID: u32 = 0xFFFF0154; // Low 340
            let mut data = Vec::with_capacity(120);
            data.extend_from_slice(agent_id.as_bytes());
            data.extend_from_slice(group_id.as_bytes());
            data.extend_from_slice(request_id.as_bytes());
            data.extend_from_slice(&0i32.to_le_bytes()); // IntervalDays
            data.extend_from_slice(&0i32.to_le_bytes()); // CurrentInterval
            let start = "2026-01-01";
            data.push(start.len() as u8);
            data.extend_from_slice(start.as_bytes());
            let end = "2026-12-31";
            data.push(end.len() as u8);
            data.extend_from_slice(end.as_bytes());
            data.extend_from_slice(&0i32.to_le_bytes()); // Balance
            data.extend_from_slice(&0i32.to_le_bytes()); // TotalCredits
            data.extend_from_slice(&0i32.to_le_bytes()); // TotalDebits
            data.extend_from_slice(&0i32.to_le_bytes()); // ObjectTaxCurrent
            data.extend_from_slice(&0i32.to_le_bytes()); // LightTaxCurrent
            data.extend_from_slice(&0i32.to_le_bytes()); // LandTaxCurrent
            data.extend_from_slice(&0i32.to_le_bytes()); // GroupTaxCurrent
            data.extend_from_slice(&0i32.to_le_bytes()); // ParcelDirFeeCurrent
            data.extend_from_slice(&0i32.to_le_bytes()); // ObjectTaxEstimate
            data.extend_from_slice(&0i32.to_le_bytes()); // LightTaxEstimate
            data.extend_from_slice(&0i32.to_le_bytes()); // LandTaxEstimate
            data.extend_from_slice(&0i32.to_le_bytes()); // GroupTaxEstimate
            data.extend_from_slice(&0i32.to_le_bytes()); // ParcelDirFeeEstimate
            data.extend_from_slice(&0i32.to_le_bytes()); // NonExemptMembers
            let last = "2026-01-01";
            data.push(last.len() as u8);
            data.extend_from_slice(last.as_bytes());
            data.extend_from_slice(&0i32.to_le_bytes()); // TaxDate
            self.send_message(
                GROUP_ACCOUNT_SUMMARY_REPLY_ID,
                &data,
                packet.source,
                true,
                false,
            )
            .await?;
            info!("[GROUPS] Sent GroupAccountSummaryReply for {}", group_id);
        }
        Ok(())
    }

