    async fn handle_avatar_properties_update(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 80 {
            let agent_id = Uuid::from_slice(&packet.data[0..16])?;
            let mut offset = 32;
            let image_id = Uuid::from_slice(&packet.data[offset..offset + 16]).unwrap_or_default();
            offset += 16;
            let fl_image_id =
                Uuid::from_slice(&packet.data[offset..offset + 16]).unwrap_or_default();
            offset += 16;
            let about_len = if offset + 2 <= packet.data.len() {
                u16::from_le_bytes(packet.data[offset..offset + 2].try_into().unwrap_or([0; 2]))
                    as usize
            } else {
                0
            };
            offset += 2;
            let about_text = if offset + about_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + about_len]).to_string()
            } else {
                String::new()
            };
            offset += about_len;
            let fl_len = if offset < packet.data.len() {
                packet.data[offset] as usize
            } else {
                0
            };
            offset += 1;
            let fl_text = if offset + fl_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + fl_len]).to_string()
            } else {
                String::new()
            };
            offset += fl_len;
            let allow_publish = if offset < packet.data.len() {
                packet.data[offset] != 0
            } else {
                false
            };
            offset += 1;
            let mature_publish = if offset < packet.data.len() {
                packet.data[offset] != 0
            } else {
                false
            };
            offset += 1;
            let url_len = if offset < packet.data.len() {
                packet.data[offset] as usize
            } else {
                0
            };
            offset += 1;
            let profile_url = if offset + url_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + url_len]).to_string()
            } else {
                String::new()
            };

            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    match sqlx::query(
                        r#"INSERT INTO userprofile (useruuid, "profileAboutText", "profileFirstText", "profileURL", "profileImage", "profileFirstImage", "profileAllowPublish", "profileMaturePublish")
                           VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
                           ON CONFLICT (useruuid) DO UPDATE SET "profileAboutText" = $2, "profileFirstText" = $3, "profileURL" = $4, "profileImage" = $5, "profileFirstImage" = $6, "profileAllowPublish" = $7, "profileMaturePublish" = $8"#
                    )
                    .bind(agent_id.to_string())
                    .bind(&about_text)
                    .bind(&fl_text)
                    .bind(&profile_url)
                    .bind(image_id.to_string())
                    .bind(fl_image_id.to_string())
                    .bind(if allow_publish { "1" } else { "0" })
                    .bind(if mature_publish { "1" } else { "0" })
                    .execute(pool).await {
                        Ok(_) => info!("[PROFILE] Updated profile for {}", agent_id),
                        Err(e) => warn!("[PROFILE] Failed to update profile for {}: {}", agent_id, e),
                    }
                }
            }
        }
        Ok(())
    }

