    async fn handle_region_handle_request(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 16 {
            let mut region_id_bytes = [0u8; 16];
            region_id_bytes.copy_from_slice(&packet.data[0..16]);
            let region_id = Uuid::from_bytes(region_id_bytes);
            info!(
                "[REGION] RegionHandleRequest for {} from {}",
                region_id, packet.source
            );

            let session = {
                let states = self.avatar_states.read();
                states.keys().next().copied()
            };
            if let Some(aid) = session {
                if let Some(sess) = self.session_manager.get_session_by_agent_id(aid) {
                    let region_handle = ((sess.region_x as u64) << 32) | (sess.region_y as u64);
                    let mut data = BytesMut::with_capacity(24);
                    data.put_slice(region_id.as_bytes());
                    data.put_u64_le(region_handle);
                    const REGION_ID_AND_HANDLE_REPLY_ID: u32 = 0xFFFF0136; // Low 310
                    self.send_message(
                        REGION_ID_AND_HANDLE_REPLY_ID,
                        &data,
                        packet.source,
                        true,
                        false,
                    )
                    .await?;
                }
            }
        }
        Ok(())
    }

