    async fn handle_user_report(&self, packet: &UdpPacket) -> Result<()> {
        if packet.flags & FLAG_RELIABLE != 0 {
            self.send_ack(packet.sequence, packet.source).await?;
        }
        if packet.data.len() >= 48 {
            let agent_id = Uuid::from_bytes(packet.data[0..16].try_into().unwrap_or([0u8; 16]));
            let target_id = Uuid::from_bytes(packet.data[32..48].try_into().unwrap_or([0u8; 16]));
            let mut offset = 48;
            let report_type: u8 = packet.data.get(offset).copied().unwrap_or(0);
            offset += 1;
            let category: u8 = packet.data.get(offset).copied().unwrap_or(0);
            offset += 1;
            let _check_flags: u8 = packet.data.get(offset).copied().unwrap_or(0);
            offset += 1;
            let summary_len = packet.data.get(offset).copied().unwrap_or(0) as usize;
            offset += 1;
            let summary = if offset + summary_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + summary_len]).to_string()
            } else {
                String::new()
            };
            offset += summary_len;
            let details_len = if offset + 2 <= packet.data.len() {
                u16::from_le_bytes(packet.data[offset..offset + 2].try_into().unwrap_or([0; 2]))
                    as usize
            } else {
                0
            };
            offset += 2;
            let details = if offset + details_len <= packet.data.len() {
                String::from_utf8_lossy(&packet.data[offset..offset + details_len]).to_string()
            } else {
                String::new()
            };

            if let Some(db) = &self.db_connection {
                if let Some(pool) = db.postgres_pool() {
                    sqlx::query(
                        "CREATE TABLE IF NOT EXISTS abuse_reports (id SERIAL PRIMARY KEY, reporter TEXT NOT NULL, target TEXT NOT NULL, report_type INTEGER, category INTEGER, summary TEXT, details TEXT, region TEXT, created_at TIMESTAMP DEFAULT NOW())"
                    ).execute(pool).await.ok();
                    sqlx::query(
                        "INSERT INTO abuse_reports (reporter, target, report_type, category, summary, details, region) VALUES ($1, $2, $3, $4, $5, $6, $7)"
                    )
                    .bind(agent_id.to_string()).bind(target_id.to_string()).bind(report_type as i32).bind(category as i32)
                    .bind(&summary).bind(&details).bind(&self.region_name)
                    .execute(pool).await.ok();
                }
            }
            info!(
                "[ADMIN] UserReport: {} reported {} type={} cat={}: {}",
                agent_id, target_id, report_type, category, summary
            );
        }
        Ok(())
    }

